window.NOVEL_DATA = {"title": "الوريث الخامس", "subtitle": "رواية تشويق تاريخي", "author": "فكرة أصلية: أحمد نبيل", "tagline": "الدم يدلّك على الطريق، لكنه لا يخبرك بمن ينتظرك في آخره.", "items": [{"id": "chapter-0", "order": 0, "title": "استهلال: الصورة التي لم تُلتقط", "section": "ما قبل البداية", "firstLine": "البر الغربي - الأقصر، شتاء 1978", "wordCount": 652, "minutes": 4, "era": "1978", "theme": "seventies", "sound": "wind", "icon": "◫", "scene": "البر الغربي — الأقصر", "html": "<p>البر الغربي - الأقصر، شتاء 1978</p>\n<p>لم يكن نعيم عبد الوارث يخاف الظلام. عاش عمره كله في قرية ينام أهلها على ظل الجبل، ويستيقظون على مقابر أقدم من أسماء أجدادهم. كان يعرف أن الظلام لا يعض، وأن العقارب لا تهاجم إلا إذا داستها قدم غبية، وأن الأصوات التي تخرج من الشقوق ليلًا تصنعها الريح حين تضيق بها الممرات.</p>\n<p>لكنه في تلك الليلة كان خائفًا.</p>\n<p>وقف داخل الممر الحجري وهو يضغط ظهره إلى الجدار. كان عرقه باردًا، مع أن الهواء في جوف الصخر خانق. في يده اليمنى كاميرا روسية قديمة، وفي اليسرى مصباح صغير لفّ حول زجاجه قطعة قماش زرقاء حتى لا يراه الرجال في الخارج.</p>\n<p>جاءه صوت نادر السيوفي من وراء الباب الحجري:</p>\n<p>- نعيم... أنت لا تفهم ما وجدناه.</p>\n<p>لم يرد.</p>\n<p>كان الباب بينهما مجرد لوح من الحجر انزلق من موضعه منذ دقائق. لا يقفل تمامًا، ولا يفتح إلا بمقدار إصبعين. من الشق الضيق عبر خط من الضوء وقطع الغبار المعلق كأنه سكين.</p>\n<p>قال نادر، بصوت أكثر هدوءًا:</p>\n<p>- اخرج، وسننسى كل شيء. لك مال يكفي أولادك وأولاد أولادك.</p>\n<p>نظر نعيم إلى أرض الحجرة. لم يكن هناك ذهب كما وعدتهم الخرائط، ولا تماثيل كاملة، ولا توابيت مزخرفة. كانت هناك جرار فخارية سوداء، وألواح خشبية متآكلة، وحزمة برديات تحولت أطرافها إلى رماد. وعلى الجدار المقابل صف من الأسماء، مئات الأسماء، مكتوبة بأحبار مختلفة ولغات مختلفة، كأن كل عصر مر من هنا وترك توقيعه ثم أغلق الباب وراءه.</p>\n<p>وفي منتصف الجدار كانت كف سوداء، لها خمسة أصابع طويلة، وتحتها علامة تشبه رأس ابن آوى وقد شُق نصفين.</p>\n<p>رفع نعيم الكاميرا والتقط صورة.</p>\n<p>صدر صوت الغالق واضحًا أكثر مما ينبغي.</p>\n<p>توقف الكلام في الخارج.</p>\n<p>همس رجل آخر:</p>\n<p>- معه كاميرا.</p>\n<p>ثم اصطدمت كتف بالباب الحجري. تحرك نصف شبر، وتناثر التراب من السقف.</p>\n<p>أعاد نعيم لف الفيلم بسرعة. لم يبقَ فيه إلا لقطة واحدة. وجه الكاميرا إلى الركن السفلي من الحجرة، حيث ظهرت عظام بشرية تحت قماش كتان تحول إلى لون الشاي. إلى جوار الجمجمة خاتم نحاسي يحمل نفس علامة ابن آوى المشقوق.</p>\n<p>التقط الصورة الأخيرة.</p>\n<p>هذه المرة لم ينتظر.</p>\n<p>أخرج علبة الفيلم، ووضع بدلًا منها علبة فارغة كان قد احتفظ بها في جيبه. دس الفيلم الحقيقي داخل تجويف صغير في مقبض الكاميرا، ثم أغلقه بظفره. كان يعرف أن الحيلة لن تخدعهم طويلًا، لكنها قد تمنحه دقائق.</p>\n<p>ارتطم الباب مرة ثانية.</p>\n<p>- نعيم! صاح نادر. لا تجعلني أؤذيك.</p>\n<p>ابتسم نعيم رغم أن أسنانه كانت ترتجف.</p>\n<p>- أنت أذيت ناسًا ماتوا من ثلاثة آلاف سنة، يا دكتور. أنا دوري جه متأخر شوية بس.</p>\n<p>لم يدرِ من أين جاءته الشجاعة، ولا لماذا قال الجملة كأنه حفظها من شخص آخر. اندفع نحو الممر الجانبي الذي لم يره الرجال. كان منخفضًا حتى اضطر إلى الزحف. ترك الكاميرا تتدلى من عنقه، وشعر بالصخر يمزق جلبابه عند الكتف.</p>\n<p>خلفه، انفتح الباب.</p>\n<p>سمع خطوات وصيحة غاضبة، ثم طلقة ارتدت داخل الحجرة وتكاثرت أصداؤها حتى بدت كأن الجبل كله يطلق النار.</p>\n<p>واصل الزحف.</p>\n<p>كان يعرف أن الممر يخرج قرب بئر جافة خلف بيت مهجور. اكتشفه وهو صبي، حين كان يتحدى أبناء القرية بالدخول إلى فتحات الجبل. لم يخبر أحدًا به. حتى زوجته زهية لم تعرف.</p>\n<p>خرج من البئر قبل الفجر بقليل، وركض بين الحقول حتى وصل بيته. لم يوقظ أحدًا. دخل الغرفة التي ينام فيها ابنه الصغير عمران، ووقف لحظة عند الباب. كان الصبي مستلقيًا على بطنه، وقد ألقى ساقًا فوق الغطاء. إلى جواره أخته مها، رضيعة لا تعرف من أبيها إلا صوته.</p>\n<p>رفع نعيم لوح الأرضية تحت السرير، ووضع الكاميرا في الفراغ، ثم أعاد الخشب والتراب كما كانا. بعد ذلك جلس وكتب على ورقة صغيرة خمس كلمات:</p>\n<p><strong>لا تصدقوا الرجل الذي يعيد لكم أسماءكم.</strong></p>\n<p>طواها مرتين ووضعها داخل غطاء الكاميرا.</p>\n<p>حين خرج من البيت كانت الشمس قد بدأت تلوّن حافة الجبل. وجد سيارة سوداء تنتظره عند أول الطريق.</p>\n<p>لم يحاول الهرب.</p>\n<p>فتح الباب الخلفي وجلس.</p>\n<p>كان نادر السيوفي في الداخل، معطفه مغطى بغبار أبيض، وفي يده علبة الفيلم الفارغة.</p>\n<p>قال وهو يتأمل نعيم:</p>\n<p>- أين الصور؟</p>\n<p>نظر نعيم من النافذة إلى بيته الصغير، ثم إلى الجبل الذي بدا بريئًا تحت ضوء الصباح.</p>\n<p>- الصورة اللي بتدور عليها ما اتصورتش لسه.</p>\n<p>تحركت السيارة.</p>\n<p>ولم يعد نعيم عبد الوارث إلى بيته قط.</p>\n<div class=\"scene-break\" aria-hidden=\"true\"><span></span><span></span><span></span></div>"}, {"id": "chapter-1", "order": 1, "title": "الفصل الأول: سبعة وتسعون بالمئة", "section": "القسم الأول: العينة", "firstLine": "بدأ الأمر بإعلان رخيص ظهر ليوسف وهو يأكل فولًا باردًا أمام شاشة الكمبيوتر.", "wordCount": 876, "minutes": 5, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>بدأ الأمر بإعلان رخيص ظهر ليوسف وهو يأكل فولًا باردًا أمام شاشة الكمبيوتر.</p>\n<p>كان الإعلان لشاب من قرية في قنا، يرفع ورقة ملونة ويضحك للكاميرا: «طلعت سبعة وتسعين في المية مصري قديم يا جماعة! جدي كان فرعون وأنا معرفش.» خلفه صوت امرأة تصيح أن يترك الهاتف ويأتي ليحمل أسطوانة الغاز.</p>\n<p>ضحك يوسف، ثم أعاد المقطع.</p>\n<p>لم يكن مقتنعًا بتحليلات الأنساب. بحكم عمله في تصوير المباني الأثرية للفنادق وشركات الدعاية، سمع كثيرًا من الكلام عن شركات تبيع للناس ما يريدون سماعه. نصف زبائنها يخرجون أمراء، والنصف الآخر محاربين من الشمال، ولا أحد يخرج ابن خباز مات وهو مدين لبائع العدس.</p>\n<p>لكن اسم الشركة لفت نظره: <strong>جذور</strong>.</p>\n<p>كان شعارها كفًا بخمسة أصابع تتحول خطوطها إلى فروع شجرة.</p>\n<p>ظل يتأمله لحظة أطول من اللازم.</p>\n<p>نادته أمه من الغرفة الأخرى:</p>\n<p>- يوسف، الكهربائي هييجي إمتى؟</p>\n<p>- قال بعد الضهر.</p>\n<p>- بعد الضهر بتاع النهارده ولا بعد الضهر بتاع السنة الجاية؟</p>\n<p>- هكلمه تاني.</p>\n<p>عاد إلى الإعلان. العرض ينتهي بعد ست ساعات. عينة لعاب، تقرير أصل جغرافي، وربط اختياري بأقارب مجهولين. السعر أقل من نصف المعتاد لأن الشركة تطلق حملة خاصة في محافظات الصعيد تحت عنوان: «اعرف الحكاية التي يحملها دمك».</p>\n<p>ضغط زر الشراء بدافع لا يستحق اسم الفضول. ربما ملل. ربما لأن ذكرى جده نعيم عادت إليه في الليلة السابقة، مع أن الرجل اختفى قبل مولد يوسف بسنوات. أمه لا تتحدث عنه إلا لتقول إنه كان «دماغه ناشفة»، وعمّه عمران يقول إنه هرب مع بعثة أجنبية بعدما سرق قطعة أثرية.</p>\n<p>وصلت العلبة بعد يومين.</p>\n<p>بصق يوسف في الأنبوب أمام المرآة، وشعر بسخافة شديدة. كتب اسمه وتاريخ ميلاده، ثم تردد عند خانة «مكان ميلاد الأب والجد». كتب: القرنة، الأقصر. عند اسم الجد كتب «نعيم عبد الوارث»، ثم شطب الاسم. التعليمات لم تطلبه.</p>\n<p>مر شهر ونسي الأمر.</p>\n<p>في مساء خميس، بينما كان يصور واجهة بيت قديم في الدرب الأحمر، وصلته رسالة: <strong>نتيجتك جاهزة</strong>.</p>\n<p>فتحها وهو واقف فوق سلم معدني. ظهرت أمامه دائرة من الألوان: وادي النيل 82%، شمال أفريقيا 9%، شرق المتوسط 6%، غير محدد 3%. أسفلها عبارة دعائية تقول إن سلالته الأبوية «من أقدم السلالات المستمرة في جنوب الوادي».</p>\n<p>هز كتفيه.</p>\n<p>- يعني دفعت ألفين جنيه عشان أعرف إني من الأقصر.</p>\n<p>سمعه العامل الواقف تحته فقال:</p>\n<p>- ما كنت تسأل أمك يا باشمهندس، كانت قالت لك ببلاش.</p>\n<p>أغلق يوسف الصفحة، لكنه لاحظ قبل أن تختفي نافذة صغيرة حمراء في أسفل الشاشة:</p>\n<p><strong>تم العثور على تطابق أرشيفي استثنائي. لا يمكن عرض البيانات. سيتواصل معك مختص.</strong></p>\n<p>التقط لها صورة ثم أكمل عمله.</p>\n<p>جاء الاتصال في الثانية وسبع عشرة دقيقة بعد منتصف الليل.</p>\n<p>رقم أرضي من القاهرة.</p>\n<p>- أستاذ يوسف عبد الوارث؟</p>\n<p>كان صوت امرأة شابًا، لكنه متوتر كأنها تصعد درجًا.</p>\n<p>- أيوه.</p>\n<p>- أنا الدكتورة مريم الشناوي من معمل جذور. هل أنت وحدك؟</p>\n<p>نظر إلى أمه النائمة على الأريكة أمام التلفزيون. خفض الصوت.</p>\n<p>- تقريبًا. خير؟</p>\n<p>صمتت لحظة.</p>\n<p>- حضرتك فعّلت ربط العينة بالأقارب؟</p>\n<p>- غالبًا. هو فيه قريب غني ظهر؟</p>\n<p>لم تضحك.</p>\n<p>- ظهر تطابق ما ينفعش يظهر.</p>\n<p>جلس يوسف.</p>\n<p>- يعني إيه؟</p>\n<p>- عينة حضرتك اتقارنت بعينة مرجعية داخلية، مش موجودة في قاعدة بيانات العملاء. العينة المرجعية مأخوذة من بقايا بشرية محفوظة في مخزن أثري من سنة 1978. التقدير الأولي لعمرها أكثر من ثلاثة آلاف سنة.</p>\n<p>انتظر أن تكمل النكتة.</p>\n<p>لم تكمل.</p>\n<p>قال:</p>\n<p>- وتطابق إزاي؟</p>\n<p>- مش تطابق كامل طبعًا. خط أبوي نادر جدًا، ومقاطع متوارثة... بس النتيجة أقرب من الطبيعي بمراحل. النظام صنّفك تلقائيًا تحت كود داخلي اسمه V-5.</p>\n<p>- في فايف؟</p>\n<p>سمع صوت باب يُفتح عندها، ثم احتكاكًا سريعًا.</p>\n<p>قالت مريم بصوت أخفض:</p>\n<p>- اسمعني كويس. بكرة هيكلموك ويقولوا لك إن في خطأ تقني. ما تروحش مقر الشركة. وما تسلمش حد أي حاجة تخص جدك.</p>\n<p>شعر يوسف ببرودة في ذراعه.</p>\n<p>- جدي؟ أنتِ عرفتي اسم جدي منين؟</p>\n<p>انقطع نفسها.</p>\n<p>- هم ما كانوش بيدوروا على العينة. كانوا بيدوروا عليك.</p>\n<p>انقطع الخط.</p>\n<p>اتصل يوسف مرة ثانية. الرقم مشغول. في الثالثة أعطاه رسالة أن الرقم غير متاح.</p>\n<p>ظل جالسًا في الظلام، والهاتف في يده، حتى انتبه إلى أن أمه فتحت عينيها.</p>\n<p>قالت من غير أن تنهض:</p>\n<p>- مين كان بيكلمك؟</p>\n<p>- واحدة من المعمل.</p>\n<p>- معمل إيه؟</p>\n<p>- تحليل الـDNA.</p>\n<p>أغمضت عينيها ثم فتحتهما ببطء.</p>\n<p>- أنت عملت تحليل إيه؟</p>\n<p>حكى لها نصف الحقيقة. ترك المومياء والكود والتهديد، وقال فقط إن النتيجة أظهرت قرابة بعيدة تخص جده.</p>\n<p>جلست أمه. اختفى النعاس من وجهها.</p>\n<p>- يوسف، امسح النتيجة دي.</p>\n<p>- ليه؟</p>\n<p>- عشان بقول لك.</p>\n<p>- هو جدي كان عمل إيه بالضبط؟</p>\n<p>قامت من مكانها، وأغلقت باب الشرفة رغم أن الجو حار.</p>\n<p>- جدك ما كانش حرامي، لو ده اللي عايز تعرفه. لكن الناس اللي قالت عليه حرامي كانوا يقدروا يخلوا الشمس تطلع من الغرب في الورق الرسمي.</p>\n<p>اقترب منها.</p>\n<p>- وإيه اللي حصل له؟</p>\n<p>- اختفى.</p>\n<p>- دي مش إجابة.</p>\n<p>نظرت إليه، وفي عينيها شيء رآه للمرة الأولى: خوف قديم، محفوظ بعناية حتى صار جزءًا من ملامحها.</p>\n<p>- لأن مفيش إجابة غيرها.</p>\n<p>رن جرس الباب.</p>\n<p>كانت الساعة تقترب من الثالثة صباحًا.</p>\n<p>لم يتحرك أي منهما.</p>\n<p>رن الجرس مرة ثانية، ثم جاء صوت رجل من الخارج:</p>\n<p>- طرد للأستاذ يوسف.</p>\n<p>همست أمه:</p>\n<p>- ما تفتحش.</p>\n<p>اقترب يوسف من العين السحرية. لم يرَ أحدًا. فقط ممر العمارة الأصفر وكيسًا بنيًا على الأرض.</p>\n<p>انتظر خمس دقائق قبل أن يفتح. كان الكيس خفيفًا، بلا اسم مرسل. بداخله علبة بلاستيكية صغيرة، فيها مفتاح ذاكرة أسود وقطعة نحاسية مستديرة عليها خمس شقوق.</p>\n<p>وعلى ورقة لاصقة، بخط متعجل:</p>\n<p><strong>أنا آسفة. لو وصلت لك دي، يبقى هم سبقوني. افتح الملف عند شخص تثق به، من جهاز غير متصل بالإنترنت. لا تثق في الرجل الذي سيعرض أن يعيد لك اسم جدك. - مريم</strong></p>\n<p>رفع يوسف عينيه نحو أمه.</p>\n<p>كانت تحدق في القطعة النحاسية.</p>\n<p>قالت بصوت خافت:</p>\n<p>- دي كانت في رقبة أبويا.</p>"}, {"id": "chapter-2", "order": 2, "title": "الفصل الثاني: بيت تحت التراب", "section": "القسم الأول: العينة", "firstLine": "في الظهيرة، اتصلت شركة جذور.", "wordCount": 858, "minutes": 5, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>في الظهيرة، اتصلت شركة جذور.</p>\n<p>هذه المرة كان المتحدث رجلًا ذا صوت دافئ مدرّب على طمأنة العملاء.</p>\n<p>- أستاذ يوسف، معك هاني من إدارة العلاقات العلمية. حصل خلل في تقريرك الليلة الماضية، ونعتذر جدًا عن الإزعاج.</p>\n<p>- أي خلل؟</p>\n<p>- نظامنا أظهر تنبيهًا تجريبيًا خاصًا بعينات البحث الأثري. لا يوجد تطابق حقيقي، وطبعًا بياناتك في أمان كامل.</p>\n<p>- والدكتورة مريم؟</p>\n<p>تأخر الرد نصف ثانية.</p>\n<p>- مريم مين يا فندم؟</p>\n<p>- الشناوي. من المعمل عندكم.</p>\n<p>- لا يوجد عندنا موظفة بالاسم ده.</p>\n<p>أنهى يوسف المكالمة من غير أن يودع.</p>\n<p>لم يفتح ذاكرة مريم في البيت. أخذها إلى مكتب صديقه القديم شادي، الذي يدير محل صيانة كمبيوتر في شارع جانبي بمدينة نصر. أغلق شادي باب المحل، وفصل جهازًا قديمًا عن الشبكة، ثم ارتدى قفازين ساخرًا:</p>\n<p>- إحنا بنفتح فلاشة ولا هنشيل قنبلة؟</p>\n<p>- افتح بس.</p>\n<p>احتوت الذاكرة على ثلاثة ملفات. ملف نصي مشفر، صورة لصفحة من قاعدة بيانات، وتسجيل صوتي مدته سبع وأربعون ثانية.</p>\n<p>شغل يوسف التسجيل.</p>\n<p>ظهر صوت مريم، هذه المرة أهدأ:</p>\n<p>«لو أنت بتسمعني، غالبًا أنا ما قدرتش أقابلك. الشركة بدأت مشروع اسمه سلسلة خمسة من تسع سنين. جمعوا عينات من قرى بعينها في قنا والأقصر وسوهاج، تحت ستار دراسات أنساب مجانية. كانوا بيدوروا على نمط كروموسوم Y مرتبط بعينة عظمية اسمها A-17. لما عينتك دخلت، النظام بعت تنبيه للرئيس التنفيذي شخصيًا. فتحت السجل، ولقيت أربع حالات أقدم اتعلم عليها بكلمة CLOSED. اتنين ماتوا في حوادث، واحد اختفى، والرابع ملفه اتمسح. اسم جدك موجود في المستندات الورقية للمشروع، من سنة 1978. ما عرفتش ليه. الصورة فيها كل اللي قدرت أنسخه. كلمة السر للملف: تاريخ اختفاء جدك، ثمانية أرقام.»</p>\n<p>انتهى التسجيل بصوت طرق على باب ثم نفس حاد.</p>\n<p>قال شادي:</p>\n<p>- دي مش شركة تحاليل. دي جماعة فيلم جيمس بوند.</p>\n<p>فتح يوسف الصورة. كانت لقطة شاشة لصفحة داخلية تحمل شعار جذور، وفيها جدول بأسماء مشفرة، تواريخ، ودرجات قرابة. في أعلى الصفحة: <strong>PROJECT LINE V / ACTIVE SUBJECT: Y.A.W.</strong></p>\n<p>أسفلها صورة لعظمة صغيرة بجوار مسطرة قياس، ثم صورة فوتوغرافية باهتة لرجل بجلباب أبيض يقف أمام مدخل صخري. رغم رداءة الصورة، عرف يوسف الرجل من صورة واحدة معلقة في بيت عمه بالأقصر.</p>\n<p>نعيم عبد الوارث.</p>\n<p>إلى جوار الصورة سطر بالإنجليزية: <strong>Local guide. Suspected theft. Missing after breach. Asset not recovered.</strong></p>\n<p>قال شادي:</p>\n<p>- تعرف اختفى إمتى؟</p>\n<p>- أمي كانت طفلة. أواخر السبعينات.</p>\n<p>اتصل بها. رفضت في البداية، ثم قالت: السابع عشر من يناير 1978.</p>\n<p>كتب 17011978.</p>\n<p>انفتح الملف.</p>\n<p>احتوى على تقرير ممسوح ضوئيًا من ست صفحات، صادر عن بعثة أثرية خاصة لم يسمع بها يوسف. كانت أسماء المشاركين مطموسة إلا اسمين: الدكتور نادر حلمي السيوفي، ومساعدة نقوش شابة تُدعى ليلى منصور. يذكر التقرير العثور على «فراغ معماري غير مسجل» خلف مقبرة صغيرة، ثم توقف الحفر بسبب «انهيار أمني وسرقة أحد العمال المحليين لعينات وصور».</p>\n<p>في الصفحة الأخيرة قائمة مفقودات:</p>\n<p>- عينة عظمية A-17.<br>- خاتم نحاسي مشقوق العلامة.<br>- فيلم فوتوغرافي غير محمض.<br>- دليل الحجرة الخامسة.</p>\n<p>أخرج يوسف القطعة النحاسية من جيبه. وضعها إلى جوار الشاشة. كانت بحجم عملة قديمة، وعلى وجهها رأس حيوان طويل الأذنين مشقوق بخط عمودي. على الحافة خمس شقوق، أربعة منها ضحلة، والخامس أعمق.</p>\n<p>قال شادي:</p>\n<p>- يا ابني سلم الكلام ده للشرطة.</p>\n<p>- أقول لهم إيه؟ شركة تحاليل بتدور على خرزة جدي؟</p>\n<p>- قول لهم إن البنت اللي بعتت لك مهددة.</p>\n<p>بحث يوسف عن اسم مريم الشناوي. ظهرت حسابات كثيرة، ثم خبر منشور منذ أقل من ساعة:</p>\n<p><strong>وفاة باحثة شابة إثر سقوطها من شرفة منزلها في المعادي. التحقيقات الأولية ترجح الانتحار.</strong></p>\n<p>كانت الصورة لمريم.</p>\n<p>لم يقل يوسف شيئًا.</p>\n<p>أغلق شادي صفحة الخبر، ثم نظر إليه:</p>\n<p>- الشرطة. دلوقتي.</p>\n<p>لكن قبل أن ينهضا، انطفأت أنوار المحل.</p>\n<p>جاء صوت حركة عند الباب الخلفي.</p>\n<p>همس شادي:</p>\n<p>- مفيش باب خلفي.</p>\n<p>كان يقصد أن الباب لا يُستخدم، وأن خزانة معدنية تقف أمامه منذ سنوات. إلا أن الخزانة تحركت الآن ببطء، تصدر صريرًا فوق الأرض.</p>\n<p>أطفأ يوسف شاشة الكمبيوتر وانتزع ذاكرة مريم. في العتمة، سمع ضربة مكتومة ثم تأوه شادي. مد يده فلم يجد إلا الهواء.</p>\n<p>ظهر ضوء هاتف في آخر المحل، وخلفه رجل ضخم يرتدي قناعًا طبيًا. لم يتكلم. اندفع مباشرة نحو يوسف.</p>\n<p>رفع يوسف كرسيًا بلاستيكيًا في وجهه. انكسر الكرسي من الضربة الأولى. أمسك الرجل بذراعه، فغرس يوسف القطعة النحاسية في ظاهر يده بكل قوته. صرخ الرجل وتركه.</p>\n<p>ركض يوسف نحو الواجهة، اصطدم بطاولة، ثم قفز فوق صندوق طابعات. كان الباب الزجاجي مقفولًا. شادي، من الأرض، رمى إليه سلسلة المفاتيح.</p>\n<p>فتح يوسف الباب واندفع إلى الشارع.</p>\n<p>لم يتبعه الرجل.</p>\n<p>بعد عشر دقائق وصلت الشرطة. لم يجدوا في المحل إلا شادي مصابًا بجرح في رأسه، وخزانة محطمة، وكاميرات مراقبة توقفت قبل الحادث بدقيقة. وصف يوسف الرجل، لكنه لم يرَ من وجهه شيئًا.</p>\n<p>تولى المحضر ضابط مباحث اسمه عمر خطاب، في منتصف الثلاثينات، له عينان لا تفصحان إن كان يصدق أو يسخر. استمع إلى حكاية مريم والـDNA والبعثة القديمة دون أن يقاطعه. ثم قال:</p>\n<p>- الفلاشة معاك؟</p>\n<p>تردد يوسف.</p>\n<p>- ضاعت في الخناقة.</p>\n<p>نظر عمر إلى جيب قميصه المنتفخ، ثم كتب الجملة كما قالها.</p>\n<p>- والقطعة النحاسية؟</p>\n<p>- إيه؟</p>\n<p>- شادي قال إنك ضربت الراجل بقطعة نحاس.</p>\n<p>- وقعت.</p>\n<p>رفع الضابط عينيه.</p>\n<p>- أنت كده بتضيع وقتي ولا بتحمي نفسك؟</p>\n<p>- الاتنين احتمال.</p>\n<p>أغلق عمر الدفتر.</p>\n<p>- خليك قريب. وما تسافرش.</p>\n<p>في تلك اللحظة وصل إلى هاتف يوسف إشعار برسالة بريد إلكتروني من عنوان رسمي لشركة جذور:</p>\n<p><strong>دعوة شخصية من السيد رائف السيوفي، الرئيس التنفيذي. نود مناقشة اكتشاف قد يعيد لأسرتكم اعتبارها التاريخي.</strong></p>\n<p>أسفل الدعوة صورة لرائف السيوفي، رجل أنيق في أوائل الأربعينات، يبتسم أمام واجهة متحف.</p>\n<p>قرأ يوسف الاسم مرتين.</p>\n<p>السيوفي.</p>\n<p>نفس اسم رئيس بعثة 1978.</p>"}, {"id": "chapter-3", "order": 3, "title": "الفصل الثالث: حوري", "section": "القسم الأول: العينة", "firstLine": "طيبة، العام التاسع والعشرون من حكم الملك", "wordCount": 749, "minutes": 4, "era": "مصر القديمة", "theme": "ancient", "sound": "stone", "icon": "𓂀", "scene": "طيبة — وادي النيل", "html": "<p>طيبة، العام التاسع والعشرون من حكم الملك</p>\n<p>عرف حوري أن معلمه سيموت قبل أن يسقط.</p>\n<p>رأى ذلك في الطريقة التي أمسك بها جحوتي مسند الطاولة. لم يكن الرجل عجوزًا، لكنه بدا فجأة كمن فقد ثقله، كأن روحه صعدت إلى أعلى وبقي جسده يبحث عنها. انقلب قدح الجعة، وسال على البردية التي أمضيا فيها أسبوعًا كاملًا يسجلان أجور العمال.</p>\n<p>مد حوري يده ليمسكه، إلا أن كبير المشرفين باحري سبقه.</p>\n<p>قال باحري:</p>\n<p>- يبدو أن كاتبنا شرب أكثر مما يحتمل.</p>\n<p>كان يبتسم.</p>\n<p>لم ينظر أحد إلى الإبرة البرونزية الصغيرة التي سحبها من رقبة جحوتي وأخفاها داخل كمه. لم يرها إلا حوري، لأنه كان جالسًا على الأرض يجمع لفائف الحسابات، ولأن الشمس دخلت من فتحة السقف وانعكست على رأسها لحظة واحدة.</p>\n<p>سقط جحوتي على ركبتيه. بحثت عيناه عن حوري.</p>\n<p>قال كلمة واحدة لم يسمعها سواه:</p>\n<p>- الخامس.</p>\n<p>ثم مات.</p>\n<p>امتلأت دار السجلات بالصراخ. جاء الحراس، وأُبعد الكتبة الصغار، وأمر باحري أن يقال إن جحوتي أصيب بسكتة من الحر. لم يعترض أحد. كان باحري مسؤولًا عن مخازن الحبوب، وعن رجال يحملون العصي، وعن نصف البطون التي تشبع أو تجوع في قرية العمال.</p>\n<p>في المساء، عاد حوري إلى بيته وهو يحمل سلة المعلم. كانت زوجته مريت تطحن الشعير قرب الباب. رفعت رأسها وقالت:</p>\n<p>- لماذا جئت بأشياء جحوتي؟</p>\n<p>- مات.</p>\n<p>توقفت يدها.</p>\n<p>كان جحوتي قد علم حوري الكتابة حين كان صبيًا ينقل الماء. كان يقول إن اليد التي تعرف كتابة الاسم تستطيع أن تمنع صاحب الاسم من الموت مرة ثانية.</p>\n<p>وضع حوري السلة على الأرض. فيها أقلام بردي، حجر حبر، قطعة خبز يابس، وتميمة خشبية رخيصة. لا شيء يفسر الكلمة الأخيرة.</p>\n<p>قلب السلة، فسقط قاعها المزدوج.</p>\n<p>خرج منه قرص نحاسي صغير، عليه رأس ابن آوى مشقوق، وحوله خمس شقوق.</p>\n<p>شهقت مريت.</p>\n<p>- ارمِه في النهر.</p>\n<p>- تعرفينه؟</p>\n<p>- أبي رسم العلامة مرة على بابنا ثم محاها. قال إن من يراها يسأل أسئلة لا يعود منها.</p>\n<p>وجد حوري تحت القرص شريطًا من الكتان كُتبت عليه جملة بحبر أحمر:</p>\n<p><strong>إذا مات حامل الاسم، فليحمل الكاتب الشاهد إلى البيت الذي تحت التراب. لا يفتح الباب إلا خمس مرات.</strong></p>\n<p>قالت مريت:</p>\n<p>- سنغادر القرية الليلة.</p>\n<p>هز رأسه.</p>\n<p>- بوابات الجبل مغلقة. وباحري يعرف أنني كنت آخر من جلس مع جحوتي.</p>\n<p>طرق أحدهم الباب.</p>\n<p>لم يكن طرق جار. ثلاث ضربات متساوية، ثم صمت.</p>\n<p>أخفت مريت القرص داخل جرة دقيق. فتح حوري.</p>\n<p>كان رجلان من حرس المخزن.</p>\n<p>قال أحدهما:</p>\n<p>- كبير المشرفين يريد سلة الكاتب المتوفى.</p>\n<p>أعطاهم السلة الفارغة. فتشا البيت، قلبا الحصر، وكسرا جرة زيت. مر أحدهما بيده فوق جرة الدقيق لكنه لم يفتحها. قبل أن يخرجا، قال:</p>\n<p>- غدًا ستأتي إلى دار السجلات. ستكتب شهادة أن معلمك كان يسرق من حسابات الملك.</p>\n<p>- لم يكن يسرق.</p>\n<p>ابتسم الرجل.</p>\n<p>- لهذا ستحتاج أن تكتبها جيدًا.</p>\n<p>بعد رحيلهما، أخرجت مريت القرص.</p>\n<p>- الآن ستفعل ما قلته. تهرب.</p>\n<p>لكن حوري كان ينظر إلى بقعة الجعة التي لطخت طرف بردية الأجور في ذاكرته. قبل موته بأيام، اكتشف جحوتي أن أكياس الحبوب المخصصة لعمال المقابر تُسجل كاملة في دار السجلات، ثم تصل ناقصة إلى القرية. الأسماء الموقعة باستلام الأجور كانت لأشخاص ماتوا، أو أطفال، أو رجال لم يوجدوا قط. باحري لا يسرق ذهبًا من مقبرة؛ كان يسرق الخبز من أفواه الأحياء، ويقتل من يعدّ الأرغفة.</p>\n<p>قال حوري:</p>\n<p>- لو كتبت الشهادة، سيصبح هو اللص في السجلات إلى الأبد.</p>\n<p>- ولو لم تكتبها ستصبح أنت ميتًا إلى الأبد.</p>\n<p>أمسك القرص. كان دافئًا من الدقيق.</p>\n<p>- جحوتي لم يقل اهرب. قال الخامس.</p>\n<p>في منتصف الليل خرجا من البيت. مريت تسير خلفه وهي تحمل مصباحًا مغطى. عبر حوري ممر العمال، ثم اتجه إلى مقبرة صغيرة غير مكتملة كان جحوتي يصحبه إليها بحجة قياس الجدران. عند الحائط الغربي وجد خمس تجاويف في الصخر. أدخل القرص في التجويف الأول.</p>\n<p>سمع صوت حجر يتحرك تحت قدميه.</p>\n<p>انفتح شق ضيق في الأرض، صعد منه هواء بارد له رائحة ورق قديم.</p>\n<p>قالت مريت:</p>\n<p>- لا تنزل.</p>\n<p>لكنه نزل.</p>\n<p>كانت الحجرة منخفضة، جدرانها بلا رسوم ملكية. فقط رفوف من الطين فوقها لفائف، وجرار مختومة، وألواح تحمل أسماء مئات العمال. في الوسط جلس جحوتي مرسومًا على الجدار، لا بثياب كاتب ملكي، بل بثوب بسيط، وإلى جواره أربعة أشخاص لم تُرسم وجوههم بعد.</p>\n<p>تحت الرسم عبارة:</p>\n<p><strong>لا نحفظ سر الملك. نحفظ أسماء الذين بنوا سره.</strong></p>\n<p>وجد حوري سجلًا يثبت سرقات باحري، ورسائل من عمال ماتوا في انهيار أخفاه المشرف، وخريطة لمخزن طوارئ نُقلت إليه أجور القرية حين عمّت الفوضى. كان الذهب قليلًا، لكن الدليل يكفي لإعدام رجال كبار.</p>\n<p>سمع وقع أقدام فوقهم.</p>\n<p>أطفأت مريت المصباح.</p>\n<p>جاء صوت باحري من فتحة الحجرة:</p>\n<p>- كنت أعرف أن العجوز اختارك.</p>\n<p>ظهر وجهه في الشق، مبتسمًا.</p>\n<p>- أعطني القرص يا حوري، وسأدع زوجتك تحتفظ بالطفل الذي في بطنها.</p>\n<p>وضع حوري يده على بطن مريت دون أن ينظر إليها. لم تكن قد أخبرته بعد.</p>\n<p>فهم من ارتجافها أن باحري يقول الحقيقة.</p>\n<p>وفهم أيضًا أن الرجل لا ينوي ترك أحد.</p>"}, {"id": "chapter-4", "order": 4, "title": "الفصل الرابع: الرجل الذي يعيد الأسماء", "section": "القسم الأول: العينة", "firstLine": "وصل يوسف إلى مقر جذور في التجمع الخامس بعد أن أرسل نسخة من الملفات إلى بريد أنشأه باسم مستعار، وترك القطعة النحاسية عند أمه. لم يخبرها أنه ذاهب. قال إن لديه تصويرًا صباحيًا، فوضعت له سندوتشين جبنة في حقيبته كأن الخطر يمكن منعه بالطعام.", "wordCount": 721, "minutes": 4, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>وصل يوسف إلى مقر جذور في التجمع الخامس بعد أن أرسل نسخة من الملفات إلى بريد أنشأه باسم مستعار، وترك القطعة النحاسية عند أمه. لم يخبرها أنه ذاهب. قال إن لديه تصويرًا صباحيًا، فوضعت له سندوتشين جبنة في حقيبته كأن الخطر يمكن منعه بالطعام.</p>\n<p>مبنى الشركة من الزجاج والحجر الأبيض، تحيط به أشجار زيتون صغيرة مزروعة في صفوف دقيقة. في البهو شاشة ضخمة تعرض وجوه مصريين من أعمار مختلفة، وتحت كل وجه نسبة مئوية وقصة قصيرة: «وجدت عائلتي بعد أربعين عامًا»، «اكتشفت أن جذوري أقدم مما تخيلت»، «الدم لا ينسى».</p>\n<p>استقبله موظف ببدلة رمادية، وصعد به إلى الطابق الأخير.</p>\n<p>كان مكتب رائف السيوفي أوسع من شقة يوسف. لا أوراق على الطاولة، ولا صور عائلية، فقط تمثال حجري صغير بلا رأس داخل صندوق زجاجي.</p>\n<p>نهض رائف لمصافحته. في الصور بدا وسيمًا؛ في الحقيقة كان أكثر هدوءًا وأقل ابتسامًا. عيناه ثابتتان كعيني شخص اعتاد أن ينتظر الآخرين حتى يكشفوا أنفسهم.</p>\n<p>- أخيرًا قابلت يوسف عبد الوارث.</p>\n<p>- واضح إن حضرتك مستنيني من زمان.</p>\n<p>أشار إلى مقعد.</p>\n<p>- منذ قبل أن تؤسس الشركة أصلًا، لو أردت الدقة.</p>\n<p>لم يجلس يوسف فورًا.</p>\n<p>- فين الدكتورة مريم؟</p>\n<p>اختفت الابتسامة القليلة.</p>\n<p>- حادث مؤسف. كانت موظفة موهوبة، وتعاني للأسف من مشكلات شخصية.</p>\n<p>- قالوا لي إنها مش موظفة عندكم.</p>\n<p>- خدمة العملاء لا تعرف أسماء كل الباحثين.</p>\n<p>جلس يوسف.</p>\n<p>- وعينة جدي؟</p>\n<p>- ليست عينة جدك.</p>\n<p>فتح رائف شاشة على الحائط. ظهرت صورة العظمة A-17، ثم رسم لشجرة وراثية معقدة.</p>\n<p>- هذه قطعة من ضلع رجل مات تقريبًا في القرن الثاني عشر قبل الميلاد. عثر عليها والدي ضمن مشروع أثري سنة 1978. كانت خارج سياقها الأصلي، ولذلك لم تُسجل رسميًا. قبل سنوات أعدنا تحليلها، واكتشفنا خطًا أبويًا شديد الندرة. جمعنا عينات كثيرة للبحث عن امتداده الحديث.</p>\n<p>- من غير ما تقولوا للناس إنهم فئران تجارب.</p>\n<p>- وافق كل عميل على استخدام مجهول للبيانات البحثية.</p>\n<p>- محدش بيقرأ أربعين صفحة شروط عشان يبصق في أنبوبة.</p>\n<p>ابتسم رائف هذه المرة بصدق قصير.</p>\n<p>- لهذا ينجح العالم الحديث.</p>\n<p>كبّر صورة الشجرة. عند طرفها اسم يوسف.</p>\n<p>- أنت أقرب امتداد حي وصلنا إليه. ليس معنى ذلك أنك حفيده المباشر؛ ثلاثة آلاف عام تجعل العبارة طفولية. لكن هناك استمرارية واضحة داخل خط عائلتك، ومعها شيء آخر.</p>\n<p>ظهرت صورة جده نعيم.</p>\n<p>- جدك عمل مع والدي. ثم سرق قطعة وفيلمًا وقاد البعثة إلى مكان غير مسجل. بعد اختفائه لُطخت سمعته. أستطيع إعادة اسمه إلى السجلات بوصفه مكتشفًا لا لصًا.</p>\n<p>تذكر يوسف جملة مريم: لا تثق في الرجل الذي سيعرض أن يعيد لك اسم جدك.</p>\n<p>قال:</p>\n<p>- مقابل إيه؟</p>\n<p>- مساعدتك في العثور على ما وجده.</p>\n<p>- أنا اتولدت بعد ما اختفى بعشرين سنة.</p>\n<p>- لكن عائلتك احتفظت بشيء. رمز، حكاية، قطعة معدنية، ربما صورة.</p>\n<p>كانت نبرة رائف عادية، إلا أن عينيه انتقلتا إلى جيب يوسف لحظة ذكر القطعة.</p>\n<p>قال يوسف:</p>\n<p>- ولو قلت لك معنديش؟</p>\n<p>- سأصدق أنك لا تعرف أن لديك.</p>\n<p>فتح رائف درجًا وأخرج ملفًا ورقيًا. دفعه نحوه. في الصفحة الأولى صورة من محضر شرطة قديم: نعيم عبد الوارث متهم بسرقة آثار والهرب. في الصفحة الثانية طلب قدمته زهية، زوجته، بعد عام لإعادة التحقيق، وعليه ختم «حفظ».</p>\n<p>- أمك عاشت ابنة رجل اتُّهم بالسرقة. عمك كبر وهو يسمع أن أباه هرب. يمكننا تصحيح ذلك.</p>\n<p>قلب يوسف الصفحات. وجد صورة لجدته شابة تحمل أمه الرضيعة أمام قسم الشرطة. لم يرَ الصورة من قبل.</p>\n<p>- ليه يهمك؟</p>\n<p>- لأن والدي مات وهو مقتنع أن نعيم خدعه. وأنا لا أحب أن أورث أخطاء الآباء.</p>\n<p>- لكنك ورثت العينة.</p>\n<p>سكت رائف قليلًا.</p>\n<p>ثم قال:</p>\n<p>- مريم أخذت بيانات لا تخصها. وأرسلت لك أشياء ليست ملكها. أعطني ما أرسلته، وسنعتبر أنك لم تعرف شيئًا.</p>\n<p>- أنت قلت مش عارف بعتت لي إيه.</p>\n<p>- لم أقل ذلك.</p>\n<p>انفتح باب المكتب، ودخل الرجل الذي هاجم يوسف في محل شادي.</p>\n<p>كان بلا قناع هذه المرة. على ظاهر يده جرح دائري حديث.</p>\n<p>قدمه رائف بهدوء:</p>\n<p>- حازم راضي، مدير الأمن.</p>\n<p>نهض يوسف.</p>\n<p>- أمن الشركة بيكسر محلات الكمبيوتر؟</p>\n<p>نظر حازم إليه من دون تعبير.</p>\n<p>قال رائف:</p>\n<p>- حازم يتصرف أحيانًا بحماس زائد. اعتبر اعتذاري شخصيًا.</p>\n<p>- والبنت اللي وقعت من البلكونة؟ حماس زائد برضه؟</p>\n<p>لأول مرة تغير وجه رائف. لم يغضب، بل برد.</p>\n<p>- الاتهامات الكبيرة تحتاج ظهرًا كبيرًا يا يوسف. وأنت جئت وحدك.</p>\n<p>وضع يوسف الملف القديم تحت ذراعه.</p>\n<p>- مش لوحدي.</p>\n<p>كان يكذب، لكنه قالها بثقة جعلت حازم ينظر إلى رائف.</p>\n<p>خرج من المكتب. لم يمنعه أحد.</p>\n<p>في المصعد، وجد رسالة من رقم مجهول:</p>\n<p><strong>الضابط عمر خطاب يعمل معهم. لا تعد إلى بيتك. اذهب إلى الأقصر، وابحث عن الدكتورة ليلى منصور قبل أن يصلوا إليها.</strong></p>\n<p>ثم وصلت صورة لامرأة مسنة تجلس أمام بيت ريفي. خلفها على الحائط كف سوداء لها خمسة أصابع.</p>\n<p>وعند باب المبنى الزجاجي، كان عمر خطاب ينتظره.</p>"}, {"id": "chapter-5", "order": 5, "title": "الفصل الخامس: الضابط الذي يعرف أكثر مما ينبغي", "section": "القسم الأول: العينة", "firstLine": "كان عمر خطاب واقفًا بجوار سيارة رمادية لا تحمل أي علامة. لم يقترب من يوسف، ولم يرفع يده بتحية. اكتفى بأن أشار إلى المقعد المجاور للسائق.", "wordCount": 818, "minutes": 5, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>كان عمر خطاب واقفًا بجوار سيارة رمادية لا تحمل أي علامة. لم يقترب من يوسف، ولم يرفع يده بتحية. اكتفى بأن أشار إلى المقعد المجاور للسائق.</p>\n<p>قال يوسف:</p>\n<p>- حضرتك بتتبعني؟</p>\n<p>- لو كنت بتتبعك ما كنتش وقفت قدامك.</p>\n<p>- ممكن تكون بتوفر بنزين.</p>\n<p>نظر عمر إلى باب الشركة الزجاجي، حيث ظهر حازم للحظة ثم اختفى.</p>\n<p>- اركب. عندك اختيار تاني إنك تمشي، بس الراجل اللي فوق هيعرف أنت رايح فين قبل ما تطلب أوبر.</p>\n<p>لم يكن في كلامه ما يطمئن. مع ذلك ركب يوسف، ووضع الملف القديم بين قدميه. تحركت السيارة من غير أن يسأله عمر عن وجهته.</p>\n<p>قال يوسف:</p>\n<p>- وصلت لك رسالة بتقول إنك شغال معاهم؟</p>\n<p>- لا. بس شكلك وصل لك.</p>\n<p>- ما جاوبتش.</p>\n<p>- وأنت ما سلمتنيش الفلاشة.</p>\n<p>مرّا بجوار صف من المقاهي اللامعة. في زجاج أحدها رأى يوسف انعكاس سيارة سوداء خلفهما.</p>\n<p>قال عمر:</p>\n<p>- عربية جذور؟</p>\n<p>- مش عارف.</p>\n<p>- عارف.</p>\n<p>انعطف فجأة إلى طريق جانبي، ثم دخل محطة وقود وخرج من الممر الآخر. اختفت السيارة السوداء.</p>\n<p>- مريم الشناوي ما انتحرتش، قال عمر.</p>\n<p>ثبت يوسف نظره أمامه.</p>\n<p>- عرفت منين؟</p>\n<p>- باب شقتها كان مقفول من الداخل، وده اللي خلّى النيابة تميل للانتحار. لكن مزلاج الشرفة اتفتح واتقفل من بره بأداة رفيعة. وفي جلدها أثر حقنة. التقرير الأولي ما كتبش ده.</p>\n<p>- ليه؟</p>\n<p>- لأن حد اتصل بالطبيب الشرعي قبل ما يوصل الجثمان.</p>\n<p>- رائف؟</p>\n<p>- ما عنديش دليل.</p>\n<p>- وعندك دليل إني معايا الفلاشة؟</p>\n<p>- عندي عقل.</p>\n<p>وصل عمر إلى كوبري، وأبطأ السرعة. النيل تحته رمادي، عريض، لا يبالي بمن يطارده أحد.</p>\n<p>- مريم بعتت رسالة لرقم طوارئ قبل موتها بساعة، قال عمر. الرقم كان رقمي. ما أعرفهاش شخصيًا، لكن أخوها كان زميلي في الكلية. كتبت: «لو حصل لي حاجة، اسأل عن سلسلة خمسة.» وبعدها بعتت اسمك.</p>\n<p>التفت إليه يوسف.</p>\n<p>- ليه ما قلتش الكلام ده في المحل؟</p>\n<p>- عشان المحضر بيتصور قبل ما الحبر ينشف. وعشان القسم عندي فيه ناس بتقبض مرتبها من الدولة ومكافأتها من شركات أمن خاصة.</p>\n<p>- يعني أنت مش معاهم؟</p>\n<p>- أنا مع اللي يثبت. لحد دلوقتي أنت راجل خبّى دليل، وكذب في محضر، وراح يقابل مشتبه به لوحده. دي مش مواصفات شاهد مريح.</p>\n<p>أخرج يوسف ذاكرة مريم من جيبه، لكنه لم يسلمها.</p>\n<p>- فيها تقرير عن بعثة سنة 1978.</p>\n<p>- عارف.</p>\n<p>- منين؟</p>\n<p>أشار عمر إلى الملف تحت قدميه.</p>\n<p>- لأن النسخة اللي معاك ناقصة صفحة.</p>\n<p>توقفت السيارة عند رصيف هادئ. أخرج عمر من درجها صورة مطبوعة ووضعها على المقود. كانت صفحة من تقرير البعثة، تحمل قائمة أفرادها كاملة. الاسم الأول نادر حلمي السيوفي، يليه ليلى منصور، ثم مهندس مسح أجنبي، وطبيب، ونعيم عبد الوارث بصفته «حارس موقع مؤقت».</p>\n<p>في آخر القائمة اسم صغير محاط بقلم أحمر:</p>\n<p><strong>الملازم فؤاد خطاب - شرطة السياحة والآثار.</strong></p>\n<p>قال عمر:</p>\n<p>- أبويا.</p>\n<p>نظر يوسف إليه.</p>\n<p>- كان معاهم؟</p>\n<p>- اختفى بعد جدك بأسبوعين. الملف الرسمي بيقول نقلوه لأسوان، لكن مفيش قرار نقل. أمي فضلت مستنياه عشر سنين قبل ما تعتبره ميت.</p>\n<p>صمتا. لأول مرة بدا عمر أقل من ضابط وأكثر من طفل كبر وهو يكره سؤالًا واحدًا.</p>\n<p>قال:</p>\n<p>- رائف مش عايز مجرد أثر. أبوه مات من سبع سنين، وبعد موته تأسست جذور بفلوس مؤسسة السيوفي للتراث. الشركة خسرت في أول خمس سنين، ومع ذلك صرفت ملايين على حملات مجانية في قرى محددة. دي مش تجارة، دي شبكة صيد.</p>\n<p>- وأنا السمكة؟</p>\n<p>- أنت أول عينة وصلت للحد اللي كانوا مستنيينه.</p>\n<p>- الرسالة قالت أروح للدكتورة ليلى منصور.</p>\n<p>- عارف مكانها؟</p>\n<p>أراه يوسف الصورة.</p>\n<p>تفحصها عمر ثم قال:</p>\n<p>- البيت ده في أرمنت، غالبًا. شكل الحيطان وطريقة الشبابيك. هتسافر؟</p>\n<p>- أيوه.</p>\n<p>- قالوا لك ما تسافرش.</p>\n<p>- حضرتك اللي قلت.</p>\n<p>- قلت خليك قريب، ما قلتش خليك مطيع.</p>\n<p>أدار السيارة، ثم مد يده.</p>\n<p>- الفلاشة.</p>\n<p>- نسخة.</p>\n<p>- دلوقتي.</p>\n<p>أعطاه يوسف نسخة صنعها شادي قبل الهجوم. لم يخبره أنها نسخة. أخذها عمر ووضعها في كيس أدلة.</p>\n<p>- هتروح القطار الليلة. ما تحجزش باسمك. خد خط تليفون جديد، وسيب موبايلك شغال في القاهرة عند حد تثق فيه. وأنا هحاول أوصل قبلك بيوم.</p>\n<p>- ليه قبلي؟</p>\n<p>- لأن الرسالة اللي وصلتك مش من مريم.</p>\n<p>شعر يوسف بأن الهواء صار أثقل.</p>\n<p>- عرفت إزاي؟</p>\n<p>- وقت إرسالها كانت مريم ميتة بثماني ساعات.</p>\n<p>نظر إلى الصورة مرة أخرى. المرأة المسنة أمام الحائط، والكف السوداء خلفها.</p>\n<p>قال عمر:</p>\n<p>- حد عايزك تروح ليلى. السؤال مش هل دي فخ. السؤال مين حاطط الفخ لمين.</p>\n<p>عند المساء ترك يوسف هاتفه عند شادي، وأعطاه تعليمات أن يرد برسائل قصيرة كل عدة ساعات. اشترى هاتفًا صغيرًا من محل في رمسيس، وحجز مقعدًا باسم «يوسف نعيم» بدلًا من اسمه الكامل. لم يخدع ذلك أحدًا محترفًا، لكنه جعله يشعر أنه يفعل شيئًا.</p>\n<p>قبل أن يصعد القطار اتصل بأمه من الرقم الجديد.</p>\n<p>- أنا مسافر الأقصر يومين.</p>\n<p>سكتت.</p>\n<p>- عرفت إنك هتروح.</p>\n<p>- منين؟</p>\n<p>- من ساعة ما شفت القطعة.</p>\n<p>- عايز أسألك عن بيت جدي.</p>\n<p>- البيت مقفول. المفتاح مع عمك عمران.</p>\n<p>- وهو يعرف عن القطعة؟</p>\n<p>- يعرف إنها كانت مع أبوه. ما يعرفش إنها رجعت.</p>\n<p>جاء صوت القطار في الخلفية.</p>\n<p>قالت أمه:</p>\n<p>- يوسف، لو عمران قال لك أبوك... أقصد جدك... كان حرامي، ما تزعلش منه. هو كان عنده تسع سنين لما أخدوه. الناس ساعات بتصدّق الكذبة اللي تريحها أكتر من الحقيقة اللي تخلّيها تستنى.</p>\n<p>- أنتِ لسه مستنية؟</p>\n<p>تأخرت في الرد.</p>\n<p>- لا. بس فيه فرق بين إني أصدق إنه مات، وإني أصدق إنه سابنا.</p>\n<p>صعد القطار. وجد مقعده بجوار نافذة متسخة. حين تحرك، رأى رجلًا في آخر العربة يفتح صحيفة ولا يقرأها.</p>\n<p>على ظاهر يده ضمادة بيضاء.</p>"}, {"id": "chapter-6", "order": 6, "title": "الفصل السادس: بقطر والكتاب ذو الجلد الأسود", "section": "القسم الأول: العينة", "firstLine": "أخميم، أواخر القرن الرابع للميلاد", "wordCount": 916, "minutes": 5, "era": "أواخر القرن الرابع", "theme": "coptic", "sound": "paper", "icon": "✥", "scene": "أخميم وصعيد مصر", "html": "<p>أخميم، أواخر القرن الرابع للميلاد</p>\n<p>كان بقطر يكره الكتب التي تصل إليه نظيفة.</p>\n<p>الكتاب النظيف لا حكاية له. أوراقه لم تُبلّلها رحلة، وجلده لم تمسه أصابع خائفة، وهوامشه لم تحمل سباب ناسخ ضاق بالعمل. أما الكتاب الذي وضعه الصبي فوق منضدته ذلك الصباح، فكان متشققًا عند الحواف، أسود الجلد، وله رائحة دخان وماء راكد. كتاب عاش أكثر مما ينبغي.</p>\n<p>قال الصبي:</p>\n<p>- أمي تقول إنك تصلحه ولا تفتحه.</p>\n<p>رفع بقطر حاجبًا.</p>\n<p>- وكيف أصلحه من غير أن أفتحه؟</p>\n<p>- قالت إنك ستقول ذلك.</p>\n<p>كان الصبي في الثانية عشرة تقريبًا، نحيلًا وعيناه حادتان. وضع إلى جوار الكتاب كيسًا صغيرًا من العملات، ثم هم بالخروج.</p>\n<p>أمسك بقطر بذراعه.</p>\n<p>- اسم أمك؟</p>\n<p>- مريم بنت حور.</p>\n<p>تجمدت أصابعه.</p>\n<p>اسم «حور» لم يكن نادرًا، لكنه في عائلته لم يكن اسمًا. كان تحذيرًا. جدته كانت تقول إن كل رجل يحمل هذا الاسم يموت قبل أن يشيب، ثم تبصق في النار حتى لا تسمعها الأرواح.</p>\n<p>ترك الصبي وفتح الكتاب.</p>\n<p>كان نصًا دينيًا قبطيًا منسوخًا فوق رقوق أقدم. الحروف واضحة، لكن التجليد غير متقن. حين رفع الغلاف الخلفي، وجد تحته شريطًا من الكتان التصق بالجلد. كتب عليه بحبر باهت رموز هيراطيقية لم يعد يقرأها إلا قلة من الكتبة.</p>\n<p>عرف أول علامة: كف بخمسة أصابع.</p>\n<p>أغلق الباب وأطفأ مصباح الدكان، رغم أن الشمس في الخارج.</p>\n<p>أمضى ساعات يفك الغلاف. بين طبقتين من الجلد وجد قرصًا نحاسيًا نصفه مفقود. رأس ابن آوى عليه مشقوق من المنتصف، وعلى حافته خمسة مواضع، أحدها محكوك حتى صار أملس.</p>\n<p>في المساء عادت أم الصبي.</p>\n<p>كانت امرأة في الأربعين، تغطي شعرها بقطعة كتان داكنة. لم تجلس.</p>\n<p>قالت:</p>\n<p>- قرأت ما بداخله؟</p>\n<p>- لم يكن ممكنًا إصلاحه من غير...</p>\n<p>- لا تكذب. أنت من بيت الناس الذين يحبون القراءة أكثر من الحياة.</p>\n<p>وضعت على الطاولة لفافة صغيرة. بداخلها أصبع بشرية جافة، يحيط بها خيط أحمر.</p>\n<p>تراجع بقطر.</p>\n<p>- ما هذا؟</p>\n<p>- ما بقي من أخي. وجده رجال الوالي حين كان يحفر عند الجبل. سألوا عن الكتاب. لم يعرفوا أنه أرسله إليك.</p>\n<p>- لماذا أرسلته لي؟</p>\n<p>- لأن جدتك كانت أخت أبي. ولأن الدور وصل إليك.</p>\n<p>ضحك بقطر، ضحكة قصيرة بلا فرح.</p>\n<p>- أي دور؟ أنا مجلد كتب. لا أحرس معابد، ولا أعرف أسرار الموتى.</p>\n<p>- لهذا نجونا. كل جيل يظن أنه آخر جيل، فيختار رجلًا لا يبدو مهمًا.</p>\n<p>أخرجت من ثوبها ورقة بردي صغيرة عليها رسم لخريطة. كان نهر النيل خطًا واحدًا، وإلى الغرب خمسة مربعات. تحتها كلمات قبطية:</p>\n<p><strong>البيت ليس حيث دفن الملك، بل حيث كُتبت أجور من دفنوه.</strong></p>\n<p>قال بقطر:</p>\n<p>- معابد الغرب تُغلق، والتماثيل تُهدم، والناس يتقاتلون على أسماء الآلهة. لماذا يهم أحدًا سجل أجور قديم؟</p>\n<p>- لأن السجل يقود إلى المخزن.</p>\n<p>- ذهب؟</p>\n<p>- خبز وفضة وأختام ورسائل. وربما ذهب. لا أعرف. الذين يطاردوننا لا يشرحون.</p>\n<p>سمعا ضجة في الشارع. أصوات رجال، ثم ارتطام خشب. اقتربت المرأة من الشق في الباب ونظرت.</p>\n<p>قالت:</p>\n<p>- وصلوا.</p>\n<p>- من؟</p>\n<p>- بيت ابن آوى.</p>\n<p>لم يكن بيتًا حقيقيًا. كان الاسم الذي أطلقته العائلة على رجال يظهرون كل عدة عقود بوجوه جديدة وعلامة واحدة. تجار، موظفون، جنود، أحيانًا رجال دين، لا يجمعهم نسب معروف. كانوا يبحثون عن القرص والخريطة، ويعرفون أكثر مما ينبغي عن أصحابها.</p>\n<p>دفع بقطر الكتاب والقرص في صندوق أدواته. فتح بابًا صغيرًا يؤدي إلى فناء خلفي.</p>\n<p>قال للمرأة:</p>\n<p>- أين الصبي؟</p>\n<p>- عند النهر.</p>\n<p>- اذهبي إليه.</p>\n<p>هزت رأسها.</p>\n<p>- سيعرفون أنك قريبنا إذا خرجت وحدك.</p>\n<p>قبل أن يرد، تحطم باب الدكان.</p>\n<p>دخل ثلاثة رجال. كان أولهم يرتدي ثوب كاتب حكومي، لا جندي. وجهه ممتلئ، ولحيته قصيرة مرتبة. على إصبعه خاتم يحمل رأس ابن آوى.</p>\n<p>قال باليونانية:</p>\n<p>- بقطر الناسخ؟</p>\n<p>رد بقطر باللغة نفسها:</p>\n<p>- المجلد. الناسخ أغلى.</p>\n<p>تفحص الرجل المكان، ثم نظر إلى المرأة.</p>\n<p>- مريم بنت حور. وفرتِ علينا وقتًا.</p>\n<p>أمسكت مريم سكينًا صغيرة من حزامها. ضحك الرجل.</p>\n<p>- لا نريد قتل أحد. نريد كتابًا لا يعني لكم شيئًا.</p>\n<p>قال بقطر:</p>\n<p>- الكتب التي لا تعني شيئًا لا يقتحم الرجال الدكاكين من أجلها.</p>\n<p>تقدم أحد الحراس. رمى بقطر مصباح الزيت على الأرض. اشتعلت النار في حصيرة القصب، وامتلأ الدكان بالدخان. أمسك مريم من يدها ودفعها إلى الفناء. ركضا فوق سطح منخفض، ثم قفزا إلى زقاق ضيق خلف المخبز.</p>\n<p>سمع الرجل يصيح من الداخل:</p>\n<p>- لا تتركوه يصل إلى الجبل!</p>\n<p>وهنا فهم بقطر أن الخريطة التي أعطته إياها مريم ليست سرًا كاملًا. كانوا يعرفون مكان الجبل. ما ينقصهم هو الباب.</p>\n<p>ركضا حتى النهر. كان الصبي ينتظر في قارب صغير مربوط إلى وتد.</p>\n<p>قالت مريم وهي تلهث:</p>\n<p>- خذ الكتاب واعبر إلى الغرب. هناك دير مهجور قرب الطريق القديم. تحت أرض مخزنه حجر عليه خمس فتحات.</p>\n<p>- وأنت؟</p>\n<p>نظرت خلفها. ظهر الرجال عند أول الزقاق.</p>\n<p>- سأجعلهم يظنون أن القرص معي.</p>\n<p>- سيقتلونك.</p>\n<p>- قتلوا أخي لأنني تأخرت. لن أتأخر مرة ثانية.</p>\n<p>دفعت ابنها إلى القارب. أمسكها الصبي وهو يبكي بصمت.</p>\n<p>وضعت يدها على وجهه.</p>\n<p>- اسمه الجديد حوري، قالت لبقطر. لا تستخدم اسمه القديم بعد اليوم.</p>\n<p>ثم نزعت عقدًا من رقبتها، كان معلقًا به نصف قرص نحاسي مزيف، وركضت في الاتجاه الآخر.</p>\n<p>تبعها الرجال.</p>\n<p>ظل الصبي ينظر حتى ابتلعها الغبار.</p>\n<p>عبر بقطر النهر قبل الغروب. لم يكن يعرف أن مريم ستعيش ساعة واحدة فقط، ولا أن ابنها سيحمل اسم حوري إلى جيل آخر، ولا أن الكتاب الأسود الذي وضعه في حجر الدير سيبقى هناك سبعمئة عام.</p>\n<p>كان يعرف شيئًا واحدًا: أن دوره الذي سخر منه صار أثقل من أن يتركه.</p>\n<p>في مخزن الدير وجد الحجر ذا الفتحات الخمس. وضع القرص في الأولى، ثم الثانية. لم يحدث شيء. في الثالثة سمع طقة خفيفة.</p>\n<p>قال الصبي:</p>\n<p>- أمي قالت إن الباب لا يفتح إلا خمس مرات.</p>\n<p>نظر بقطر إلى القرص. كان أحد الشقوق محكوكًا، كأن يدًا قد أدخلته مرارًا في موضع واحد.</p>\n<p>فتح الكتاب الأسود، وقرأ الشريط الهيراطيقي مرة أخرى. تحت الكف كانت هناك جملة لم يفهمها في الدكان. الآن، عند ضوء الغروب، ظهرت الحروف:</p>\n<p><strong>لا تعدّ الأصابع. عدّ الذين فقدوها.</strong></p>\n<p>نظر إلى الأصبع الجافة التي تركتها مريم فوق طاولته، والتي أخذها دون أن يشعر داخل كيس العملات.</p>\n<p>وفهم أن الباب صُمم لمن يعرف ثمن الوصول إليه.</p>"}, {"id": "chapter-7", "order": 7, "title": "الفصل السابع: بيت نعيم", "section": "القسم الأول: العينة", "firstLine": "لم ينم يوسف في القطار.", "wordCount": 753, "minutes": 4, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>لم ينم يوسف في القطار.</p>\n<p>الرجل صاحب الضمادة لم يتحرك من مقعده إلا مرة واحدة، عند محطة المنيا. حين قام، رأى يوسف مسدسًا صغيرًا تحت سترته. لم ينتظر ليتأكد. حمل حقيبته، مر بين العربات، ونزل في أسيوط قبل أن يغلق الباب بثوانٍ.</p>\n<p>استقل ميكروباصًا إلى سوهاج، ثم آخر إلى قنا، ثم سيارة أجرة قديمة إلى الأقصر. وصل في الظهر وعيناه تحرقان من التعب. طوال الطريق كان يتوقع أن يرى الرجل في كل مرآة.</p>\n<p>بيت عمه عمران يقع في شارع جانبي ضيق، بعيدًا عن الفنادق والمراكب. باب خشبي أخضر، فوقه شرفة من طوب مكشوف وحبال غسيل. فتح عمران قبل أن يطرق يوسف للمرة الثانية.</p>\n<p>كان رجلًا في أواخر الخمسينات، عريض الكتفين رغم بطنه، شعره أبيض عند الصدغين. عانق ابن أخته بقوة ثم أبعده ليراه.</p>\n<p>- إيه اللي جابك من غير ما تقول؟ أمك كويسة؟</p>\n<p>- كويسة. محتاج مفتاح بيت جدي.</p>\n<p>اختفت الفرحة من وجهه.</p>\n<p>- جاي على طول كده؟ لا شاي ولا سلام؟</p>\n<p>- نشرب هناك.</p>\n<p>جلس عمران في الصالة، وصب لنفسه ماءً من القُلّة. على الحائط صورة نعيم ذاتها التي ظهرت في تقرير البعثة؛ رجل نحيل بشارب كثيف، يقف أمام الجبل ويحدق في المصور كأنه لم يقتنع بفكرة الصورة.</p>\n<p>قال عمران:</p>\n<p>- مين كلمك؟</p>\n<p>- محدش.</p>\n<p>- أمك عمرها ما كانت هتخليك تفتح البيت.</p>\n<p>أخرج يوسف الملف القديم ووضعه أمامه. قرأ عمران الصفحة الأولى، ثم أغلقه.</p>\n<p>- الورق ده أعرفه.</p>\n<p>- وتعرف إنهم لفّقوا له السرقة؟</p>\n<p>- أعرف إن أبويا اختفى وساب أمي تشحت عشان تأكلنا. الورق ما يغيرش ده.</p>\n<p>- يمكن ما سابكمش بإيده.</p>\n<p>ضحك عمران بمرارة.</p>\n<p>- كل عيلة عندها ميت بتحب تعمله بطل. إحنا عملنا الغايب بريء. أريح.</p>\n<p>أراه يوسف القطعة النحاسية.</p>\n<p>تغير لون وجهه.</p>\n<p>مد يده إليها، ثم توقف قبل أن يلمسها.</p>\n<p>- جبتها منين؟</p>\n<p>- كانت عند واحدة في الشركة اللي عملت التحليل. ماتت.</p>\n<p>نهض عمران وأغلق النافذة.</p>\n<p>- امشِ من البلد.</p>\n<p>- عايز المفتاح.</p>\n<p>- البيت مفيهوش حاجة.</p>\n<p>- يبقى مش هخسر.</p>\n<p>ظل عمه ينظر إليه. ثم دخل غرفة النوم وعاد بمفتاح طويل مربوط بخيط أزرق.</p>\n<p>- أنا جاي معاك.</p>\n<p>كان بيت نعيم عند طرف القرية القديمة، نصفه غارق في التراب بعد ارتفاع الطريق عبر السنين. الباب أقصر من يوسف، واضطر إلى الانحناء. في الداخل رائحة قش وفئران وخشب قديم. الضوء يدخل من ثقوب السقف في أعمدة رفيعة.</p>\n<p>قال عمران:</p>\n<p>- أمي قفلته بعد ما ماتت. كانت تدخل تنضف مرة في السنة لحد ما رجليها بطلت تشيلها.</p>\n<p>الغرفة الأمامية فارغة إلا من سرير حديدي وصندوق ملابس. رفع يوسف المرتبة. لا شيء. تفحص الجدران، أرضية الطين، فتحات النوافذ. كان يعمل في تصوير المباني القديمة ويعرف أن البيوت تخفي تعديلات أصحابها: خط جص مختلف، طوبة أفتح، خشب لا يطابق بقية السقف.</p>\n<p>وجد لوحًا أسفل السرير أضيق من الألواح الأخرى.</p>\n<p>قال عمران بسرعة:</p>\n<p>- الأرض وقعت من زمان.</p>\n<p>نظر يوسف إليه.</p>\n<p>- ما قلتش إنها وقعت.</p>\n<p>جثا ورفع اللوح بمفك. تحته تراب مضغوط. حفر بأصابعه، ثم شعر بقماش زيتي. أخرجه.</p>\n<p>كاميرا روسية قديمة.</p>\n<p>جلس عمران على حافة السرير.</p>\n<p>- أمي دورت في البيت كله.</p>\n<p>- واضح إنها ما دورتش تحت سريرك.</p>\n<p>مسح يوسف الغبار عن العدسة. فتح الغطاء الخلفي فوجد علبة فيلم فارغة. للحظة شعر بخيبة سخيفة؛ كان يتوقع أن يجد الماضي محفوظًا كما تركه صاحبه.</p>\n<p>ثم لاحظ أن مقبض الكاميرا أثقل من المعتاد.</p>\n<p>لفه فانفصل طرفه. في داخله أسطوانة معدنية صغيرة، مغلقة بالشمع.</p>\n<p>قال عمران:</p>\n<p>- سيبها.</p>\n<p>- ليه؟</p>\n<p>- عشان من ساعة ما وريّتني القطعة وأنا فاكر حاجة كنت أتمنى تفضل مدفونة.</p>\n<p>جلس يوسف أمامه.</p>\n<p>حك عمران كفيه، ثم قال:</p>\n<p>- ليلة ما أبويا رجع آخر مرة، صحيت عليه وهو بيرفع لوح الأرض. عملت نفسي نايم. كان هدومه مقطعة وفي دم على رقبته. كتب ورقة وحطها في الكاميرا. الصبح خرج، وبعدها الناس قالت سرق وهرب. بعد أسبوع جه راجل لأمي، قال لها لو عايزة جوزها يرجع تسلمه اللي خباه.</p>\n<p>- عملت إيه؟</p>\n<p>- قالت ما تعرفش. ضربوها قدامي.</p>\n<p>كان صوته ثابتًا، وهذا جعله أشد قسوة.</p>\n<p>- أنا كنت عارف مكان الكاميرا، كمل عمران. شفت كل حاجة. بس ما قلتش. فضلت ساكت وأنا سامعها تصرخ. تسع سنين، يا يوسف. عارف يعني إيه طفل يقرر إن أمه بتضرب عشان هو خايف يتكلم؟</p>\n<p>لم يجد يوسف جوابًا.</p>\n<p>- بعد ما مشيوا، فتحت الأرض وخدت الورقة. قريتها. خمس كلمات بس. خفت منها أكتر من الضرب. حرقتها في فرن العيش.</p>\n<p>- فاكرها؟</p>\n<p>نظر عمران إلى القطعة النحاسية في يد يوسف.</p>\n<p>- «لا تصدقوا الرجل الذي يعيد لكم أسماءكم».</p>\n<p>شعر يوسف بقشعريرة.</p>\n<p>فتح الأسطوانة. بداخلها فيلم ملتف بعناية، وورقة أخرى أصغر لم تُحرق. الورقة سوداء من الرطوبة، لكن بعض الكلمات ظاهرة:</p>\n<p><strong>ليلى تعرف الحجرة. فؤاد يعرف الخائن. الصورة الخامسة ليست في الفيلم.</strong></p>\n<p>في الخارج، توقفت سيارة.</p>\n<p>انطفأ وجه عمران.</p>\n<p>- هما وصلوا.</p>\n<p>دخل رجلان من الباب الأمامي قبل أن يخرجا من الغرفة. لم يكن بينهما حازم. أحدهما شاب في قميص أبيض، والآخر يرتدي جلبابًا رماديًا ويضع يده داخل جيبه.</p>\n<p>قال الشاب لعمران:</p>\n<p>- الأستاذ رائف زعلان إنك ما بلغتوش إن ابن أختك جه.</p>\n<p>نظر يوسف إلى عمه.</p>\n<p>لم ينكر عمران.</p>"}, {"id": "chapter-8", "order": 8, "title": "الفصل الثامن: ثمن السكوت", "section": "القسم الأول: العينة", "firstLine": "لم يتحرك أحد لثوانٍ.", "wordCount": 918, "minutes": 5, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>لم يتحرك أحد لثوانٍ.</p>\n<p>كان الرجل ذو الجلباب يقف في المدخل بحيث يحجب الخروج. الشاب في القميص الأبيض دخل الغرفة ومد يده.</p>\n<p>- الفيلم والقطعة، يا أستاذ يوسف. ونخلّص الموضوع من غير وجع دماغ.</p>\n<p>نظر يوسف إلى عمران.</p>\n<p>- أنت اللي قلت لهم؟</p>\n<p>قال عمه:</p>\n<p>- اسمعني الأول.</p>\n<p>- جاوب.</p>\n<p>- أيوه.</p>\n<p>لم تكن الصدمة في الإجابة، بل في سهولتها. كأن عمران تعب من حملها.</p>\n<p>قال الشاب:</p>\n<p>- العتاب العائلي بعدين.</p>\n<p>أخرج الرجل الآخر مسدسًا من جيبه. لم يرفعه، فقط أظهره.</p>\n<p>وضع يوسف الفيلم في جيب قميصه ببطء. كانت نافذة الغرفة خلفه ضيقة، قضبانها صدئة. فوق السرير مصباح كيروسين قديم، فارغ غالبًا. إلى يساره صندوق الملابس.</p>\n<p>قال عمران:</p>\n<p>- هما مش عايزين يقتلوك. ادّيهم الحاجة.</p>\n<p>- زي ما ما كانوش عايزين يقتلوا مريم؟</p>\n<p>نظر الشاب إلى صاحبه، ثم قال:</p>\n<p>- مريم اختارت نهاية سيئة. ما تكررهاش.</p>\n<p>وفي اللحظة نفسها ضرب عمران الشاب بظهر القُلّة التي كان يحملها. تحطمت على رأسه، وانفجر الماء والطين. رفع الرجل المسدس، لكن يوسف دفع الصندوق الخشبي بقدمه. اصطدم الصندوق بركبتيه، فانطلقت الرصاصة إلى السقف.</p>\n<p>صرخ عمران:</p>\n<p>- الشباك!</p>\n<p>أمسك يوسف المصباح وضرب به القضيب الأوسط. لم يتحرك. ضرب مرة ثانية، انكسر الزجاج وبقي الحديد. جاء الرجل من خلفه، فأمسك يوسف بالقضيب بكلتا يديه وشده. الصدأ ساعده؛ خرج طرفه من الجدار.</p>\n<p>دفع عمران ابن أخته نحو الفتحة.</p>\n<p>- اطلع!</p>\n<p>- وأنت؟</p>\n<p>- أنا اللي دخلتهم، وأنا اللي هطلعك.</p>\n<p>زحف يوسف من النافذة وسقط في فناء خلفي مليء بجريد النخل. سمع ضربة من الداخل، ثم تأوه عمه. عاد نحو النافذة، لكن عمران صاح:</p>\n<p>- اجري يا حيوان!</p>\n<p>ركض.</p>\n<p>خرج إلى زقاق ضيق، قفز فوق قناة ري جافة، ودخل بين بيوت متلاصقة. لم يعرف إلى أين يتجه. اتصل بالرقم الذي أرسل صورة ليلى؛ مغلق. اتصل بعمر؛ لم يرد.</p>\n<p>عند أول شارع واسع، توقفت أمامه دراجة نارية صغيرة تقودها امرأة ترتدي خوذة سوداء.</p>\n<p>رفعت زجاج الخوذة.</p>\n<p>- اركب لو مش عايز تموت واقف.</p>\n<p>عرف سلمى عدلي رغم أنه لم يرها منذ ثلاث سنوات.</p>\n<p>كانت زميلته في كلية الآثار قبل أن يترك الدراسة ويتجه إلى التصوير، بينما أكملت هي في ترميم المخطوطات. آخر مرة التقيا فيها تشاجرا لأن يوسف صوّر نقشًا هشًا بإضاءة قوية من دون إذنها، فقالت له إنه يتعامل مع الماضي كخلفية إعلان، وقال لها إنها تتعامل معه كجثة يجب ألا يلمسها أحد.</p>\n<p>لم يكن هذا وقت استعادة الخلاف.</p>\n<p>ركب خلفها. انطلقت بين الشوارع، ثم عبرت طريقًا ترابيًا نحو مزارع القصب. بعد عشر دقائق توقفت خلف مخزن مهجور.</p>\n<p>خلعت الخوذة.</p>\n<p>- الفيلم معاك؟</p>\n<p>- إنتِ عرفتي منين؟</p>\n<p>- الدكتورة ليلى بعتتني.</p>\n<p>- والرسالة كانت منها؟</p>\n<p>- أيوه.</p>\n<p>- مريم كانت ميتة وقتها.</p>\n<p>- مين قال لك إن الرسالة من مريم؟</p>\n<p>أدرك أنه افترض ذلك لأن الرقم مجهول والصورة تخص ليلى.</p>\n<p>قال:</p>\n<p>- فين ليلى؟</p>\n<p>- مكان آمن، مؤقتًا. الأول لازم نعرف إن الفيلم صالح.</p>\n<p>فتحت باب المخزن. في الداخل معمل تصوير بدائي: أحواض تحميض، مصباح أحمر، حبال عليها صور لمقابر ونقوش. قال يوسف:</p>\n<p>- ده بتاع مين؟</p>\n<p>- أبويا كان مصور بعثات. قفلناه بعد موته، وأنا رجعت جهزته الصبح.</p>\n<p>- عرفتي إني جاي الصبح؟</p>\n<p>- عرفنا إن رائف دعاك من قبل ما تدخل مكتبه.</p>\n<p>- أنتم مين؟</p>\n<p>تجاهلت السؤال. أخذت أسطوانة الفيلم بقفازين، وفحصت حافتها.</p>\n<p>- فيلم سوفيتي، سبعة وثلاثين مليمتر. التخزين وحش، بس الشمع حماه نسبيًا. محتاج ساعات.</p>\n<p>طرق يوسف على الطاولة.</p>\n<p>- مش هسيب الحاجة وأمشي. عمي جوه البيت مع رجالة مسلحة.</p>\n<p>- عمران شغال مع رائف بقاله ست سنين.</p>\n<p>- عارف.</p>\n<p>- مش عارف ليه.</p>\n<p>أخرجت سلمى ملفًا صغيرًا. فيه صورة شاب في الثلاثينات، يشبه عمران حول العينين.</p>\n<p>- ده أيمن، ابن عمك. اتقبض عليه من سبع سنين في قضية تنقيب غير مشروع. الحكم كان خمس سنين، لكنه ما خرجش. رسميًا اتنقل مستشفى سجن، وبعدها اختفى من السجلات. رائف وعد عمران يرجعه مقابل إنه يراقب البيت والعيلة.</p>\n<p>- وهو صدقه؟</p>\n<p>- الناس بتصدق الكذبة اللي تديها شغل تعمله.</p>\n<p>كررت تقريبًا جملة أمه. ضايقه ذلك.</p>\n<p>- عمي ضرب واحد منهم وطلعني.</p>\n<p>- يمكن اختار متأخر، بس اختار.</p>\n<p>وضعت الفيلم في خزان التحميض. جلس يوسف على كرسي خشبي، وبدأ التعب يثقل رأسه. كانت سلمى تعمل بصمت، لا تتحرك حركة زائدة. قصت طرف الفيلم، اختبرت جزءًا صغيرًا، عدلت المحلول.</p>\n<p>قال:</p>\n<p>- ليه ليلى ما تظهرش؟</p>\n<p>- لأنها ظهرت مرة سنة 1978، ودفعت الثمن. اتمنعت من العمل عشرين سنة، واتهموها بتزوير سجلات، وجوزها مات في حادث عربية بعد ما حاول يفتح الملف.</p>\n<p>- والضابط فؤاد؟</p>\n<p>- اختفى. ابنه بقى ضابط، على فكرة.</p>\n<p>- أعرف.</p>\n<p>رفعت سلمى رأسها.</p>\n<p>- عمر وصلك؟</p>\n<p>- قال إنه هييجي قبلي.</p>\n<p>- ما جاش.</p>\n<p>شعر يوسف بانقباض.</p>\n<p>بعد ساعتين بدأت الصور تظهر على الورق الأبيض داخل الحوض. الأولى مهزوزة: مدخل صخري ورجلان يحملان مصابيح. الثانية لجدار مغطى بأسماء. الثالثة لقطة قريبة لكف سوداء ورأس ابن آوى مشقوق.</p>\n<p>أما الرابعة، فتوقفت سلمى عندها طويلًا.</p>\n<p>ظهر نعيم في طرف الصورة، منعكسًا في قطعة معدن لامعة. لم يكن يصور الجدار، بل شخصًا يقف أمامه.</p>\n<p>كبرت سلمى الصورة تحت عدسة.</p>\n<p>كان الشخص الدكتور نادر السيوفي. في يده مسدس، وعند قدميه رجل يرتدي زي الشرطة.</p>\n<p>قال يوسف:</p>\n<p>- فؤاد خطاب.</p>\n<p>في الصورة الخامسة ظهر فؤاد حيًا، مربوط اليدين، وإلى جواره صندوق خشبي مفتوح. داخل الصندوق كتاب أسود الجلد وقطعة قماش مطرزة بخمس نخلات.</p>\n<p>الصورة السادسة أظهرت هيكلًا عظميًا قديمًا في ركن الحجرة، والخاتم النحاسي بجواره.</p>\n<p>ثم انتهى الفيلم.</p>\n<p>قالت سلمى:</p>\n<p>- ست صور بس.</p>\n<p>- جدي كتب إن الصورة الخامسة مش في الفيلم.</p>\n<p>- يمكن يقصد خامس دليل، مش ترتيب اللقطات.</p>\n<p>قلب يوسف الصور. على ظهر آخر صورة، لم يظهر شيء أول الأمر. قربتها سلمى من المصباح الأحمر، فبرزت خدوش دقيقة صنعها رأس دبوس:</p>\n<p><strong>سالم باع الباب، وبقطر أخفى المفتاح، وحوري كتب الأسماء. الخامس لا يرث السر؛ الخامس يُختبر.</strong></p>\n<p>تحتها رسم لطريق ينتهي عند علامة تشبه بئرًا.</p>\n<p>قالت سلمى:</p>\n<p>- الأسماء دي ظهرت في مخطوط عند ليلى. كانت فاكرة إنها أسماء ناس منفصلين.</p>\n<p>- هما من عيلتي؟</p>\n<p>- غالبًا. بس فيه مشكلة.</p>\n<p>- إيه؟</p>\n<p>أشارت إلى كلمة «باع».</p>\n<p>- واحد منهم خان الباقيين.</p>\n<p>انطفأ المصباح الأحمر.</p>\n<p>جاء صوت رجل من الظلام:</p>\n<p>- والناس دائمًا تفترض أن الخائن هو الشخص الذي باع.</p>\n<p>أضاءت سلمى مصباح هاتفها.</p>\n<p>كان عمر خطاب واقفًا عند الباب، ودم يسيل من كتفه.</p>"}, {"id": "chapter-9", "order": 9, "title": "الفصل التاسع: ليلى منصور لا تستقبل الضيوف", "section": "القسم الأول: العينة", "firstLine": "أغلق يوسف الباب خلف عمر، بينما أخرجت سلمى حقيبة إسعافات من خزانة معدنية. الرصاصة خدشت أعلى كتفه ولم تستقر، لكن الدم غمر قميصه.", "wordCount": 881, "minutes": 5, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>أغلق يوسف الباب خلف عمر، بينما أخرجت سلمى حقيبة إسعافات من خزانة معدنية. الرصاصة خدشت أعلى كتفه ولم تستقر، لكن الدم غمر قميصه.</p>\n<p>قالت وهي تقص القماش:</p>\n<p>- مين ضربك؟</p>\n<p>- راجل كان مستنيني عند أرمنت. عرفت بعدين إن العنوان اللي في الصورة مش بيت ليلى، بيت واحدة ماتت من سنتين.</p>\n<p>نظر إلى يوسف.</p>\n<p>- الفخ كان ليا، مش ليك. بعتوا لك الرسالة عارفين إنك هتكلمني.</p>\n<p>- إنت قلت إنهم بيراقبوا المحاضر.</p>\n<p>- وطلعوا بيراقبوا تليفوني كمان.</p>\n<p>ضغطت سلمى شاشًا على الجرح. لم يتأوه.</p>\n<p>قال يوسف:</p>\n<p>- عمي عندهم.</p>\n<p>- لو كان حيًا، هيستخدموه عشان ترجع. لو مات، هيستخدموا موته لنفس السبب.</p>\n<p>- دي طريقة مواساة عند الشرطة؟</p>\n<p>- دي طريقة تقليل مفاجآت.</p>\n<p>وضع يوسف الصور أمامه. توقف عمر عند صورة أبيه. مد إصبعًا نحو الوجه من غير أن يلمسه.</p>\n<p>كان فؤاد خطاب في الخامسة والثلاثين وقتها، أصغر من ابنه الآن. في الصورة نظر إلى الكاميرا مباشرة، لا إلى المسدس. بدا كأنه يعرف أن شخصًا في مستقبل بعيد سيراه.</p>\n<p>قال عمر:</p>\n<p>- أمي قالت إن آخر مرة رجع فيها البيت كان ريحته تراب وزيت كاميرات. سألته فين، قال لها: «كنت بدور على ناس ماتت ومحدش بلغ عنهم.»</p>\n<p>قلب الصورة. لم يجد كتابة.</p>\n<p>قالت سلمى:</p>\n<p>- لازم نروح ليلى قبل الفجر. المكان الحقيقي بعيد عن الطريق.</p>\n<p>- وهي تثق فيك؟ سأل يوسف.</p>\n<p>- لا. عشان كده لسه عايشة.</p>\n<p>خرجوا في سيارة عمر بعد أن لف كتفه. قادت سلمى، وجلس يوسف في الخلف يراقب الطريق. تجاوزوا أرمنت، ثم تركوا الأسفلت إلى مسار تحيط به مزارع موز وقصب. بعد قرابة ساعة وصلوا إلى بيت طيني منخفض لا ضوء فيه.</p>\n<p>طرقت سلمى سبع طرقات بنظام غريب: اثنتان، ثم واحدة، ثم أربع.</p>\n<p>فتح الباب شاب يحمل بندقية صيد. لم يتجاوز العشرين.</p>\n<p>- اتأخرتوا.</p>\n<p>قالت سلمى:</p>\n<p>- والست ليلى؟</p>\n<p>- قالت لو معاكم حد من الشرطة ما تدخلهمش.</p>\n<p>رفع عمر بطاقته ثم وضعها في جيبه.</p>\n<p>- اعتبرني مصاب تايه.</p>\n<p>جاء صوت امرأة من الداخل:</p>\n<p>- دخّلهم يا محمود. لو كانوا جايين يقتلوني، البندقية دي آخر حاجة هتمنعهم.</p>\n<p>كانت ليلى منصور تجلس على كرسي خشبي أمام منضدة مغطاة بأوراق. تجاوزت السبعين، شعرها أبيض قصير، وعيناها خلف نظارة سميكة شديدتا الحضور. الحائط خلفها لم يحمل كفًا سوداء كما في الصورة؛ كانت الكف مرسومة على قطعة قماش معلقة، ويمكن نقلها لأي مكان.</p>\n<p>قالت ليوسف قبل السلام:</p>\n<p>- أنت تشبه جدتك أكثر من نعيم. ده حسن حظ.</p>\n<p>ثم نظرت إلى عمر.</p>\n<p>- وأنت نسخة سيئة من فؤاد. هو كان يدخل البيوت ويسلّم الأول.</p>\n<p>جلسوا. لم تقدم شايًا، ولم تسأل عن الطريق. طلبت الفيلم والصور، وفحصتها واحدة واحدة.</p>\n<p>عند صورة نادر وفؤاد قالت:</p>\n<p>- كنت أعرف أن نعيم صوّرها. لم أكن أعرف أنه أنقذ الفيلم.</p>\n<p>قال عمر:</p>\n<p>- أبويا مات هناك؟</p>\n<p>خلعت نظارتها ونظفتها ببطء.</p>\n<p>- لا أعرف. رأيته آخر مرة حيًا. نادر أمر حازم الكبير - أبو حازم اللي عند رائف - ياخده خارج الحجرة. سمعت طلقة بعد ربع ساعة، لكن الجبل يكرر الأصوات. أحيانًا الطلقة الواحدة تعيش أكثر من الرجل.</p>\n<p>- ليه ما بلغتيش؟</p>\n<p>- بلغت. واتهموني أنا ونعيم بسرقة البعثة. أبوك كان الضابط الوحيد الذي كتب تقريرًا مخالفًا، فاختفى تقريره معه.</p>\n<p>أشارت إلى الكتاب الأسود في الصورة.</p>\n<p>- ده اللي بدأ كل شيء. وجدناه داخل صندوق مملوكي في الحجرة. نص قبطي مجلد فوق شرائط أقدم. فيه أربع طبقات كتابة: هيراطيقي، قبطي، عربي، ثم ملاحظات نعيم بالقلم الرصاص. كل طبقة تركها واحد من العائلة نفسها.</p>\n<p>قال يوسف:</p>\n<p>- حوري، بقطر، سالم، نعيم.</p>\n<p>- وأنت الخامس.</p>\n<p>- الخامس يعمل إيه؟</p>\n<p>- هذا هو السؤال الذي قتل مريم.</p>\n<p>فتحت درجًا وأخرجت ظرفًا. فيه نسخة لصفحة من الكتاب الأسود. كانت الكلمات العربية مكتوبة بخط مملوكي متشابك، وبين السطور حروف قبطية ورسوم صغيرة.</p>\n<p>- نادر أخذ الكتاب، قالت ليلى. قبل موته نقل مقتنياته إلى مؤسسة ابنه. رائف يملك أربع طبقات من الدليل، لكنه لا يملك الشيء الذي وضعه نعيم خارج الكتاب.</p>\n<p>- الفيلم؟</p>\n<p>- الفيلم يثبت الجريمة، لكنه لا يفتح الباب.</p>\n<p>وضعت القطعة النحاسية في منتصف الطاولة. كان يوسف قد استعادها بعد الهروب؛ لم يتذكر حتى كيف بقيت في جيبه.</p>\n<p>- القرص ليس مفتاحًا، قالت. هو أداة قياس. الشقوق الخمسة تمثل زوايا ضوء في أوقات مختلفة. الحجرة الأصلية لها خمسة مداخل كاذبة وباب واحد لا يظهر إلا عندما يمر الضوء من بئر علوية. كل جيل سجّل زاوية عصره بطريقته.</p>\n<p>قالت سلمى:</p>\n<p>- لكن موقع الحجرة معروف من تقرير 1978.</p>\n<p>- الموقع انهار بعد البعثة. أو فُجّر. المدخل الذي استخدموه اختفى. بقي مدخل أقدم من جهة وادٍ جانبي، لا يظهر على الخرائط الحديثة.</p>\n<p>أخرجت ليلى خريطة يدوية. فيها خمس علامات: معبد قديم، دير مهجور، خان قوافل، بيت نعيم، وبئر.</p>\n<p>- كل علامة تخص زمنًا. لو وصلوا إلى الخامسة سيعرفون المدخل.</p>\n<p>قال يوسف:</p>\n<p>- ومريم عرفت إيه؟</p>\n<p>ترددت ليلى، ثم دفعت إليه ورقة مطبوعة من معمل جيني مستقل.</p>\n<p>- أرسلت لي قبل موتها جزءًا من نتائج A-17. العظمة ليست من صاحب المقبرة، ولا من ملك. هي لرجل مات داخل الحجرة، عمره نحو ثلاثين عامًا، وعنده كسر قديم في عظمة اليد اليمنى وفقد إصبعًا.</p>\n<p>تذكر يوسف جملة بقطر التي لم يكن يعرفها بعد، لكنها كانت مكتوبة في الصفحة القبطية: لا تعد الأصابع. عد الذين فقدوها.</p>\n<p>قالت ليلى:</p>\n<p>- مريم قارنت الإصابات بوصف موجود في النص الهيراطيقي. العظمة لحوري، الكاتب الأول.</p>\n<p>- يعني فعلًا من عيلتي؟</p>\n<p>- ربما. لكن رائف لا يهتم بإثبات أنك حفيده. هو استخدم الـDNA كمنخل. كان يبحث عن عائلة حافظت على خط أبوي ومكان جغرافي محدد، لأن حامل السر يُختار من الأبناء عبر الأجيال.</p>\n<p>قال عمر:</p>\n<p>- وأربع حالات CLOSED؟</p>\n<p>- رجال من فروع بعيدة. وصلوا إليهم قبل يوسف. لم يكن معهم شيء، أو لم يفهموا ما معهم. اثنان ماتا، واحد اختفى، والرابع...</p>\n<p>نظرت ليلى إلى الباب.</p>\n<p>دخل محمود، الشاب ذو البندقية، وهو يسند رجلًا مصابًا.</p>\n<p>كان عمران.</p>\n<p>وجهه متورم، ويده اليسرى معلقة بزاوية غير طبيعية. رفع عينيه إلى يوسف وقال:</p>\n<p>- أيمن كان الحالة الرابعة.</p>\n<p>ثم سقط على ركبتيه.</p>"}, {"id": "chapter-10", "order": 10, "title": "الفصل العاشر: الحالة الرابعة", "section": "القسم الثاني: العلامات الخمس", "firstLine": "أفاق عمران على فراش في الغرفة المجاورة، بعد أن ثبتت سلمى ذراعه بلوحين خشبيين ورباط قماش. لم يكن كسرًا بسيطًا، لكنها قالت إن المستشفى يعني بلاغًا، والبلاغ يعني رجال رائف قبل الطبيب.", "wordCount": 752, "minutes": 4, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>أفاق عمران على فراش في الغرفة المجاورة، بعد أن ثبتت سلمى ذراعه بلوحين خشبيين ورباط قماش. لم يكن كسرًا بسيطًا، لكنها قالت إن المستشفى يعني بلاغًا، والبلاغ يعني رجال رائف قبل الطبيب.</p>\n<p>جلس يوسف قرب الباب. لم يساعد عمه حين طلب الماء؛ ناوله الكوب من بعيد.</p>\n<p>قال عمران بعد أن شرب:</p>\n<p>- معاك حق تزعل.</p>\n<p>- أنا مش زعلان. أنا مش فاهم بس إزاي بعتني لناس قتلوا بنت.</p>\n<p>- ما كنتش أعرف بمريم.</p>\n<p>- كنت تعرف بابن عمك؟</p>\n<p>أغمض عمران عينيه.</p>\n<p>- أيمن دخل مع ناس يحفروا في أرض صحراوية. قالوا له يومين شغل ويطلع بفلوس يتجوز. اتقبض عليهم. في السجن جه له واحد من مؤسسة السيوفي، قال له القضية تتقفل لو عمل تحليل دم وأجاب على شوية أسئلة عن العيلة. أيمن وافق. بعدها بشهور قالوا لي اتنقل مستشفى. رحت، قالوا مفيش حد بالاسم ده.</p>\n<p>- ورائف كلمك؟</p>\n<p>- بعد سنة. وراني فيديو لأيمن قاعد في أوضة، تعبان بس حي. قال إن ابني عنده مشكلة في أوراق القضية، وإنه يقدر يطلعه. طلب مني أراقب البيت، وأسألكم لو ظهر مفتاح أو فيلم أو كلام من أبويا.</p>\n<p>- ست سنين وما رجعش ابنك، ولسه بتصدقه؟</p>\n<p>فتح عمران عينيه. فيهما غضب لا يعرف أين يذهب.</p>\n<p>- كل ست شهور كان يبعت فيديو جديد.</p>\n<p>قالت ليلى من عند المنضدة:</p>\n<p>- هل رأيت تاريخًا داخل الفيديو؟ جريدة؟ مباراة؟ خبرًا؟</p>\n<p>سكت عمران.</p>\n<p>- مرة كان لابس قميص أنا جايبه له، قال.</p>\n<p>- القميص لا يثبت الزمن.</p>\n<p>أخرجت حاسوبًا قديمًا وشغلت ملفًا أعطاها إياه عمران. ظهر أيمن على كرسي، خلفه حائط أبيض، يقول: «أنا كويس يا حاج، اسمع كلام الأستاذ رائف، وأنا راجع قريب.»</p>\n<p>أعادت ليلى المقطع ببطء. في الزاوية ظل شجرة يتحرك على الحائط. أوقفته عند لحظة.</p>\n<p>قالت سلمى:</p>\n<p>- الفيديو متكرر.</p>\n<p>- إيه؟</p>\n<p>- حركة الظل ترجع نفسها كل أربع ثوانٍ. الخلفية مركبة.</p>\n<p>اقترب يوسف من الشاشة. وجه أيمن كان أنحف من الصور، وعيناه تهربان إلى يسار الكاميرا. على رقبته بقعة داكنة.</p>\n<p>قال عمر:</p>\n<p>- آخر فيديو وصلك إمتى؟</p>\n<p>- من شهرين.</p>\n<p>- ملفه الأصلي؟</p>\n<p>أعطاه عمران الهاتف. نقل عمر الفيديو إلى الحاسوب وفحص بياناته.</p>\n<p>- الملف اتعمل من نسخة واحدة قديمة، وتغير صوته وصورته كل مرة. برنامج توليد وجه وصوت. أول نسخة عندك سنة 2020. الباقي مبني عليها.</p>\n<p>ظل عمران ينظر إلى الشاشة.</p>\n<p>لم يبك. رفع يده السليمة ووضعها على فمه، ثم قال بصوت كأنه يخرج من بئر:</p>\n<p>- يعني ابني مات من ست سنين وأنا بخدم قاتله.</p>\n<p>قال عمر:</p>\n<p>- مش مؤكد.</p>\n<p>صرخ عمران:</p>\n<p>- ما تقوليش مش مؤكد! أنا عشت على مش مؤكد عمري كله. أبويا مش مؤكد مات. ابني مش مؤكد مات. كل راجل في البيت ده يختفي ويسيب لنا احتمال ننام جنبه.</p>\n<p>حاول النهوض، فسقط الكوب وانكسر. أمسكه يوسف قبل أن يقع. قاومه لحظة، ثم ترك جسده يهبط.</p>\n<p>بعد دقائق، قال عمران بهدوء مخيف:</p>\n<p>- أنا عارف مكان حاجة رائف ما يعرفهاش.</p>\n<p>نظروا إليه.</p>\n<p>- لما رجالة نادر جم البيت زمان، واحد منهم كان بيتكلم مع أمي. سألها عن «قماش سالم». أمي قالت اتحرق. بعد سنين، وأنا برمم سقف المخزن، لقيت قطعة قماش ملفوفة جوه عارضة خشب. عليها خمس نخلات وكلام مش مفهوم. خفت أسلمها لرائف، وخفت أقول لحد. حطيتها في مقام قديم عند قوص، في تجويف ورا حجر مكسور.</p>\n<p>قالت ليلى:</p>\n<p>- قطعة القماش التي في صورة فؤاد.</p>\n<p>- دي كانت نسخة. الأصل معايا.</p>\n<p>- لماذا لم يأخذها نادر؟</p>\n<p>- أبويا بدّلها قبل ما يدخل الحجرة. الظاهر إنه كان عارف إن حد في البعثة خاين.</p>\n<p>قال عمر:</p>\n<p>- وأبويا يعرف الخائن. ده اللي كتبه نعيم.</p>\n<p>مد عمران يده إلى يوسف.</p>\n<p>- ساعدني أقوم. هنروح قوص.</p>\n<p>قال يوسف:</p>\n<p>- إنت محتاج مستشفى.</p>\n<p>- محتاج أعمل حاجة واحدة صح قبل ما جسمي يقرر يعاقبني على الباقي.</p>\n<p>رفضت ليلى أن يتحرك قبل الفجر. خلال الانتظار شرحت لهم ما تعرفه عن سالم الوراق، صاحب الطبقة العربية في الكتاب. لم يبقَ من نصه إلا صفحات مصورة سنة 1978. كان يكتب كمن يعترف أمام قاضٍ، لكنه لا يذكر جريمته مباشرة. يكرر جملة واحدة: «بعت الباب ولم أبع البيت.»</p>\n<p>قال يوسف:</p>\n<p>- يعني باع المكان.</p>\n<p>قالت ليلى:</p>\n<p>- أو جعل شخصًا يعتقد ذلك.</p>\n<p>قال عمران من الفراش:</p>\n<p>- أمي كانت بتقول مثل غريب: اللي يبيع الباب يفضل له الحيطان.</p>\n<p>رفعت ليلى رأسها.</p>\n<p>- لم أسمع هذا المثل خارج أوراق سالم.</p>\n<p>- كانت تقوله لما حد يلوم أبويا.</p>\n<p>أحضرت خريطة، وحددت طريق قوص القديم. المقام الذي وصفه عمران يقع قرب بقايا خان للقوافل، بُني فوق أساسات أقدم. في نص سالم إشارة إلى «بيت المراكب التي تمشي على الرمل»، وهي تسمية للقوافل.</p>\n<p>قالت سلمى:</p>\n<p>- لو القماش فيه زاوية الضوء الثالثة، نحتاج الأولى والثانية والرابعة والخامسة.</p>\n<p>- الأولى في نص حوري، قالت ليلى. الثانية في كتاب بقطر. الثالثة مع سالم. الرابعة وضعها نعيم في مكان لا نعرفه. الخامسة ليست شيئًا تركه أحد.</p>\n<p>- يبقى إيه؟</p>\n<p>نظرت إلى يوسف.</p>\n<p>- الاختبار.</p>\n<p>قبل الفجر بنصف ساعة سمعوا محرك سيارة يقترب. أطفأ محمود الأنوار ورفع بندقيته.</p>\n<p>توقفت السيارة عند الباب.</p>\n<p>جاء صوت امرأة من الخارج:</p>\n<p>- دكتورة ليلى؟ أنا مها عبد الوارث.</p>\n<p>أم يوسف.</p>"}, {"id": "chapter-11", "order": 11, "title": "الفصل الحادي عشر: سالم يبيع الباب", "section": "القسم الثاني: العلامات الخمس", "firstLine": "قوص، سنة 792 للهجرة", "wordCount": 763, "minutes": 4, "era": "792 هـ", "theme": "medieval", "sound": "rain", "icon": "✦", "scene": "قوص — صعيد مصر", "html": "<p>قوص، سنة 792 للهجرة</p>\n<p>لم يكن سالم الوراق خائنًا حين دخل خان السيوفي. صار خائنًا بعد أن خرج منه، وهذه مسافة لا تتجاوز أربعين خطوة.</p>\n<p>كان المطر نادرًا في قوص، لكنه هطل تلك الليلة وملأ الفناء برائحة الطين وروث الجمال. جلس سالم أمام التاجر صفي الدين السيوفي، وبينهما صندوق صغير من خشب الجميز. في الخارج كانت ابنته فريدة تسعل داخل العربة، سعالًا جافًا يزداد كل ليلة، والطبيب قال إن الدواء يأتي مع قافلة الشام ولن يعطيه بالدين.</p>\n<p>فتح صفي الدين الصندوق.</p>\n<p>في داخله نصف قرص نحاسي وورقة كتبت عليها خمس نخلات.</p>\n<p>قال:</p>\n<p>- هذا لا يساوي ثمن الدواء.</p>\n<p>- يساوي ما تبحث عنه عائلتك من مئات السنين.</p>\n<p>ابتسم التاجر. كان رجلًا رقيق الصوت، يلبس ثوبًا بلا زينة، ولا يشبه اللصوص في الحكايات. لهذا خافه سالم.</p>\n<p>- عائلتي تبحث عن طرق التجارة، يا ورّاق. لا عن خرز الموتى.</p>\n<p>- ورجالك الذين فتشوا دكاني أمس كانوا يبحثون عن ماذا؟ كتب النحو؟</p>\n<p>أغلق صفي الدين الصندوق.</p>\n<p>- أنت الذي جئت إلينا.</p>\n<p>جاء سعال فريدة من الخارج. انحنت كتفا سالم.</p>\n<p>- أريد قارورة الدواء وخمسين دينارًا.</p>\n<p>- خمسة.</p>\n<p>- ثلاثين.</p>\n<p>- عشرة، وحماية لك ولابنتك من والي قوص الذي يسأل عن ديونك.</p>\n<p>- والكتاب الأسود يبقى معي.</p>\n<p>لمعت عينا التاجر.</p>\n<p>- إذن هو موجود.</p>\n<p>عرف سالم أنه أخطأ. لم يذكر الكتاب أحد قبله.</p>\n<p>نهض.</p>\n<p>- انتهى الكلام.</p>\n<p>قال صفي الدين:</p>\n<p>- اجلس. ابنتك تنزف حين تسعل، وأنت لا تملك ثمن كفنها. لا تجعل الكبرياء يقتلها ثم تسمي نفسك أبًا صالحًا.</p>\n<p>ظل سالم واقفًا. تذكر زوجته يوم ماتت وهي تضع فريدة. أمسكته من ثوبه وقالت: «لا تورّثها ما ورثته أنت.» كان يقصد السر، أو الفقر، أو الخوف؛ لم يسألها.</p>\n<p>جلس.</p>\n<p>- عشرون وقارورة.</p>\n<p>- وخريطة الباب.</p>\n<p>- أعطيك موضع الباب، لا ما وراءه.</p>\n<p>- لا فرق.</p>\n<p>قال سالم:</p>\n<p>- الفرق هو كل شيء.</p>\n<p>أخرج من كمه قطعة قماش عليها خمس نخلات مطرزة بخيوط زرقاء. تحت كل نخلة عدد مختلف من العقد. وضع إصبعه على الثالثة.</p>\n<p>- عند فجر اليوم السابع بعد أقصر نهار، قف أمام البئر ذات الحجرين، واجعل ظل النخلة الثالثة يقع على الشق. هناك الباب.</p>\n<p>دفع صفي الدين إليه كيسًا وقارورة زجاجية.</p>\n<p>- إن كذبت، لن تموت وحدك.</p>\n<p>خرج سالم. كانت الأربعون خطوة إلى العربة أطول طريق مشاه في حياته. فتح القارورة وأعطى ابنته الجرعة. نامت فريدة للمرة الأولى منذ أيام من غير سعال.</p>\n<p>عند الفجر جاء رجال السيوفي وأخذوه معهم إلى الجبل.</p>\n<p>كان سالم قد رسم لهم طريقًا يؤدي إلى مدخل قديم من عصر بقطر. وضعوا القرص في الحجر، وعدّوا عقد النخلة الثالثة. انفتح ممر صغير.</p>\n<p>ابتسم صفي الدين.</p>\n<p>- قلت إنك بعت الباب فقط.</p>\n<p>قال سالم:</p>\n<p>- وهذا هو الباب.</p>\n<p>دخل الرجال. لم يدخل سالم.</p>\n<p>بعد دقائق سمع صراخًا، ثم صوت انهيار. خرج رجل واحد ووجهه مغطى بالدم. أمسك سالم من عنقه:</p>\n<p>- قادتنا إلى بئر دفن!</p>\n<p>كان الممر الكاذب ينتهي إلى حفرة صممها حوري لمن يدخل بالزاوية الخطأ. مات ثلاثة رجال تحت الحجارة.</p>\n<p>اقترب صفي الدين، وعلى ثوبه غبار لا دم.</p>\n<p>- كنت تعرف.</p>\n<p>- قلت لك: بعت الباب. لم أقل إنه باب البيت.</p>\n<p>ضربه التاجر بعصاه فسقط. أمسكوا يديه وسحبوه إلى الخان. طوال الطريق كان سالم يبتسم لأن فريدة بعيدة، ولأن القماش الذي أعطاهم إياه نسخة تنقصها عقدة واحدة.</p>\n<p>حين وصلوا وجد العربة فارغة.</p>\n<p>قال صفي الدين:</p>\n<p>- أين ابنتك؟</p>\n<p>لم يجب.</p>\n<p>في الليلة السابقة، قبل دخوله الخان، أرسل فريدة مع راهب مسافر إلى أخميم، وأعطاها الكتاب الأسود والقماش الأصلي. أوصاها ألا تستخدم اسمها، وأن تتزوج رجلًا لا يعرف شيئًا عن الأسرار.</p>\n<p>لكن الأطفال لا ينفذون وصايا الآباء كاملة. احتفظت فريدة باسمها، وحكت لابنها أن أباها باع الباب لينقذها. وهكذا وصل العار إلى الأجيال أسرع من الحقيقة.</p>\n<p>حبس صفي الدين سالم في مخزن القوافل. لم يعذبه في اليوم الأول. جلس أمامه وسأله:</p>\n<p>- لماذا تحرسون المكان؟</p>\n<p>- لأنكم تريدونه.</p>\n<p>- جواب طفل.</p>\n<p>- وجشعكم سؤال طفل.</p>\n<p>في اليوم الثالث كسروا إصبعًا من يده اليمنى. في الخامس أحضروا رجلًا قال إنه رأى فريدة في الطريق. في السابع اعترف سالم بمكان الكتاب: دير مهجور غرب النهر.</p>\n<p>كان اعترافًا قديمًا. الكتاب لم يعد هناك منذ زمن بقطر. لكنه أعطى صفي الدين شيئًا يطارده، وهذا ما احتاجه.</p>\n<p>قبل موته طلب ورقًا وحبرًا ليكتب الخريطة الصحيحة. وافق التاجر، ظنًا أن الألم انتصر.</p>\n<p>رسم سالم خمس نخلات، لكنه لم يضع الطريق في الجذوع أو العقد. أخفاه في الفراغات بين الأغصان، حيث لا ينظر من يفتش عن العلامات.</p>\n<p>كتب أسفلها:</p>\n<p><strong>أنا سالم بن مروان، بعت الباب لأشتري ليلة لابنتي. من يقرأني لا يغفر لي ولا يلعنني قبل أن يعرف ثمن الليالي. البيت غرب ظل الخيانة، لا شرقها.</strong></p>\n<p>ثم طوى القماش داخل عارضة من خشب الخان.</p>\n<p>عندما جاء صفي الدين صباحًا، وجد سالم ميتًا والحبر على أصابعه.</p>\n<p>أما القماش الذي وجدوه فوق الطاولة، فكان نسخة ثالثة تقود إلى قبر فارغ.</p>\n<p>منذ ذلك اليوم صار اسم السيوفي مرتبطًا بعلامة ابن آوى المشقوق. ليس لأنهم ورثوها، بل لأن سالم رسمها على باب الخان بدم إصبعه المكسور.</p>\n<p>كان يريد أن يحذر من يأتي بعده.</p>\n<p>لكن التحذيرات القديمة تشبه الزينة حين ينسى الناس سببها.</p>"}, {"id": "chapter-12", "order": 12, "title": "الفصل الثاني عشر: أم يوسف تعرف الطريق", "section": "القسم الثاني: العلامات الخمس", "firstLine": "دخلت مها البيت وهي تحمل حقيبة صغيرة وكأنها جاءت لزيارة عائلية. لم تعانق ابنها. ضربته على كتفه أولًا، ثم جذبته إليها.", "wordCount": 683, "minutes": 4, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>دخلت مها البيت وهي تحمل حقيبة صغيرة وكأنها جاءت لزيارة عائلية. لم تعانق ابنها. ضربته على كتفه أولًا، ثم جذبته إليها.</p>\n<p>- تقفل تليفونك وتسافر وراك ناس؟ أنت عندك سبع سنين؟</p>\n<p>قال يوسف وهو يبتعد:</p>\n<p>- إنتِ عرفتي المكان إزاي؟</p>\n<p>- عمران كلمني قبل ما تروح له. قال لي إنك فتحت بيت أبويا، وبعدها الخط اتقفل. كلمت سلمى.</p>\n<p>نظر إلى سلمى.</p>\n<p>قالت:</p>\n<p>- رقمها عندي من زمان.</p>\n<p>- من زمان ليه؟</p>\n<p>- مش وقت غيرة متأخرة، قالت أمه. عايز تعرف إيه اللي مخبياه؟ هقول.</p>\n<p>جلست أمام ليلى. تبادلتا نظرة طويلة، ثم قالت مها:</p>\n<p>- كنتِ مع أبويا آخر ليلة؟</p>\n<p>- قبل الأخيرة، قالت ليلى.</p>\n<p>- كنتِ تعرفي إنه رجع البيت؟</p>\n<p>- عرفت بعد سنين.</p>\n<p>- وسبتونا نصدق إنه هرب.</p>\n<p>- كنت تحت تهديد، واتمنعت من الشغل، وزوجي مات.</p>\n<p>- وأنا كنت عندي أربع سنين. كل واحد فيكم عنده سبب كويس جدًا.</p>\n<p>لم ترد ليلى.</p>\n<p>أخرجت مها من حقيبتها شريطًا رفيعًا من الخشب، بطول ذراع، محفورًا عليه صف من العلامات. قالت:</p>\n<p>- ده كان في ظهر دولاب أمي. قبل ما تموت قالت لي لو القطعة رجعت، أدي الشريط ليوسف، مش لعمران.</p>\n<p>انقبض وجه عمران، لكنه لم يعترض.</p>\n<p>قال يوسف:</p>\n<p>- ليه أنا؟</p>\n<p>- عشان أنت آخر واحد في العيلة ما عاشش عمره كله مستني راجل غايب. قالت إن اللي هيفتح المكان لازم يكون عنده فضول من غير ثأر.</p>\n<p>تفحصت ليلى الشريط. العلامات ليست هيروغليفية كاملة، بل خطوط قياس وأرقام عربية حديثة أضافها نعيم. في طرفه ثقب يطابق حجم القطعة النحاسية.</p>\n<p>وضعت القرص فيه. استقرت الشقوق الخمسة مقابل خطوط مختلفة.</p>\n<p>قالت سلمى:</p>\n<p>- دي مسطرة ظل.</p>\n<p>- الرابعة، قالت ليلى. نعيم لم يخبئ زاوية في الفيلم. صنع أداة تجمع الزوايا الأربع.</p>\n<p>- والخامسة؟ سأل يوسف.</p>\n<p>قالت مها:</p>\n<p>- أغنية.</p>\n<p>نظروا إليها.</p>\n<p>- أبويا كان بيغني لنا وإحنا صغيرين: «خمسة مشوا للجبل، أربعة رجعوا بظلالهم، والخامس رجع باسمه». أمي كانت بتمنعه. بعد ما اختفى بطلت تغنيها، لكني فاكرة اللحن.</p>\n<p>طلبت ليلى أن تغني. رفضت مها أولًا، ثم فعلت بصوت خافت خالٍ من الزخرفة. كان اللحن بسيطًا، كل جملة تنتهي بنغمة أطول. طرقت سلمى بإصبعها مع الإيقاع.</p>\n<p>- خمس جمل. أطوال مختلفة.</p>\n<p>حركت القرص داخل الشريط وفق عدد النبضات. انطبقت الشقوق على خطوط القياس، وتكوّن سهم يشير إلى الجنوب الغربي.</p>\n<p>قالت ليلى:</p>\n<p>- ليس موقعًا. اتجاه من نقطة مرجعية.</p>\n<p>- مقام قوص، قال عمران. القماش يعطي النقطة.</p>\n<p>قرروا الانطلاق فورًا قبل أن يعرف رائف أن عمران هرب. بقيت مها مع ليلى ومحمود، وذهبت سلمى ويوسف وعمر وعمران في سيارة واحدة. كان الفجر يقترب حين وصلوا إلى بقايا الخان قرب قوص.</p>\n<p>المقام بناء صغير بقبة مائلة، محاط بمقابر حديثة. فتح عمران تجويفًا خلف حجر عند القاعدة وأخرج لفافة قماش داخل أنبوب بلاستيكي.</p>\n<p>قال يوسف:</p>\n<p>- حاطط أثر عمره ستمية سنة في كيس تلاجة؟</p>\n<p>- كان كيس محترم.</p>\n<p>فردت سلمى القماش فوق غطاء السيارة. خمس نخلات زرقاء، وتحتها زخارف هندسية. بعض الخيوط تآكلت، لكن العقد ظاهرة.</p>\n<p>أخرجت مسطرة نعيم ووضعتها فوق النخلة الثالثة. لم تتطابق.</p>\n<p>قال عمران:</p>\n<p>- يمكن القماش غلط.</p>\n<p>- أو إحنا بنبص للناحية الغلط، قال يوسف.</p>\n<p>تذكر عبارة سالم التي نقلتها ليلى: البيت غرب ظل الخيانة، لا شرقها. قلب القماش على ظهره. ظهرت الفراغات بين الأغصان كخطوط متصلة، تشكل رسمًا لوادٍ وخمس نتوءات صخرية.</p>\n<p>وضعت سلمى المسطرة ثانية. انطبق السهم على نتوء صغير قرب حافة القماش.</p>\n<p>رفع عمر هاتفًا عليه خريطة طبوغرافية قديمة.</p>\n<p>- فيه وادي مهجور بالوصف ده غرب القرنة، اسمه عند البدو وادي الخرس.</p>\n<p>قال يوسف:</p>\n<p>- ليه الخرس؟</p>\n<p>قال عمران:</p>\n<p>- لأن الصدى فيه ما بيرجعش.</p>\n<p>جاء صوت سيارة من الطريق.</p>\n<p>انطفأت مصابيحها قبل أن تقترب.</p>\n<p>قال عمر:</p>\n<p>- انزلوا.</p>\n<p>انتشروا خلف جدران الخان. توقفت سيارتان، ونزل منهما حازم وخمسة رجال. كان حازم يمسك هاتفًا وينظر إلى الشاشة.</p>\n<p>همس عمران:</p>\n<p>- حاطين جهاز تتبع فيا.</p>\n<p>فتش يوسف ثيابه بسرعة. وجد تحت رباط الذراع قطعة سوداء صغيرة ألصقها خاطفوه.</p>\n<p>نزعتها سلمى، ونظرت حولها، ثم ركضت منحنية إلى جمل مربوط قرب المقام ووضعته داخل كيس العلف المعلق بسرجه. صفعت الحيوان فانطلق مذعورًا نحو الطريق الزراعي.</p>\n<p>نظر حازم إلى هاتفه، ثم صاح برجاله أن يتبعوا الإشارة.</p>\n<p>تحركت السيارتان خلف الجمل.</p>\n<p>كتم عمران ضحكة تحولت إلى ألم.</p>\n<p>قال عمر:</p>\n<p>- عندنا عشر دقائق قبل ما يكتشفوا إن الوريث عنده أربع رجلين.</p>\n<p>لكن قبل أن يركبوا، خرج رجل سادس من داخل المقام. كان ينتظرهم منذ البداية.</p>\n<p>وجه مسدسه إلى رأس مها، التي لم تبقَ مع ليلى كما اتفقوا.</p>\n<p>قالت مها، بغضب أكثر من الخوف:</p>\n<p>- قلت لكم مش هقعد.</p>\n<p>وقف خلفها رائف السيوفي.</p>\n<p>- وأنا ممتن لعناد العائلة، قال. يوفر عليّ جمعكم واحدًا واحدًا.</p>"}, {"id": "chapter-13", "order": 13, "title": "الفصل الثالث عشر: اتفاق في المقابر", "section": "القسم الثاني: العلامات الخمس", "firstLine": "لم يرفع رائف صوته، ولم يحتج إلى ذلك. كان يحمل مسدسًا صغيرًا ملاصقًا لجانب مها، وخلفه رجلان ظهرا من ظلام المقام.", "wordCount": 693, "minutes": 4, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>لم يرفع رائف صوته، ولم يحتج إلى ذلك. كان يحمل مسدسًا صغيرًا ملاصقًا لجانب مها، وخلفه رجلان ظهرا من ظلام المقام.</p>\n<p>قال يوسف:</p>\n<p>- سيبها وخد القماش.</p>\n<p>- القماش عندي منه ثلاث نسخ.</p>\n<p>- دي الأصلية.</p>\n<p>- أعرف. لكن الأصل من دون الشخص الذي يفهمه مجرد قطعة متسخة.</p>\n<p>أشار إلى مسطرة نعيم في يد سلمى.</p>\n<p>- أريد الأداة، القرص، والفيلم.</p>\n<p>قال عمر:</p>\n<p>- والفيديو اللي يثبت قتل أبويا؟</p>\n<p>ابتسم رائف.</p>\n<p>- لا يوجد فيديو.</p>\n<p>- الصور تكفي تفتح قبر أبوك من جديد.</p>\n<p>- أبي في قبر حقيقي، يا حضرة الضابط. على عكس كثيرين في هذه الحكاية.</p>\n<p>تحرك عمران خطوة. ضغط رائف السلاح إلى جسد مها.</p>\n<p>- لا تختبرني. أنت بالذات استنفدت فرصك.</p>\n<p>قال عمران:</p>\n<p>- أيمن فين؟</p>\n<p>نظر إليه رائف كما ينظر طبيب إلى مريض يعرف التشخيص.</p>\n<p>- مات في أول أسبوع من الاحتجاز. أصيب بنزيف بعد الضرب. لم أكن موجودًا، لكني ورثت المشكلة.</p>\n<p>أغلق عمران عينيه. كان الاعتراف أرحم من الاحتمال، ولهذا بدا وجهه فارغًا لا محطمًا.</p>\n<p>قال رائف:</p>\n<p>- الفيديوهات كانت وسيلة عملية. أنت خدمت ابنك بعد موته، وهذا أكثر مما يفعله آباء كثيرون لأبنائهم وهم أحياء.</p>\n<p>اندفع عمران. كانت حركة بطيئة بسبب إصابته، ومع ذلك لم يتوقعها الرجل خلف رائف. اصطدم به وأسقطه. جذبت مها ذراع رائف إلى أسفل، فانطلقت الرصاصة في التراب.</p>\n<p>أطلق عمر النار على مصباح السيارة، فغرق المكان في الظلام. أمسك يوسف بالقماش والمسطرة، وسحب أمه خلف جدار مقبرة. صاحت سلمى:</p>\n<p>- ناحية الزرع!</p>\n<p>ركضوا بين القبور. الرصاص يضرب الحجارة من حولهم. كان عمران آخرهم، يتعثر لكنه يرفض أن يمسكه أحد.</p>\n<p>وصلوا إلى ساقية جافة وانزلقوا داخلها. قادهم عمر على طول المجرى حتى ابتعدت الأصوات. عند حافة مزرعة وجدوا عربة نقل صغيرة يقودها رجل مسن. أوقفه عمر ببطاقته، ثم أخذوا العربة بعد أن وعده بإعادتها.</p>\n<p>قال الرجل وهو يراقبهم يصعدون:</p>\n<p>- دي حكومة ولا عيلة؟</p>\n<p>قالت مها:</p>\n<p>- للأسف الاتنين.</p>\n<p>تحركوا نحو الطريق العام. بعد كيلومترين، رن هاتف يوسف الجديد. رقم رائف.</p>\n<p>رد.</p>\n<p>- نسيت تعرض عليّ أرجّع اسم جدي.</p>\n<p>قال رائف:</p>\n<p>- العرض قائم. لكن السعر ارتفع.</p>\n<p>- أمي كانت في إيدك وسيبتها.</p>\n<p>- لأنني لا أريد قتل أمك. أريد فتح الحجرة. وأنت ستفعل، لأن شيئًا فيها يخصك أكثر مما تظن.</p>\n<p>- الذهب؟</p>\n<p>- الذهب أقل ما فيها.</p>\n<p>- إيه أكتر؟</p>\n<p>صمت رائف لحظة، ثم قال:</p>\n<p>- جدك.</p>\n<p>انقطع الخط.</p>\n<p>نظرت مها إلى يوسف. كانت تسمع من قربه.</p>\n<p>قالت:</p>\n<p>- كذاب.</p>\n<p>لكن يدها كانت ترتجف.</p>\n<p>عادوا إلى بيت ليلى، فوجدوا الباب مفتوحًا ومحمود غائبًا. الأوراق مبعثرة، والكمبيوتر محطم. على الأرض بقعة دم صغيرة لا تكفي لمعرفة مصير أحد.</p>\n<p>وجدت سلمى ليلى في مخزن خلفي، مقيدة وفاقدة الوعي. كانت تتنفس. بجوارها ورقة تركها رائف:</p>\n<p><strong>موعدنا عند الباب الخامس. لا تتأخروا، فالوادى لا يحتمل أكثر من وريث.</strong></p>\n<p>قال عمر:</p>\n<p>- عنده شخص آخر من العيلة.</p>\n<p>نظر عمران إلى الورقة.</p>\n<p>- مفيش غيرنا.</p>\n<p>قالت مها:</p>\n<p>- فيه.</p>\n<p>اتجهت الأنظار إليها.</p>\n<p>- أبوكم نعيم كان له أخ من الأب سافر السودان وهو صغير. العيلة قطعت خبره. أمي كانت بتقول إن له ولاد رجعوا أسوان في التسعينات.</p>\n<p>قالت ليلى حين أفاقت:</p>\n<p>- الحالات الأربع لم تكن كلها رجالًا غرباء. الحالة الثالثة اسمها الحقيقي عادل حوري عبد الوارث، من أسوان. اختفى سنة 2023.</p>\n<p>- ورائف قال جدك، قال يوسف.</p>\n<p>- لم يقل أي جد، رد عمر. ممكن يكون وجد عادل أو جثمانه داخل الموقع.</p>\n<p>فتشوا ما بقي من أوراق ليلى. كانت قد أخفت نسخة من خريطة 1978 داخل غلاف كتاب طبخ. أظهرت موقع الحجرة القديمة ومسارًا جانبيًا لم يُستكمل مسحه. عند نهاية المسار كتبت بقلم أحمر: <strong>صوت ماء بلا ماء</strong>.</p>\n<p>قال عمران:</p>\n<p>- وادي الخرس فيه عين ناشفة، لكن تحتها مجرى قديم. لما تحط ودنك على الصخر تسمع صوت كأنه مية.</p>\n<p>- تعرف الطريق؟</p>\n<p>- أبويا خدني مرة وأنا صغير. قال لي لو ضعت امشِ عكس الصدى. افتكرت إنه بيهزر.</p>\n<p>قرر عمر الاتصال بفريق يثق به من النيابة وشرطة الآثار. وجد هاتفه بلا شبكة. جرّب اللاسلكي في السيارة؛ مشوش.</p>\n<p>قالت ليلى:</p>\n<p>- الوادي محاط بجبل. الشبكة ضعيفة طبيعيًا، ورائف عنده أجهزة تشويش.</p>\n<p>قال عمر:</p>\n<p>- ندخل من غير دعم يبقى بنحقق له اللي عايزه.</p>\n<p>قال يوسف:</p>\n<p>- لو استنينا، هيفتح بالراجل التاني أو يقتله.</p>\n<p>- مش هيفتح. عنده أربع زوايا بس.</p>\n<p>رفعت مها مسطرة أبيها.</p>\n<p>- والخامسة أغنية أعرفها أنا ويوسف.</p>\n<p>قالت سلمى:</p>\n<p>- يبقى مش يوسف وحده الاختبار. العيلة كلها.</p>\n<p>ساد صمت قصير.</p>\n<p>ثم قال عمران:</p>\n<p>- فيه طريق رعاة يدخل الوادي من الجنوب. العربيات ما تعرفوش. نوصل قبلهم للعين الناشفة.</p>\n<p>نظر عمر إلى كتفه المصاب، وإلى ذراع عمران المكسورة، وإلى ليلى التي بالكاد جلست.</p>\n<p>- فريق ممتاز لاقتحام جبل.</p>\n<p>قالت مها:</p>\n<p>- أنت ممكن تقعد.</p>\n<p>ابتسم عمر للمرة الأولى.</p>\n<p>- دلوقتي فهمت يوسف طالع لمين.</p>"}, {"id": "chapter-14", "order": 14, "title": "الفصل الرابع عشر: الحجرة الأولى", "section": "القسم الثاني: العلامات الخمس", "firstLine": "عندما واجه حوري باحري في الحجرة، لم يكن يملك سلاحًا. كان يحمل قلمًا من البوص، ومريت تحمل طفلًا لم يولد بعد. أما باحري فكان فوقهما ومعه حارسان.", "wordCount": 589, "minutes": 3, "era": "مصر القديمة", "theme": "ancient", "sound": "stone", "icon": "𓂀", "scene": "طيبة — وادي النيل", "html": "<p>عندما واجه حوري باحري في الحجرة، لم يكن يملك سلاحًا. كان يحمل قلمًا من البوص، ومريت تحمل طفلًا لم يولد بعد. أما باحري فكان فوقهما ومعه حارسان.</p>\n<p>قال المشرف:</p>\n<p>- ارمِ القرص.</p>\n<p>رفع حوري وجهه إلى الفتحة.</p>\n<p>- لو أخذته، لن تعرف أين المخزن.</p>\n<p>- أعرف أنك ستدلني.</p>\n<p>- قتلت جحوتي قبل أن يدلّك.</p>\n<p>- جحوتي كان يظن أن كتابة الحقيقة تجعلها قوية. الحقيقة ورق. النار أقوى.</p>\n<p>أشعل أحد الحراس شعلة وألقاها إلى الحجرة. سقطت قرب لفائف السجلات. أسرعت مريت وضربتها بقطعة قماش، لكن النار أمسكت بطرف إحدى البرديات.</p>\n<p>أخرج حوري القرص وأمسكه بحيث يراه باحري.</p>\n<p>- اتركها تخرج.</p>\n<p>- كلاكما.</p>\n<p>- هي أولًا.</p>\n<p>أمر باحري حارسه أن يمد حبلًا. ربطت مريت الحبل حول خصرها، لكنها همست لحوري:</p>\n<p>- لا تعطهم شيئًا.</p>\n<p>- الطفل...</p>\n<p>- الطفل لا يحتاج أبًا يعيش عبدًا لخوفه.</p>\n<p>صعدت. ما إن وصلت إلى الفتحة حتى أمسكها الحارسان. وضع باحري سكينًا على بطنها.</p>\n<p>- الآن القرص.</p>\n<p>رماه حوري.</p>\n<p>التقطه باحري، وابتسم. ثم دفع مريت إلى جانب الحارسين.</p>\n<p>- اقتلوها خارجًا.</p>\n<p>صرخ حوري واندفع نحو الجدار. في اللحظة نفسها عضت مريت يد الحارس، وانتزعت شعلته. ضربت بها وجه الرجل الآخر. سقط الاثنان عند الفتحة، وتدحرج أحدهما إلى الحجرة.</p>\n<p>قفز باحري خلفه ليحمي القرص.</p>\n<p>كان ذلك ما أراده حوري.</p>\n<p>أمسك بلوح طيني من الأرض وضرب ركبة المشرف. سقط باحري، وانزلق القرص من يده. التقطه حوري، لكن الحارس الذي سقط معه أمسك ساقه. تشابكوا بين الرفوف، واشتعلت النار في لفافة أخرى.</p>\n<p>صرخت مريت من أعلى:</p>\n<p>- الحجر الخامس!</p>\n<p>كان جحوتي قد أراها مرة رسمًا سريًا؟ لم يفهم. نظر حوله. في الجدار خمسة أحجار بارزة، كل واحد يحمل علامة إصبع. ضغط الأول، لم يحدث شيء. ضغط الثاني، ثم الثالث. خلفه نهض باحري وسحب سكينه.</p>\n<p>ضغط الرابع.</p>\n<p>اقترب باحري.</p>\n<p>أما الخامس فكان منخفضًا قرب الأرض، وعليه بقعة حبر سوداء تشبه كفًا. ضغطه حوري بقدمه.</p>\n<p>انفتح جزء من الأرض تحت باحري والحارس. سقطا في ممر سفلي، ثم انغلق الحجر فوقهما. بقي صوت باحري يصيح من تحت الأرض:</p>\n<p>- ستدفن نفسك معهم!</p>\n<p>قال حوري:</p>\n<p>- على الأقل سيعرفون اسمي.</p>\n<p>أطفأ النار قدر استطاعته. أنقذ معظم السجلات، لكن خريطة المخزن احترق طرفها. عرف أن باحري إن خرج سيعود برجال أكثر، وأن الحجرة لن تبقى آمنة.</p>\n<p>قضى الليل ينقل أهم اللفائف إلى جرار محكمة. كتبت مريت أسماء الموتى على الجدار حتى لا تضيع إن أكلت النار الورق. عند الفجر رسم حوري كفًا سوداء فوق المدخل، ثم نقش أربعة وجوه بلا ملامح إلى جوار صورته.</p>\n<p>قالت مريت:</p>\n<p>- لماذا أربعة؟</p>\n<p>- لأن الباب يحتاج خمس شهادات. جحوتي كان الأولى، وأنا الثانية.</p>\n<p>- لكنك رسمت نفسك أولًا.</p>\n<p>ابتسم.</p>\n<p>- الكتبة يغشون في الترتيب.</p>\n<p>قسم حوري دليل الحجرة إلى أجزاء. وضع القياس الأول على القرص. أخفى الثاني في نص يمكن نسخه فوق نص آخر. جعل الثالث رسمًا لا يُقرأ إلا من ظهره. ترك الرابع لمن يأتي بعده، أما الخامس فلم يكتبه.</p>\n<p>قالت مريت:</p>\n<p>- وكيف يعرف آخرهم؟</p>\n<p>- لن يعرف. إذا وصل إليه السر كاملًا، سيختار: يفتح الباب لنفسه، أو يفتح الأسماء للناس. هذا اختباره.</p>\n<p>- وماذا لو اختار لنفسه؟</p>\n<p>نظر إلى الجدار المليء بأسماء العمال.</p>\n<p>- نكون قد حفظنا أسماءنا ثلاثة آلاف عام لنمنحها لصًا.</p>\n<p>- فكرة سيئة.</p>\n<p>ضحك، رغم الدخان والدم.</p>\n<p>بعد ثلاثة أيام جاء رجال باحري. وجدوا المقبرة خالية والمدخل منهارًا. لم يجدوا حوري ولا مريت.</p>\n<p>عاشا في قرية جنوبية باسمين جديدين. وُلد ابنهما، وفقد حوري إصبعه في عمل بالحجر بعد سنوات. مات في الثلاثين حين عاد سرًا إلى الحجرة ليضيف سجلًا جديدًا، وانهار عليه الممر.</p>\n<p>دفنته مريت في الداخل، ووضعت القرص بجواره.</p>\n<p>أما باحري، فخرج من الممر السفلي حيًا. فقد عينه اليسرى، لكنه احتفظ بما سمعه. علّم أبناءه أن بيتًا تحت التراب يخفي ثروة سُرقت منهم. رسم لهم رأس ابن آوى المشقوق، لأن آخر ما رآه قبل سقوطه كان القرص ينقسم أمام عينه المصابة.</p>\n<p>هكذا بدأت المطاردة.</p>\n<p>ليس من لعنة، ولا نبوءة.</p>\n<p>من رجل سرق الخبز، ورجل كتب السرقة.</p>"}, {"id": "chapter-15", "order": 15, "title": "الفصل الخامس عشر: وادي الخرس", "section": "القسم الثاني: العلامات الخمس", "firstLine": "تحركوا قبل غروب الشمس بساعتين. تركوا السيارات في مزرعة يملكها قريب لمحمود، وساروا جنوبًا عبر طريق رعاة لا يظهر على الخرائط. بقيت ليلى في البيت بسبب إصابتها، وأصرت مها على المجيء. لم يستطع يوسف منعها، ولم يحاول طويلًا.", "wordCount": 530, "minutes": 3, "era": "الحاضر — تحت الأرض", "theme": "underground", "sound": "water", "icon": "⌁", "scene": "وادي الخرس", "html": "<p>تحركوا قبل غروب الشمس بساعتين. تركوا السيارات في مزرعة يملكها قريب لمحمود، وساروا جنوبًا عبر طريق رعاة لا يظهر على الخرائط. بقيت ليلى في البيت بسبب إصابتها، وأصرت مها على المجيء. لم يستطع يوسف منعها، ولم يحاول طويلًا.</p>\n<p>كان عمران يسير وذراعه معلقة، يتصبب عرقًا لكنه لا يشتكي. عمر يحمل مسدسه وقطعة قماش حول كتفه. سلمى تحمل حقيبة فيها القماش والمسطرة والصور، كأنها تنقل مريضًا هشًا.</p>\n<p>وصلوا إلى حافة الوادي عند المغيب.</p>\n<p>فهم يوسف سبب الاسم. الجبال هنا لا تعيد الصوت؛ تبتلعه. رمى حجرًا، فسمع ارتطامه مرة واحدة بلا صدى. حتى خطواتهم بدت قريبة من أجسادهم، كأن العالم خارج متر واحد قد اختفى.</p>\n<p>قال عمران:</p>\n<p>- العين الناشفة بعد اللسان الحجري.</p>\n<p>أشار إلى صخرة طويلة بارزة من الجبل. مروا خلفها فوجدوا حفرة دائرية، قاعها مغطى بحصى أبيض. انحنى يوسف ووضع أذنه على الحجر. سمع خريرًا بعيدًا.</p>\n<p>قال:</p>\n<p>- فيه مية تحتنا.</p>\n<p>- مجرى قديم، قالت سلمى. ممكن يكون هو اللي نحت الممر.</p>\n<p>فردوا قماش سالم. وقفت مها في موضع النخلة الثالثة، وغنت اللحن. حركت سلمى القرص داخل مسطرة نعيم مع النبضات. اتجه السهم إلى جدار أملس لا فتحة فيه.</p>\n<p>قال عمر:</p>\n<p>- مستنيين الشمس؟</p>\n<p>- زاوية الفجر في النص، قالت سلمى. لكن نعيم عدّلها لمسار القمر. الليلة القمر يكمل قبل منتصف الليل.</p>\n<p>انتظروا في شق صخري. لم يشعلوا نارًا. أكل يوسف سندوتش الجبنة الذي وضعته أمه في حقيبته منذ القاهرة؛ كان مهروسًا ودافئًا، لكنه جعله يشعر للحظة أنه خارج كل هذا.</p>\n<p>قالت مها وهي تراه:</p>\n<p>- كنت عارفة إنك هتحتاجه.</p>\n<p>- كنتِ عارفة إني هدخل جبل؟</p>\n<p>- لا. عارفة إنك بتنسى تاكل لما تتوتر.</p>\n<p>جلس عمران بعيدًا. اقترب منه يوسف وأعطاه نصف السندوتش.</p>\n<p>قال عمه:</p>\n<p>- مش مستني منك تسامحني.</p>\n<p>- كويس.</p>\n<p>- بس لو خرجنا، أمك تعرف كل حاجة عن أيمن. ما تخلوهاش تقول لي كان ممكن تعمل كذا. أنا عارف كل حاجة كان ممكن أعملها.</p>\n<p>- قول لها بنفسك.</p>\n<p>- لو خرجنا.</p>\n<p>- قول لما نخرج.</p>\n<p>ظهر القمر فوق الحافة. وضعت سلمى القرص في المسطرة، ومر ضوؤه عبر الثقب ليسقط على الجدار. تحركت البقعة مع اللحن الذي غنته مها. عند النغمة الخامسة وصلت إلى شق رفيع لم يلاحظوه.</p>\n<p>ضغط يوسف القطعة النحاسية داخله.</p>\n<p>لم يحدث شيء.</p>\n<p>قالت مها:</p>\n<p>- الأغنية بتقول أربعة رجعوا بظلالهم، والخامس رجع باسمه. يمكن النغمة الأخيرة مش اتجاه. اسم.</p>\n<p>- اسم مين؟</p>\n<p>نظر يوسف إلى الجدار. على القماش أربع كلمات موزعة بين الأغصان: حوري، بقطر، سالم، نعيم. بقيت مساحة خامسة فارغة.</p>\n<p>قال:</p>\n<p>- يوسف.</p>\n<p>لا شيء.</p>\n<p>قال عمران:</p>\n<p>- اسم العيلة؟ عبد الوارث؟</p>\n<p>لا شيء.</p>\n<p>مررت سلمى أصابعها فوق الشق.</p>\n<p>- حوري كتب إن الأخير يختار. يمكن مش الاسم اللي اتولدت به. الاسم اللي تدخل به.</p>\n<p>فكر يوسف في إعلان جذور، وفي النسب المئوية، وفي رائف الذي يريد أن يعيد لجدّه اسمه. تذكر أن حوري قال إن كتابة الاسم تمنع موته الثاني.</p>\n<p>اقترب من الجدار وقال:</p>\n<p>- نعيم عبد الوارث لم يكن لصًا.</p>\n<p>صدر صوت عميق تحت أقدامهم.</p>\n<p>تحرك الجدار ببطء إلى الداخل.</p>\n<p>قال عمر:</p>\n<p>- واضح إن الجبل بيحب المحاضر الرسمية.</p>\n<p>فتح أمامهم ممر ضيق ينزل إلى الظلام. الهواء الخارج منه بارد ورطب. على أول درجة علامة كف سوداء.</p>\n<p>أضاء يوسف مصباحه.</p>\n<p>في آخر الممر كان هناك رجل مربوط إلى عمود حجري، رأسه منحني. رفعه حين رأى الضوء.</p>\n<p>كان يشبه صورة أيمن، لكنه أكبر بكثير.</p>\n<p>قال عمران بصوت مكسور:</p>\n<p>- ابني؟</p>\n<p>فتح الرجل عينيه.</p>\n<p>ثم جاء صوت تصفيق بطيء من خلفهم.</p>\n<p>وقف رائف السيوفي عند مدخل الوادي، وحوله رجال مسلحون.</p>\n<p>- الآن فقط، قال، اكتملت العائلة.</p>"}, {"id": "chapter-16", "order": 16, "title": "الفصل السادس عشر: رجل مات مرتين", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "أجبرهم حازم على رفع أيديهم. نزع مسدس عمر، وأخذ حقيبة سلمى والقطعة النحاسية ومسطرة نعيم. فتش الرجال عمران بعنف، مع أن ذراعه المكسورة كانت واضحة. لم يقاوم. كان ينظر فقط إلى الرجل المربوط في آخر الممر.", "wordCount": 881, "minutes": 5, "era": "الحاضر — تحت الأرض", "theme": "underground", "sound": "water", "icon": "⌁", "scene": "وادي الخرس", "html": "<p>أجبرهم حازم على رفع أيديهم. نزع مسدس عمر، وأخذ حقيبة سلمى والقطعة النحاسية ومسطرة نعيم. فتش الرجال عمران بعنف، مع أن ذراعه المكسورة كانت واضحة. لم يقاوم. كان ينظر فقط إلى الرجل المربوط في آخر الممر.</p>\n<p>قال:</p>\n<p>- أيمن؟</p>\n<p>رفع الرجل رأسه ثانية. كان شعره طويلًا تتخلله خصل بيضاء، ولحيته غير متساوية. في وجهه ندبة تبدأ من الأذن وتنتهي قرب الفم. لكنه حين قال «يا حاج» عاد عمره فجأة إلى صورة الشاب الذي خرج من البيت منذ سبع سنوات.</p>\n<p>اندفع عمران نحوه، فأمسكه أحد الرجال.</p>\n<p>قال رائف:</p>\n<p>- اتركه. لن يهرب أحد الآن.</p>\n<p>فك عمران الحبل بيده السليمة. سقط أيمن عليه، أضعف من أن يقف. ضمه أبوه من الرأس، ولم يتكلم أي منهما. كان صوت تنفسهما وحده يملأ الممر.</p>\n<p>قال يوسف لرائف:</p>\n<p>- قلت له مات.</p>\n<p>- قلت ما احتجت أن أقوله ليحسم موقفه. كان على وشك أن يظل متعلقًا بأمل يمنعه من الدخول.</p>\n<p>- وإنت حاططه جوه إزاي والباب كان مقفول؟</p>\n<p>أشار رائف إلى عمق الممر.</p>\n<p>- المدخل الذي فتحتموه هو الخامس. توجد فتحة أخرى من حجرة 1978، لكنها انهارت جزئيًا. نستطيع إدخال رجل، لا إخراج شيء كبير. أيمن عاش هناك أسابيع في كل مرة، نجرب معه العلامات.</p>\n<p>رفع عمران وجهه.</p>\n<p>- أسابيع؟</p>\n<p>قال أيمن بصوت أجش:</p>\n<p>- مش طول السنين يا حاج. كانوا بينقلوني. مخزن، بيت، جبل... بطلت أعرف.</p>\n<p>- ليه ما خرجتهوش بعد ما لقيت إنه ما يعرفش؟ سأل يوسف.</p>\n<p>قال رائف:</p>\n<p>- لأنه كان أول دليل على أننا وجدنا الفرع الصحيح. ثم صار ضمانًا لتعاون أبيه. البشر الذين لا يعرفون شيئًا قد يكونون مفيدين جدًا.</p>\n<p>أعطى حازم أوامر لرجاله. دخل اثنان أولًا بالمصابيح، ثم دفعوا يوسف أمامهم. حمل عمران ابنه بمساعدة مها. سلمى تسير إلى جوار ليلى في ذهنها، تكرر التعليمات التي قالتها قبل أن تبقى خلفهم: لا تلمسوا ورقًا مكشوفًا، لا تتنفسوا غبارًا أبيض، ولا تصدقوا أن الممر الذي يبدو مستقيمًا مستقيم.</p>\n<p>نزلوا ثلاثين درجة، ثم وصلوا إلى قاعة نصفها طبيعي ونصفها منحوت. على الجدار صف من فتحات المصابيح القديمة، بعضها يحمل سخامًا حديثًا من بعثة نادر. في الأرض سكة حديد صغيرة صدئة استخدمها العمال سنة 1978 لنقل الردم.</p>\n<p>توقف رائف عند بقعة محفور حولها حرف N بالإنجليزية.</p>\n<p>- هنا وقف أبي، قال. كان في الخامسة والثلاثين، مقتنعًا أنه على بعد ساعات من أكبر اكتشاف في القرن. خرج من الوادي بلا اكتشاف، وبجثتين، ورجل مفقود، وسمعة اشتراها بالصمت.</p>\n<p>قال عمر:</p>\n<p>- جثة مين؟</p>\n<p>- ستعرف.</p>\n<p>واصلوا السير حتى انفتح الممر على الحجرة التي ظهرت في صور نعيم. الكف السوداء ما زالت على الجدار، والأسماء تمتد حولها. الرفوف متربة لكن معظم الجرار بقي في مكانه. في الركن الهيكل القديم لحوري، إلا أن الخاتم لم يعد بجواره.</p>\n<p>اقترب يوسف خطوة.</p>\n<p>كان غريبًا أن ينظر إلى عظام رجل قيل له إن دمه يحمل أثره. لم يشعر بقرابة، ولا رهبة مقدسة. شعر بحزن عادي تجاه شخص مات وحيدًا وهو يحاول أن يضيف ورقة إلى غرفة.</p>\n<p>وضع رائف القرص في صندوق زجاجي صغير كان يحمله حازم، كأنه يخشى أن يلمسه الهواء.</p>\n<p>- A-17، قال. أخذ أبي جزءًا من ضلعه. كانت العينة الوحيدة التي خرجت من هنا وبقيت قابلة للتحليل.</p>\n<p>قال يوسف:</p>\n<p>- وحوّلتوا بلد كاملة لمعمل عشان تعرفوا مين قريبه.</p>\n<p>- لم نبحث عن قريب. بحثنا عن ذاكرة. العائلات التي تبقى في المكان نفسه تحفظ أشياء لا تسجلها الدولة: أغنية، اسم بئر، سبب خوف من حجر. الجينات أعطتنا قائمة احتمالات، ثم تولى الخوف غربلتها.</p>\n<p>وقف عمر أمام صورة أبيه في ذهنه، ثم سأل:</p>\n<p>- الجثتان؟</p>\n<p>أشار رائف إلى ممر جانبي سُد نصفه بالحجارة.</p>\n<p>- هناك.</p>\n<p>حفر الرجال بأيديهم وأدوات صغيرة. بعد دقائق ظهر حذاء جلدي متآكل، ثم عظم ساق. أزاحوا حجرًا آخر، فانكشفت بقايا رجلين متجاورين. الأول يرتدي حزام شرطة صدئًا. الثاني حول معصمه ساعة معدنية توقفت عقاربها عند الثالثة وأربع دقائق.</p>\n<p>شهقت مها.</p>\n<p>عرفت الساعة.</p>\n<p>قالت:</p>\n<p>- أمي اشترتها له يوم عيد ميلاده.</p>\n<p>جلس عمران على الأرض، وأيمن مستند إليه. لم يقتربا. أما عمر فانحنى أمام الحزام، ومد يده إلى لوحة الاسم المعدنية. مسحها بإبهامه حتى ظهرت الحروف:</p>\n<p><strong>فؤاد خ.</strong></p>\n<p>قال رائف:</p>\n<p>- أبي لم يقتلهما.</p>\n<p>رفع عمر رأسه ببطء.</p>\n<p>- أكمل الجملة دي بس لو ناوي تموت بسرعة.</p>\n<p>- حازم الكبير قتلهما من دون أمر. هكذا قال أبي. بعد أن اكتشف فؤاد محاولة تهريب القطع، حاول القبض عليه. نعيم صوّر المواجهة. خرجا من الحجرة، ثم لم يصلا إلى الوادي.</p>\n<p>نظر حازم إلى العظام. لم يظهر على وجهه شيء.</p>\n<p>قال عمر:</p>\n<p>- وأنت خليت ابن الراجل يكمل شغله عندك.</p>\n<p>قال رائف:</p>\n<p>- الأبناء لا يرثون جرائم الآباء.</p>\n<p>ضحك يوسف ضحكة خالية من المرح.</p>\n<p>- غريبة جايّة منك.</p>\n<p>اقترب حازم من عمر ووضع فوهة المسدس عند كتفه المصاب.</p>\n<p>- أبويا كان بينفذ أوامر.</p>\n<p>قال عمر:</p>\n<p>- وأبوك مات، فاضطريت تورث المهنة مش الجريمة؟</p>\n<p>ضربه حازم في الجرح. سقط عمر على ركبته.</p>\n<p>قال رائف بحدة:</p>\n<p>- كفاية. لم نأتِ للمحاكمة.</p>\n<p>أخرج الكتاب الأسود من حقيبة جلدية. كان أقدم وأصغر مما تخيله يوسف، وغلافه مشقق كما وصفته الصور. فتحه عند صفحة وضعت فيها علامة.</p>\n<p>- أربع شهادات أوصلتنا إلى هذه الحجرة. الخامسة تفتح ما وراء الجدار. يا يوسف، ستقرأ أسماءكم، وتغني أمك، وتضع القطعة حيث تقول المسطرة.</p>\n<p>- ولو رفضت؟</p>\n<p>نظر رائف إلى أيمن.</p>\n<p>- سيموت رجل عاش أطول مما خططنا له. ثم نجرب بأمك. ثم بعمك. في النهاية ستكتشف أن البطولة طريقة بطيئة للموافقة.</p>\n<p>ساعد يوسف عمر على الوقوف.</p>\n<p>همس الضابط:</p>\n<p>- الوقت في صالحنا.</p>\n<p>- إزاي؟</p>\n<p>- قبل ما ندخل فعّلت نداء طوارئ في جهاز تتبع مستقل. لو ما لغيتوش خلال ساعتين، يبعت الموقع عند أول إشارة.</p>\n<p>- مفيش شبكة.</p>\n<p>- أول إشارة تكفي. المهم نطلع فوق قبل ما رائف يطلع.</p>\n<p>كان قد مر نصف ساعة.</p>\n<p>قال رائف:</p>\n<p>- ابدأ.</p>\n<p>اقترب يوسف من الجدار. بين الأسماء وجد أربع مساحات، كل مساحة تحمل كتابة من عصر مختلف. أما الخامسة فكانت خالية إلا من خط رأسي، كأنه ينتظر اسمًا.</p>"}, {"id": "chapter-17", "order": 17, "title": "الفصل السابع عشر: بقطر يغيّر اسم ابنه", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "لم يصل بقطر إلى الحجرة في يوم واحد. عبر النهر مع الصبي، ثم سار ليلتين في طرق جانبية حتى بلغ الدير المهجور. كان الجنود يفتشون المعابر عن مريم بنت حور، ثم عن قريب لها يحمل كتابًا أسود. لم يعرف إن كانوا وجدوا جثمانها أم لا.", "wordCount": 606, "minutes": 3, "era": "أواخر القرن الرابع", "theme": "coptic", "sound": "paper", "icon": "✥", "scene": "أخميم وصعيد مصر", "html": "<p>لم يصل بقطر إلى الحجرة في يوم واحد. عبر النهر مع الصبي، ثم سار ليلتين في طرق جانبية حتى بلغ الدير المهجور. كان الجنود يفتشون المعابر عن مريم بنت حور، ثم عن قريب لها يحمل كتابًا أسود. لم يعرف إن كانوا وجدوا جثمانها أم لا.</p>\n<p>في الليلة الثانية سأل الصبي:</p>\n<p>- هل ماتت أمي؟</p>\n<p>قال بقطر:</p>\n<p>- لا أعرف.</p>\n<p>- الكبار يقولون لا أعرف حين يعرفون.</p>\n<p>- والكبار أحيانًا يقولون ماتت لأن انتظار الخبر أصعب عليهم. اختر الكذبة التي تقدر أن تنام معها.</p>\n<p>نام الصبي وهو يمسك طرف ثوب بقطر.</p>\n<p>عند الدير وجدا المخزن محفورًا من قبل. رجال بيت ابن آوى سبقوهما بأيام، قلبوا الجرار وكسروا الأرض، لكنهم لم يجدوا الحجر الصحيح. كان مخفيًا تحت موضع معلف قديم، وعليه خمس فتحات لا تستقيم مع القرص إلا إذا وُضع مقلوبًا.</p>\n<p>قال الصبي:</p>\n<p>- لماذا مقلوبًا؟</p>\n<p>- لأن الذين يصنعون الأسرار يحبون أن يثبتوا أنهم أذكى من الذين يبحثون عنها.</p>\n<p>- هل هم أذكى؟</p>\n<p>- غالبًا ماتوا، ونحن ننفذ أوامرهم. احكم أنت.</p>\n<p>أدخل بقطر القرص في الفتحة الثانية، بعد أن لف حوله خيطًا يقيس عدد عقد ورد في النص. انزلق الحجر وظهر تجويف، لا ممر. في داخله جرّة صغيرة وبردية تحولت إلى رقائق. حملت البردية رسم الحجرة الأصلية وإشارة إلى مكان عظام حوري.</p>\n<p>أما الجرة فاحتوت على خمس قطع من خشب الجميز، كل واحدة محفور عليها اسم. الأول حوري، الثاني بلا اسم، والثلاثة الأخرى فارغة.</p>\n<p>فهم بقطر أن عليه أن يكتب اسمه على الثانية.</p>\n<p>رفض.</p>\n<p>جلس طوال الليل أمام القطعة. كان يعرف ما يعنيه أن يضيف اسمه. سيصبح الكتاب مسؤوليته، والصبي مسؤوليته، والمطاردة نصيب أولاده إن تزوج. كان يستطيع أن يحرق البردية والقرص وينهي الحكاية. ربما لا يوجد ذهب، وربما بيت ابن آوى يطارد وهمًا صنعه رجل خائف.</p>\n<p>قال الصبي:</p>\n<p>- أمي قالت إن الدور وصل إليك.</p>\n<p>- أمك أعطتني دورًا لم أطلبه.</p>\n<p>- هي أيضًا لم تطلب أن يقطعوا إصبع خالي.</p>\n<p>أخرج بقطر الأصبع الجافة من الكيس. كانت قبيحة، بلا كرامة، جزءًا من رجل اختُصر إلى دليل. تذكر العبارة: لا تعدّ الأصابع. عدّ الذين فقدوها.</p>\n<p>لم يكن المقصود طريقة فتح حجر. كان المقصود ألا يرى الأرقام وينسى أصحابها.</p>\n<p>كتب اسمه على القطعة الثانية.</p>\n<p>ثم فتح الكتاب الأسود، وفك تجليده كله. وضع بين صفحاته نص حوري بعد أن نسخه بحروف قبطية يفهمها من يأتي بعده. لم يترجم كل شيء. أخفى الزاوية الثانية في طول الأسطر: خمسة أسطر قصيرة، ثم ثلاثة طويلة، ثم واحد قصير. من يقرأ المعنى وحده لن يراها.</p>\n<p>قال الصبي:</p>\n<p>- ماذا سيكون اسمي؟</p>\n<p>- قالت أمك حوري.</p>\n<p>- هذا اسم قديم.</p>\n<p>- الأسماء القديمة أكثر أمانًا. الناس يظنونها حكاية.</p>\n<p>- وأنت أبي؟</p>\n<p>توقف بقطر.</p>\n<p>لم يكن متزوجًا، ولم يحمل طفلًا من قبل. كان يحب امرأة تبيع القماش في السوق، لكنه يؤجل الزواج لأنه لا يملك دكانًا كبيرًا. الآن يملك طفلًا ومطاردة وكتابًا يمكن أن يقتل من يلمسه.</p>\n<p>قال:</p>\n<p>- إذا أردت.</p>\n<p>- أريد حتى نجد أمي.</p>\n<p>- وبعدها؟</p>\n<p>فكر الصبي.</p>\n<p>- نرى.</p>\n<p>لم يجدا مريم.</p>\n<p>بعد سنوات عرفا أن الجنود قتلوها قرب النهر ودفنوها بلا اسم. ذهب بقطر إلى المكان، حمل حفنة تراب، وكتب اسمها في أول هامش فارغ من الكتاب الأسود. ثم كتب أسماء كل من عرف أنهم ماتوا بسبب المطاردة.</p>\n<p>كبر حوري وصار صانع قوارب. تزوج، وأنجب بنتًا سماها مريم. لم يحك لها عن الكتاب حتى بلغت الثلاثين، ثم أعطاها إياه وقال:</p>\n<p>- هذا ليس ميراثًا. الميراث شيء تملكه. هذا شيء يملك جزءًا منك.</p>\n<p>أما بقطر فمات شيخًا، على خلاف نبوءة الجدة. قبل موته طلب أن يُدفن بلا كتاب ولا قرص، وأن يُكتب على قبره «مجلد» لا «حارس».</p>\n<p>قال له حوري:</p>\n<p>- أنت حفظت السر.</p>\n<p>رد بقطر:</p>\n<p>- حفظت طفلًا. السر جاء في حقيبته.</p>\n<p>وصل الكتاب عبر البنات والأبناء، وتغيرت اللغة فوق صفحاته. وحين جاء زمن سالم الوراق، لم يكن أحد يعرف إن كان بقطر من دم حوري الأول أم صار من العائلة لأنه اختار طفلًا عند النهر.</p>\n<p>لهذا لم يكن الـDNA يعرف القصة كاملة.</p>\n<p>الدم حفظ خطًا واحدًا.</p>\n<p>أما العائلة فحفظت من اختار أن يبقى.</p>"}, {"id": "chapter-18", "order": 18, "title": "الفصل الثامن عشر: الجدار الذي يقرأ صاحبه", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "بدأ يوسف من كتابة حوري. لم يكن يقرأ الهيراطيقية، لكن سلمى ترجمت له من النسخة التي حفظتها قبل أن يأخذ رائف الحقيبة. أشار إلى الكف السوداء، ثم إلى موضع العظمة، ثم إلى أسماء العمال.", "wordCount": 494, "minutes": 3, "era": "الحاضر — تحت الأرض", "theme": "underground", "sound": "water", "icon": "⌁", "scene": "وادي الخرس", "html": "<p>بدأ يوسف من كتابة حوري. لم يكن يقرأ الهيراطيقية، لكن سلمى ترجمت له من النسخة التي حفظتها قبل أن يأخذ رائف الحقيبة. أشار إلى الكف السوداء، ثم إلى موضع العظمة، ثم إلى أسماء العمال.</p>\n<p>غنت مها الجملة الأولى من الأغنية.</p>\n<p>وضع رائف القرص في المسطرة، وحرّكه حسب الإيقاع. سقط ضوء المصباح عبر الثقب على الاسم الأول: حوري.</p>\n<p>انتقلوا إلى طبقة بقطر. كانت حروفها محفورة حول شكل كتاب. غنت مها الجملة الثانية، وتحرك الضوء إلى اسم «مريم بنت حور».</p>\n<p>قال يوسف:</p>\n<p>- دي أم الولد، مش بقطر.</p>\n<p>قالت سلمى:</p>\n<p>- لأنه أضاف اسمها قبل اسمه. النص بيقول كده.</p>\n<p>نظر رائف إليها.</p>\n<p>- لم أسمح لك بالكلام.</p>\n<p>- يبقى افتح الباب لوحدك.</p>\n<p>لم يرد. كان يحتاجها.</p>\n<p>في طبقة سالم، ظهرت خمس نخلات صغيرة. قلب يوسف القماش في يده كما فعل في الخان، وأدار المسطرة غربًا. استقر الضوء على اسم فريدة.</p>\n<p>قال عمران:</p>\n<p>- بنته.</p>\n<p>بدأ المعنى يتضح. الجدار لا يطلب أسماء الحراس، بل أسماء الأشخاص الذين اختاروهم على أنفسهم: مريت، مريم، فريدة... وفي الطبقة الرابعة، طبقة نعيم، كان الاسم المخفي ليس نعيمًا.</p>\n<p>بحث يوسف في الخدوش الحديثة. وجد حرفين عربيين: فاء وخاء.</p>\n<p>قال عمر:</p>\n<p>- فؤاد خطاب.</p>\n<p>أضاء الاسم. صدر صوت من داخل الجدار، كأن تروسًا حجرية قديمة تحركت.</p>\n<p>بقيت المساحة الخامسة.</p>\n<p>قال رائف:</p>\n<p>- اسمك.</p>\n<p>- غلط.</p>\n<p>- أنت الخامس.</p>\n<p>- كل واحد قبلنا كتب اسم حد اختاره. حوري اختار مراته وطفله. بقطر اختار مريم والولد. سالم اختار بنته. جدي اختار فؤاد؛ رجع يصوره ويحفظ دليله بدل ما يهرب.</p>\n<p>- هذه قراءة عاطفية.</p>\n<p>- الباب مبني على قراءة عاطفية.</p>\n<p>وجه حازم مسدسه إلى أيمن.</p>\n<p>- اكتب اسمًا بسرعة.</p>\n<p>نظر يوسف حوله. أمه، عمران، أيمن، سلمى، عمر. كل اسم قد يكون الاختيار، وكل اختيار يعني أن الآخرين أقل. لم يكن هذا اختبارًا نبيلًا؛ كان فخًا نفسيًا صنعه رجل ميت.</p>\n<p>قالت مها بهدوء:</p>\n<p>- الأغنية بتقول الخامس رجع باسمه.</p>\n<p>- يعني أنا.</p>\n<p>- أو رجّع الاسم لصاحبه.</p>\n<p>اقتربت من عظام نعيم وفؤاد. نزعت لوحة اسم فؤاد من الحزام، ثم أخذت ساعة أبيها من معصم الهيكل بحذر. وضعت الاثنين أسفل المساحة الفارغة.</p>\n<p>قالت:</p>\n<p>- اكتب: المفقودون.</p>\n<p>قال رائف:</p>\n<p>- لا يوجد هذا في أي نص.</p>\n<p>ردت:</p>\n<p>- عشان محدش قبلنا كان عنده العدد ده من الناس اللي ماتت من غير اسم.</p>\n<p>أمسك يوسف قطعة فحم من فتحة مصباح قديمة. كتب على المساحة:</p>\n<p><strong>المفقودون</strong></p>\n<p>غنت مها الجملة الخامسة.</p>\n<p>لم يتحرك الضوء.</p>\n<p>ضحك حازم بسخرية.</p>\n<p>لكن أيمن، المستند إلى أبيه، قال بصوت ضعيف:</p>\n<p>- مش اللحن ده.</p>\n<p>نظروا إليه.</p>\n<p>- كانوا بيشغلوه لي وأنا مربوط. تسجيل قديم لجدتي زهية. آخر نغمة كانت بتنزل، مش تطلع.</p>\n<p>قالت مها:</p>\n<p>- أمي كانت غيرتها بعد اختفاء أبويا.</p>\n<p>أعادت الغناء، وخفضت النغمة الأخيرة.</p>\n<p>تحرك الضوء إلى الكلمة.</p>\n<p>انشق الجدار من المنتصف.</p>\n<p>خرج هواء بارد محمل برائحة معدن وماء قديم. خلفه ممر ينقسم إلى طريقين. فوق الأيمن رسم صندوق، وفوق الأيسر رسم صف من الأشخاص بلا وجوه.</p>\n<p>قال رائف:</p>\n<p>- أخيرًا.</p>\n<p>اندفع نحو طريق الصندوق.</p>\n<p>لكن أرضه هبطت نصف إصبع تحت قدمه، وظهر خط من الرمل يسيل من السقف.</p>\n<p>قالت سلمى:</p>\n<p>- استنى! ده ميزان ضغط.</p>\n<p>توقف.</p>\n<p>على الأرض بين الطريقين حجر دائري له تجويفان للقرص: واحد شرقًا، وواحد غربًا.</p>\n<p>قال يوسف:</p>\n<p>- البيت غرب ظل الخيانة، لا شرقها.</p>\n<p>حدق رائف في طريق الصندوق. الذهب إلى الشرق.</p>\n<p>الأسماء إلى الغرب.</p>"}, {"id": "chapter-19", "order": 19, "title": "الفصل التاسع عشر: ابن أبيه", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "أمر رائف حازم أن يضع القرص في التجويف الشرقي.", "wordCount": 617, "minutes": 3, "era": "الحاضر — تحت الأرض", "theme": "underground", "sound": "water", "icon": "⌁", "scene": "وادي الخرس", "html": "<p>أمر رائف حازم أن يضع القرص في التجويف الشرقي.</p>\n<p>قال يوسف:</p>\n<p>- سالم كتب إن الشرق باب كاذب.</p>\n<p>- سالم كذب ثلاث مرات في النص نفسه.</p>\n<p>- عشان يضلل عيلتك.</p>\n<p>- أو ليحتفظ بالذهب لعائلتك.</p>\n<p>اقترب رائف من الحجر. خلف هدوئه كان شيء قد انكسر. أمضى عمره يطارد غرفة، وحين وجدها وقفت أمامه جملة رجل مات في سجن قبل ستة قرون.</p>\n<p>قال:</p>\n<p>- أبي دخل من الشرق سنة 1978. وجد الحجرة الأولى.</p>\n<p>- وما وصلش للآخر.</p>\n<p>- لأن نعيم سرق القرص.</p>\n<p>- لأن نعيم أنقذك من إن أبوك يدفن هنا.</p>\n<p>ضربه رائف بمؤخرة المسدس على فمه. تذوق يوسف الدم.</p>\n<p>قال رائف:</p>\n<p>- لا تجعل جدك قديسًا. أخذ الفيلم وترك فؤاد يموت.</p>\n<p>رفع عمر رأسه.</p>\n<p>- الصورة بتقول العكس.</p>\n<p>- الصورة لحظة. أبي قال إن نعيم اتفق مع فؤاد على أخذ الصندوق وابتزاز البعثة. لما اختلفوا، بدأ إطلاق النار.</p>\n<p>قال عمران:</p>\n<p>- أبوك قال لك اللي يخليك تقدر تبص له وهو بيموت.</p>\n<p>التفت رائف إليه.</p>\n<p>- وأبوك تركك طفلًا.</p>\n<p>- أبويا مدفون قدامنا. أبوك عاش ورجع لك وحكى لك كدبة. مين فينا اتساب أكتر؟</p>\n<p>لم يجب رائف. أخرج من جيبه دفترًا صغيرًا مهترئًا. قال:</p>\n<p>- هذا يوميات أبي. آخر صفحة كتبها قبل موته: «البيت لي. باحري كان جدي الأول، وحوري سرق سجل العائلة وأموالها. ما نسميه جريمة كان استردادًا.»</p>\n<p>ضحكت ليلى لو كانت معهم، لكن سلمى قامت بدورها:</p>\n<p>- بعد ثلاثة آلاف سنة لسه مصدقين إن موظف مخازن كان عنده بيت ملكي؟</p>\n<p>- توجد أختام ملكية في السجلات.</p>\n<p>- لأن الفلوس أجور عمال الملك، مش ملك باحري.</p>\n<p>قال رائف:</p>\n<p>- التاريخ يكتبه من يخرج بالدليل.</p>\n<p>- عشان كده قتلت مريم؟ سأل يوسف.</p>\n<p>سكت رائف.</p>\n<p>أجاب حازم بدلًا منه:</p>\n<p>- مريم ما كانتش لازم تفتح ملفات الإدارة.</p>\n<p>نظر رائف إليه بغضب.</p>\n<p>فهم يوسف. لم يعطِ رائف أمرًا مباشرًا، لكنه يعرف من فعل ولم يعاقبه. مثل أبيه. مثل كل رجل يترك الجريمة لمرؤوس ثم يرث فائدتها.</p>\n<p>قال عمر:</p>\n<p>- اعترف تاني بصوت أعلى. التسجيل ضعيف.</p>\n<p>نظر حازم إلى صدره. كان زر صغير في قميص عمر يومض. اندفع لينتزعه، لكن عمر ضرب معصمه، ودفع المسدس إلى أعلى. انطلقت رصاصة أصابت السقف.</p>\n<p>في اللحظة نفسها ركلت سلمى المصباح الرئيسي. دارت الظلال في الحجرة. جذب يوسف القرص من يد حازم، وقفز نحو التجويف الغربي.</p>\n<p>أطلق رائف النار.</p>\n<p>شعر يوسف بحرارة تمر قرب أذنه. وضع القرص في الحجر وأداره.</p>\n<p>هبط الطريق الغربي قليلًا، وانفتح بابه.</p>\n<p>أما الطريق الشرقي فانغلق نصفه فجأة. كان أحد رجال رائف قد دخل فيه، فقطع الحجر جسده عنهم. صرخ من الداخل.</p>\n<p>قال رائف:</p>\n<p>- ماذا فعلت؟</p>\n<p>- اخترت البيت.</p>\n<p>اندفع رائف نحوه. تصارع الاثنان فوق الحجر الدائري. لم يكن يوسف أقوى، لكنه كان غاضبًا بلا حساب. ضربه رائف في الضلوع، وأمسك بيده التي تحمل القرص. جاء حازم من الجانب، إلا أن عمران اصطدم به بكتفه السليمة.</p>\n<p>سقطا قرب الحافة.</p>\n<p>أمسك أيمن مسدسًا وقع على الأرض. كانت يده ترتجف. وجهه إلى حازم.</p>\n<p>قال حازم:</p>\n<p>- أنت ما تعرفش تستخدمه.</p>\n<p>قال أيمن:</p>\n<p>- علّمتوني.</p>\n<p>أطلق رصاصة أصابت ساق حازم. سقط الرجل وصاح.</p>\n<p>تراجع رائف إلى الطريق الشرقي. رأى من خلال الفتحة صناديق تلمع أطرافها. الذهب موجود فعلًا. مد يده إلى الحجر ليعيد القرص شرقًا.</p>\n<p>أمسك يوسف بالقرص بكل قوته.</p>\n<p>قال رائف:</p>\n<p>- تستطيع أن تخرج بأسماء موتى، أو بثروة تغيّر حياة عائلتك.</p>\n<p>قال يوسف:</p>\n<p>- كل واحد قبلي دفع عشان حد يعيش. إنت الوحيد اللي عايز كل الناس تموت عشان حاجة تملكها.</p>\n<p>ضغط رائف فوهة المسدس إلى بطنه.</p>\n<p>- اتركه.</p>\n<p>جاء صوت مها خلفه:</p>\n<p>- يا يوسف، سيبه.</p>\n<p>نظر إليها. لم تكن تستسلم. كانت تنظر إلى الرمل الذي بدأ يسيل من سقف الطريق الشرقي. وزن رائف ورجاله فعّل آلية الانهيار.</p>\n<p>ترك يوسف القرص.</p>\n<p>انتزعه رائف، ووضعه في الشرق.</p>\n<p>انفتح الطريق الشرقي كاملًا.</p>\n<p>ابتسم ودخل.</p>\n<p>بعد ثلاث خطوات انهارت الأرض تحته.</p>\n<p>تعلق بالحافة بيد واحدة، وسقط المسدس في الظلام. ركض حازم المصاب نحوه، لكنه توقف حين رأى الصناديق تنزلق إلى الحفرة.</p>\n<p>صاح رائف:</p>\n<p>- اسحبني!</p>\n<p>نظر حازم إلى سيده، ثم إلى صندوق صغير علق قرب قدمه. اختار الصندوق.</p>\n<p>ترك رائف يسقط.</p>\n<p>لم يصل صوته إلى قاع.</p>\n<p>وادي الخرس لا يعيد الصدى، حتى تحت الأرض.</p>"}, {"id": "chapter-20", "order": 20, "title": "الفصل العشرون: الصورة الخامسة", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "أغلق الطريق الشرقي بعد سقوط رائف. بقي حازم معهم، ينزف من ساقه ويحمل صندوقًا صغيرًا كأنه طفل. وجه عمر إليه المسدس الذي التقطه.", "wordCount": 617, "minutes": 3, "era": "الحاضر — تحت الأرض", "theme": "underground", "sound": "water", "icon": "⌁", "scene": "وادي الخرس", "html": "<p>أغلق الطريق الشرقي بعد سقوط رائف. بقي حازم معهم، ينزف من ساقه ويحمل صندوقًا صغيرًا كأنه طفل. وجه عمر إليه المسدس الذي التقطه.</p>\n<p>- حطه.</p>\n<p>قال حازم:</p>\n<p>- ده حقي.</p>\n<p>- لأن أبوك قتل عشان يوصل له؟</p>\n<p>- لأن أبويا مات خدام عند السيوفي، وأنا مش هموت زيّه.</p>\n<p>فتح الصندوق. في داخله لم يكن ذهب، بل ألواح شمعية سوداء ولفافة قماش. رمى حازم الصندوق بغضب. سقط أحد الألواح وانكسر، فظهرت داخله رقائق ذهبية رفيعة منقوشة بأسماء.</p>\n<p>قالت سلمى:</p>\n<p>- دي بطاقات أجور. الذهب كان موزعًا داخل السجلات عشان ما يتسرقش ككتلة.</p>\n<p>نظر حازم إلى عشرات الصناديق التي ابتلعها الطريق الشرقي. لم يعد يستطيع الوصول إليها.</p>\n<p>رفع سلاحًا آخر من حزامه، لكنه لم يكمل. ضربه عمر في صدغه فسقط فاقدًا الوعي.</p>\n<p>قال عمر:</p>\n<p>- كنت مستني اللحظة دي من وأنا عندي تسع سنين.</p>\n<p>فتحوا الطريق الغربي. لم تكن حجرة واحدة، بل ممرًا طويلًا عليه رسوم لأشخاص يحملون سلالًا وأحجارًا وماءً. لا ملوك، لا آلهة، لا معارك. في النهاية قاعة مستطيلة محفوظة بجفاف عجيب. على رفوفها مئات الجرار، وفي الوسط صندوق حجري منخفض.</p>\n<p>قالت سلمى:</p>\n<p>- ما حدش يلمس حاجة. حتى النفس هنا محتاج إذن.</p>\n<p>لكن يوسف اقترب من الجدار المقابل. كان فارغًا إلا من خمسة تجاويف مستطيلة، بحجم الصور التي التقطها نعيم.</p>\n<p>أخرج الصور من جيبه. لم يأخذها رائف؛ ظن أن الفيلم وحده مهم. وضع أربع صور في التجاويف المناسبة. بقي الخامس فارغًا.</p>\n<p>قالت مها:</p>\n<p>- أبويا كتب الصورة الخامسة مش في الفيلم.</p>\n<p>وجد يوسف في وسط الجدار عدسة حجرية مصقولة، أو قطعة بلور عكرة. خلفها موضع للقرص. وضعه. مر ضوء مصابيحهم عبر الشقوق الخمسة وأسقط ظلال الصور فوق الجدار. تراكبت اللقطات الأربع: الكف، الأسماء، الهيكل، نادر وفؤاد.</p>\n<p>بقي شكل ناقص في المنتصف.</p>\n<p>قالت سلمى:</p>\n<p>- محتاج جسم يقف قدام الضوء.</p>\n<p>وقف يوسف حيث يشير الخط. ظهر ظله بين الصور، لكنه لم يكتمل. وقفت مها إلى جواره، ثم عمران وأيمن وعمر. خمسة ظلال متجاورة.</p>\n<p>اندمجت على الجدار لتكوّن صورة واحدة: رجال ونساء يحملون لوحًا طويلًا فوق رؤوسهم، وعلى اللوح كلمة هيروغليفية ترجمتها سلمى:</p>\n<p><strong>الشهود.</strong></p>\n<p>هذه هي الصورة الخامسة؛ لا يلتقطها فرد، ولا توجد من دون الأحياء.</p>\n<p>انفتح الصندوق الحجري.</p>\n<p>في داخله لم يكن كنزًا، بل سجل كبير من ألواح خشبية مربوطة، محفوظ بينها أوراق بردي. وعلى الغطاء الداخلي رسالة كتبها نعيم بالقلم الرصاص سنة 1978:</p>\n<p><strong>وصلنا إلى هنا أنا وفؤاد. قرأنا ما استطعنا. نادر يريد الصناديق، وفؤاد يريد البلاغ، وأنا أريد أن أخرج بالصور. لو لم نخرج، لا تجعلوا المكان قبرًا ثانيًا. الأسماء إذا بقيت هنا ماتت، حتى لو ظل الورق سليمًا. أخرجوها للناس.</strong></p>\n<p>أسفل الرسالة بصمة كف نعيم، وإلى جوارها بصمة فؤاد.</p>\n<p>جلس عمر على الأرض.</p>\n<p>مرر إصبعه فوق بصمة أبيه من غير أن يلمسها.</p>\n<p>قال:</p>\n<p>- كان هنا. وصل هنا فعلًا.</p>\n<p>وجدوا داخل السجل قوائم أجور، شكاوى عمال، رسائل زوجات يطلبن حصص الحبوب، أسماء أطفال ماتوا في وباء، وتقارير عن سرقة باحري. كل ورقة تقول إن أصحاب المقابر العظيمة لم يكونوا وحدهم في التاريخ.</p>\n<p>وفي آخر الصندوق ظرف حديث مغلق، كتب عليه نعيم:</p>\n<p><strong>إلى زهية.</strong></p>\n<p>ناولته مها بيدين مرتجفتين. فتحته. كانت الرسالة قصيرة:</p>\n<p>«يا زهية، لو رجعتِ تقرئي دي من غيري، ما تستنيش. أنا دخلت بإرادتي، لكن لو ما خرجتش فمش بإرادتي. قولي للعيال إني خفت، بس عملت الحاجة وأنا خايف. ما تقوليش بطل. البطل كلمة بتتقال لما الناس مش عارفة الحقيقة كاملة. سامحيني لو قدرتِ، ولو ما قدرتيش عيشي برضه.»</p>\n<p>قرأتها مها بصوت منخفض. عند آخر كلمة جلست قرب أخيها.</p>\n<p>قال عمران:</p>\n<p>- أمي ماتت وهي مستنياه.</p>\n<p>قالت مها:</p>\n<p>- يمكن كانت مستنية الجملة دي، مش هو.</p>\n<p>اهتزت الأرض.</p>\n<p>سقط غبار من السقف.</p>\n<p>قالت سلمى:</p>\n<p>- آلية الشرق أثرت على المكان كله. لازم نخرج.</p>\n<p>أغلق يوسف الصندوق، لكنه لم يستطع حمله. السجل وحده ثقيل، والجرار بالمئات.</p>\n<p>قال عمر:</p>\n<p>- نصور ونطلع. فريق الآثار يرجع بمعدات.</p>\n<p>بدأت سلمى تصوير كل شيء بسرعة منهجية. أما يوسف فوجد في زاوية القاعة فتحة صغيرة يدخل منها هواء. اقترب، فسمع صوت ماء يعلو.</p>\n<p>المجرى الجوفي تغير بعد انهيار الطريق الشرقي.</p>\n<p>بدأ الماء يدخل الحجرة.</p>"}, {"id": "chapter-21", "order": 21, "title": "الفصل الحادي والعشرون: الماء لا يحفظ الأسرار", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "دخل الماء من الفتحة أولًا كخيط، ثم صار جدولًا يضرب أرض الحجرة ويجر معه غبار ثلاثة آلاف عام. ارتفع إلى كعوبهم خلال دقائق.", "wordCount": 772, "minutes": 4, "era": "الحاضر — تحت الأرض", "theme": "underground", "sound": "water", "icon": "⌁", "scene": "وادي الخرس", "html": "<p>دخل الماء من الفتحة أولًا كخيط، ثم صار جدولًا يضرب أرض الحجرة ويجر معه غبار ثلاثة آلاف عام. ارتفع إلى كعوبهم خلال دقائق.</p>\n<p>قالت سلمى:</p>\n<p>- الممر اللي دخلنا منه أوطى من هنا. لو رجعنا هنقابل المية وهي طالعة.</p>\n<p>قال أيمن:</p>\n<p>- فيه فتحة فوق الرفوف. كانوا بينزلوني منها بحبل.</p>\n<p>أشار إلى أعلى الجدار الشرقي. لم تكن فتحة واضحة، بل شقًا خلف صف من الجرار. صعد يوسف فوق صندوق حجري، وأزاح جرة فارغة. وجد نفقًا ضيقًا يميل إلى أعلى.</p>\n<p>قال عمر:</p>\n<p>- نطلع واحد واحد. سلمى الأول ومعاها الصور والرسالة. مها بعدها. أيمن، عمران، يوسف. أنا آخر واحد.</p>\n<p>نظر إلى حازم الملقى على الأرض.</p>\n<p>قال عمران:</p>\n<p>- وده نسيبه.</p>\n<p>فتح حازم عينيه عند سماع الجملة. كان واعيًا، يتظاهر بالإغماء.</p>\n<p>قال يوسف:</p>\n<p>- هناخده.</p>\n<p>- ده قتل مريم، قالت سلمى.</p>\n<p>- عشان يتحاكم. مش عشان يبقى عضم جديد الناس تختلف عليه.</p>\n<p>ضحك حازم بصوت ضعيف.</p>\n<p>- فاكر نفسك مختلف؟ أول ما المية توصل لرقبتك هتسيبني.</p>\n<p>ربط عمر يديه بحزام، ثم لف حبلًا حول صدره. صعدت سلمى أولًا وهي تحمل حقيبة صغيرة فيها الصور، رسالة نعيم، ولوحًا واحدًا من سجل الأسماء. رفضت أخذ الذهب. قالت إن اللوح يكفي لإثبات الحجرة، وإن تصوير الباقي محفوظ في ثلاث بطاقات ذاكرة وزعتها بينهم.</p>\n<p>صعدت مها. عند فتحة النفق التفتت إلى عظام أبيها.</p>\n<p>- هنرجع لك، قالت.</p>\n<p>لم تقل «هنطلعك». كأن الرجل قد يفضل البقاء حتى يأتي من يعرف كيف يحمله من غير أن يحوله إلى خبر.</p>\n<p>ارتفع الماء إلى الركبتين.</p>\n<p>دفعوا أيمن داخل الشق. كان يعرف المنعطفات رغم ضعفه. بعده عمران، ثم حازم مربوطًا، ويوسف يسحبه من الخلف. بقي عمر في القاعة حتى تأكد أن الجميع دخل.</p>\n<p>قبل أن يصعد، سمع صوتًا من الطريق الشرقي.</p>\n<p>سعالًا.</p>\n<p>خرج رائف من فتحة منخفضة، مغطى بالطين والدم. كانت ذراعه اليمنى معلقة، ووجهه فقد هدوءه تمامًا. في يده دفتر أبيه، وقد ضغطه إلى صدره ليحميه من الماء.</p>\n<p>قال:</p>\n<p>- السجل.</p>\n<p>رفع عمر المسدس.</p>\n<p>- ارمِ اللي في إيدك.</p>\n<p>ابتسم رائف. كان بينه وبين عمر الماء المتصاعد، وخلفه الطريق الشرقي ينهار.</p>\n<p>- ستطلق النار على آخر شخص يعرف أين دُفن أبوك؟</p>\n<p>- لقيته.</p>\n<p>- وجدت عظامًا. لا تعرف من أعطى الأمر، ولا لماذا.</p>\n<p>- هازم هيقول.</p>\n<p>نظر رائف إلى النفق، وعرف أنهم أخذوه.</p>\n<p>اندفع نحو الصندوق الحجري. كان يريد السجل الكبير. أمسك غطاءه وحاول سحبه، لكن الماء ثقّل الأوراق والخشب.</p>\n<p>قال عمر:</p>\n<p>- سيبه واطلع.</p>\n<p>- هذه عائلتي.</p>\n<p>- دي أسماء ناس سرقتهم عيلتك.</p>\n<p>أطلق رائف رصاصة. أصابت الحجر قرب رأس عمر. رد عمر، فأصاب ساقه. سقط رائف في الماء، لكنه ظل ممسكًا بالسجل.</p>\n<p>صرخ يوسف من داخل النفق:</p>\n<p>- عمر!</p>\n<p>- اطلعوا!</p>\n<p>بدأ السقف يتشقق. دخل عمر الشق، لكنه رأى رائف يحاول الوقوف، والسجل يسحبه. مد يده إليه.</p>\n<p>- سيب الورق وخد إيدي.</p>\n<p>نظر رائف إلى اليد، ثم إلى السجل.</p>\n<p>للحظة بدا أصغر. لا رئيس شركة، ولا وريثًا لاسم، فقط ابنًا أمضى عمره يثبت أن أباه لم يبدد حياته من أجل كذبة.</p>\n<p>قال:</p>\n<p>- لو خرجت من غيره، أبقى لا شيء.</p>\n<p>رد عمر:</p>\n<p>- كلنا خرجنا من غيره واتولدنا عادي.</p>\n<p>مد رائف يده.</p>\n<p>أمسك عمر معصمه وسحبه. ترك رائف السجل، وارتفع نصف جسده. ثم مر لوح خشبي من السجل مع الماء واصطدم بقدمه. رأى فوقه رقائق الذهب.</p>\n<p>ترك يد عمر وانحنى ليمسكه.</p>\n<p>انهار جزء من السقف.</p>\n<p>اختفى رائف تحت الحجارة والماء.</p>\n<p>هذه المرة لم يعد.</p>\n<p>زحف عمر داخل النفق. خلفه اندفع الماء وأغلق الشق بالردم.</p>\n<p>كان النفق ضيقًا حتى إن يوسف اضطر إلى الزحف على جانبه. حازم أمامه يعرقلهم، وساقه تنزف. قال:</p>\n<p>- فكّني، أعرف أطلع لوحدي.</p>\n<p>- أنت تعرف تهرب لوحدك.</p>\n<p>- كلنا هنموت بسببك.</p>\n<p>وصلوا إلى بئر رأسية. في أعلاها نقطة ضوء صغيرة. وجدوا حبلًا حديثًا مربوطًا بمسمار معدني؛ الطريق الذي كان رجال رائف يدخلون منه. صعد أيمن أولًا ليختبره، ثم ساعد أمه وعمته - كما سماها لأول مرة حين قال لمها: «اطلعي يا عمتي».</p>\n<p>حين جاء دور حازم، رفض عمران ربطه.</p>\n<p>قال:</p>\n<p>- ابني كان مربوط بالحبل ده سنين.</p>\n<p>قال يوسف:</p>\n<p>- عشان كده هنطلعه مربوط.</p>\n<p>رفعوه. بقي يوسف وعمران وعمر في الأسفل. كان الماء قد وصل إلى البئر، يصعد حول أرجلهم.</p>\n<p>قال عمران:</p>\n<p>- اطلع يا يوسف.</p>\n<p>- أنت الأول.</p>\n<p>- ذراعي مش هتستحمل.</p>\n<p>ربطه يوسف من الخصر. بدأ عمر يسحبه من فوق بمساعدة أيمن. في منتصف الطريق انقطع جزء من الحبل، وهبط عمران مترًا واصطدم بالجدار. صرخ، ثم تدلى بلا حركة.</p>\n<p>قال أيمن من أعلى:</p>\n<p>- يا حاج! بص لي!</p>\n<p>فتح عمران عينيه.</p>\n<p>- أنا بصيت لك سبع سنين في فيديو كدب. شد يا ابني.</p>\n<p>سحبه أيمن حتى خرج.</p>\n<p>صعد يوسف بعده. كان آخر من خرج عمر. وما إن وضع قدمه على سطح الوادي حتى انهارت فتحة البئر وغمرها الطين.</p>\n<p>جلسوا تحت السماء. القمر ما زال في مكانه، كأن الساعات تحت الأرض لم تخص العالم.</p>\n<p>في يد سلمى لوح واحد يحمل أربعة عشر اسمًا لعمال لم يُذكروا في أي مقبرة. في يد مها رسالة أبيها. وفي جيب يوسف القطعة النحاسية.</p>\n<p>أما حازم فكان حيًا، مقيدًا، يحدق إلى الوادي كأنه خسر شيئًا أكثر من حريته.</p>\n<p>بعد دقائق ظهر وميض بعيد فوق حافة الجبل.</p>\n<p>ثم صوت مروحية.</p>\n<p>وصل نداء عمر إلى الشبكة.</p>"}, {"id": "chapter-22", "order": 22, "title": "الفصل الثاني والعشرون: آخر ليلة لنعيم", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "البر الغربي - يناير 1978", "wordCount": 542, "minutes": 3, "era": "يناير 1978", "theme": "seventies", "sound": "camera", "icon": "◫", "scene": "البر الغربي — الأقصر", "html": "<p>البر الغربي - يناير 1978</p>\n<p>عندما خرج نعيم وفؤاد من الحجرة الغربية، كانا يعرفان أن نادر ينتظرهما.</p>\n<p>قال فؤاد وهو يضع لوح الأسماء داخل الصندوق:</p>\n<p>- الصور معاك؟</p>\n<p>- معايا.</p>\n<p>- لو حصل حاجة، تروح بيها القسم في إسنا. ما تروحش الأقصر. نادر له ناس هناك.</p>\n<p>- وإنت؟</p>\n<p>- هطلع معاه كأني ما شفتش حاجة. أول ما نوصل فوق أقبض عليه.</p>\n<p>ضحك نعيم.</p>\n<p>- لو كان سهل يتقبض عليه، ما كانش دخلنا الجبل بمسدسات.</p>\n<p>خرج الاثنان إلى الحجرة الأولى. كان نادر واقفًا قرب الهيكل القديم، وحازم الكبير خلفه. في يد نادر الكتاب الأسود، وفي يد حازم بندقية قصيرة.</p>\n<p>قال نادر:</p>\n<p>- وجدتما المخزن؟</p>\n<p>قال فؤاد:</p>\n<p>- وجدنا أدلة تهريب، ومحاولة سرقة عينات، وسلاحًا غير مرخص. سلّم مسدسك يا دكتور.</p>\n<p>بدا نادر مصدومًا فعلًا.</p>\n<p>- أنت لا تفهم قيمة المكان.</p>\n<p>- فاهم قيمة الناس اللي قتلها باحري، والناس اللي هتقتلها إنت عشان تبيع اللي فاضل.</p>\n<p>- لن أبيع شيئًا. القطع ستدخل مجموعة المؤسسة، ثم تُعرض.</p>\n<p>قال نعيم:</p>\n<p>- بعد ما يتكتب إنك لقيتها لوحدك.</p>\n<p>نظر نادر إليه.</p>\n<p>- أنت حارس. أعطيتك فرصة تدخل التاريخ.</p>\n<p>- أنا دخلت ولقيت التاريخ زحمة. مش محتاج اسمي يتكتب فوق الناس دي.</p>\n<p>أخرج فؤاد الأصفاد.</p>\n<p>رفع حازم البندقية.</p>\n<p>قال نادر:</p>\n<p>- أنزل السلاح.</p>\n<p>لم ينزله.</p>\n<p>كرر نادر الأمر. هذه المرة تحرك فؤاد نحوه، فانطلقت الرصاصة. أصابته في بطنه.</p>\n<p>وقف الجميع لحظة لا يصدقون الصوت.</p>\n<p>قال نادر:</p>\n<p>- يا ابن المجنونة، أنا قلت أنزل السلاح!</p>\n<p>ركض نعيم إلى فؤاد. كان الدم يملأ قميصه. رفع الكاميرا والتقط صورة لنادر وحازم قبل أن يفكر. الغالق جعل حازم يلتفت إليه.</p>\n<p>قال نادر:</p>\n<p>- خذ الفيلم فقط. لا تقتله.</p>\n<p>طارده حازم إلى الممر. عرف نعيم طريق الهرب الجانبي، ودخل الحجرة الصغيرة حيث خبأ الكاميرا مؤقتًا. سمع نادر وفؤاد يتجادلان خلفه.</p>\n<p>قال فؤاد بصوت ضعيف:</p>\n<p>- لو خرجتني، أقول إنها حادثة.</p>\n<p>قال نادر:</p>\n<p>- سنخرجك.</p>\n<p>لكن حازم عاد بعد أن فقد نعيم في الممر.</p>\n<p>- الفيلم معاه.</p>\n<p>قال نادر:</p>\n<p>- طلع رجالتنا على كل المداخل.</p>\n<p>- والضابط؟</p>\n<p>- احمله.</p>\n<p>انحنى حازم، ثم أطلق رصاصة ثانية في صدر فؤاد.</p>\n<p>صرخ نادر:</p>\n<p>- إنت اتجننت؟</p>\n<p>- كان هيتكلم.</p>\n<p>- قلت أحمله!</p>\n<p>- وأنت كنت هتسيبه يخرج عشان يقول إنك بريء؟</p>\n<p>نظر نادر إلى الجثة. في تلك اللحظة كان يستطيع أن يطلق النار على حازم، أو يخرج ويبلغ. بدلًا من ذلك قال:</p>\n<p>- لازم نلاقي نعيم قبل الفجر.</p>\n<p>هذا هو القرار الذي ورثه رائف، لا الرصاصة.</p>\n<p>هرب نعيم إلى بيته، أخفى الفيلم، وكتب الورقة. حين ركب السيارة السوداء في الصباح كان يظن أن نادر سيأخذه إلى فؤاد أو يساومه. لم يعرف أن فؤاد مات.</p>\n<p>قادوه إلى الوادي مرة أخرى. في الطريق عرض عليه نادر المال والخروج من مصر. رفض.</p>\n<p>قال نادر:</p>\n<p>- أنت لا تعرف من تتحدى.</p>\n<p>قال نعيم:</p>\n<p>- أعرف. واحد كان يقدر يوقف قاتل، فقرر يدور على فيلم.</p>\n<p>عند مدخل الجبل فتشوه فلم يجدوا الصور. ضربه حازم حتى كسر ضلعين. ظل نادر واقفًا، يكرر: «قل لنا فقط أين الفيلم.»</p>\n<p>لم يقل.</p>\n<p>قبل الغروب أخذه حازم إلى الممر الجانبي. أطلق النار عليه قرب جثة فؤاد، ثم دفع الحجارة فوقهما.</p>\n<p>قال نادر إنه لم يأمر.</p>\n<p>وظل يقول ذلك أربعين عامًا.</p>\n<p>في دفتره كتب أن نعيم سرق، وأن فؤاد خانه، وأن حازم أساء الفهم، وأن الحجرة حق عائلته. كل جملة تخفف عنه جزءًا حتى أصبح في روايته الرجل الوحيد الذي لم يفعل شيئًا.</p>\n<p>أما نعيم، ففي اللحظة الأخيرة، لم يفكر في الأسماء ولا الذهب ولا التاريخ.</p>\n<p>فكر في السندوتش الذي وعد عمران أن يشتريه له من المحطة.</p>\n<p>وفي أن مها بدأت تنطق كلمة «أبويا» ناقصة.</p>\n<p>وفي زهية التي ستغضب لأنه تأخر.</p>\n<p>مات خائفًا، كما كتب.</p>\n<p>وفعل الشيء وهو خائف.</p>"}, {"id": "chapter-23", "order": 23, "title": "الفصل الثالث والعشرون: ما تقوله العظام", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "استغرقت عملية الإنقاذ الأولى حتى شروق الشمس. نُقل عمران وأيمن وعمر إلى المستشفى تحت حراسة، وأُدخل حازم غرفة عمليات ثم وُضع قيد الحبس. بقي يوسف وسلمى ومها في موقع مؤقت أقامته النيابة على حافة الوادي.", "wordCount": 554, "minutes": 3, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>استغرقت عملية الإنقاذ الأولى حتى شروق الشمس. نُقل عمران وأيمن وعمر إلى المستشفى تحت حراسة، وأُدخل حازم غرفة عمليات ثم وُضع قيد الحبس. بقي يوسف وسلمى ومها في موقع مؤقت أقامته النيابة على حافة الوادي.</p>\n<p>حين ظهرت أول شبكة، امتلأت الهواتف برسائل لم تُقرأ واتصالات فائتة. كانت قصة وفاة مريم قد تغيرت في الأخبار: النيابة تعيد التحقيق، وشبهة جنائية بعد ظهور أدلة جديدة. وبعد ساعات، داهمت قوة مشتركة مقر جذور ومخازن مؤسسة السيوفي.</p>\n<p>وجدوا ملفات مشروع سلسلة خمسة، وعينات آلاف العملاء محفوظة خارج الموافقات، وتقارير عن الحالات الأربع. وجدوا أيضًا تسجيلات أيمن الأصلية، وغرفة احتجاز في مزرعة تابعة لشركة أمن، ورسائل من حازم إلى رجاله ليلة موت مريم.</p>\n<p>لم يجدوا جثمان رائف.</p>\n<p>أغلق انهيار البئر الطريق، وأصبح الوصول إلى الحجرة يحتاج تدعيمًا هندسيًا. استمر البحث أسبوعين. انتشرت نظريات أنه هرب من مخرج آخر، وأنه في الخارج، وأن الرجل المدفون ليس هو. كانت مها تغلق التلفزيون كلما بدأ مذيع يرسم خريطة لا يعرفها.</p>\n<p>في اليوم السابع عشر، دخل فريق إنقاذ من المدخل القديم بعد تثبيته. وجدوا جسد رائف في فجوة أسفل الطريق الشرقي، يده حول لوح ذهبي صغير. لم يحمل السجل، ولم يحمل دفتر أبيه؛ جرفهما الماء.</p>\n<p>وجدوا أيضًا عظام نعيم وفؤاد، وحزام الشرطة، والساعة، ورصاصتين تطابق سلاح حازم الكبير المحفوظ في مخزن قديم للمؤسسة بوصفه «قطعة تذكارية».</p>\n<p>قال تقرير الطب الشرعي ما عجزت العائلة عن قوله خمسين عامًا: نعيم عبد الوارث لم يهرب. قُتل.</p>\n<p>أما حوري، فأثبت التأريخ أنه أقدم عظام الحجرة، وأن فقد إصبعه وكسره القديم يوافقان النص. لم يثبت العلم أنه جد يوسف المباشر. خرج خبراء على الشاشات يشرحون أن مشاركة سلالة أبوية لا تعني نسبًا فرديًا مؤكدًا عبر آلاف السنين. غضب بعض الناس لأن الحقيقة أقل إثارة من الإعلان.</p>\n<p>قال يوسف في أول تحقيق صحفي وافق عليه:</p>\n<p>- كويس. الحكاية أصلًا مش محتاجة تطلعني حفيد شخص مشهور. حوري كان كاتب أجور، وبقطر مجلد كتب، وسالم أبًا غلط، وجدي حارس موقع. لو محتاج أحولهم لملوك عشان أحترمهم، يبقى أنا ما فهمتش اللي لقيناه.</p>\n<p>انتشر المقطع أكثر من إعلان جذور.</p>\n<p>أفاق أيمن بعد عمليتين. كان يعاني من آثار إصابات قديمة وسوء تغذية ونوبات هلع. في أول ليلة بالمستشفى طلب إطفاء الضوء، ثم صرخ حين أُطفئ. جلس عمران بجواره حتى الصباح، يترك المصباح نصف مضاء.</p>\n<p>قال له أيمن:</p>\n<p>- أنت صدقت الفيديوهات؟</p>\n<p>- صدقتها.</p>\n<p>- حتى لما شكلي ما كانش بيتغير؟</p>\n<p>- كنت بتغيره في دماغي.</p>\n<p>- ليه؟</p>\n<p>- عشان لو بطلت أصدق، كان لازم أعمل حاجة. وأنا كنت جبان.</p>\n<p>قال أيمن بعد صمت:</p>\n<p>- وأنا قلت لهم الأغنية.</p>\n<p>- كنت مربوط.</p>\n<p>- برضه قلت.</p>\n<p>- يبقى إحنا الاتنين نعيش شوية من غير ما نسمي نفسنا.</p>\n<p>كانت هذه أقرب صيغة للمسامحة استطاعا الوصول إليها.</p>\n<p>اعترف حازم بقتل مريم بعد أن واجهوه بالتسجيل والرسائل. قال إن رائف لم يأمر بقتلها، بل قال: «أوقف التسريب بأي طريقة.» حاول أن يجعل العبارة مساحة يختبئ فيها. لم تسمح له النيابة.</p>\n<p>أما مشروع جذور فأُغلق، وبدأت قضية منفصلة تخص انتهاك بيانات العملاء. اكتشف آلاف الأشخاص أن لعابهم لم يكن مجرد رقم بريء. بعضهم رفع دعاوى، وبعضهم طلب حذف عينته، وبعضهم ظل يريد معرفة نسبته إلى المصريين القدماء.</p>\n<p>البشر لا يتعلمون بالطريقة نفسها، حتى من الكارثة نفسها.</p>\n<p>بعد أربعة أشهر أقيمت جنازة مشتركة لنعيم وفؤاد في الأقصر. أصر عمر أن يُدفنا قريبين، لا في قبر واحد. قال:</p>\n<p>- عاشوا آخر يوم مع بعض، كفاية عليهم.</p>\n<p>وقفت مها أمام قبر أبيها تحمل الساعة بعد تنظيفها. أصلح الساعاتي السوار، لكنه رفض تشغيلها.</p>\n<p>قال إن التروس صدئت عند الثالثة وأربع دقائق، وأي محاولة ستستبدل نصفها.</p>\n<p>قالت مها:</p>\n<p>- سيبها. الوقت اللي وقف عنده أخيرًا عرفنا معناه.</p>"}, {"id": "chapter-24", "order": 24, "title": "الفصل الرابع والعشرون: محضر بأسماء الأحياء", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "بعد عام، افتُتح معرض «الشهود» في متحف الأقصر. لم تُعرض القطع الذهبية في القاعة الأولى. بدأت الجولة بلوح خشبي رخيص يحمل أربعة عشر اسمًا، وبجواره تسجيل يقرأها ببطء.", "wordCount": 522, "minutes": 3, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>بعد عام، افتُتح معرض «الشهود» في متحف الأقصر. لم تُعرض القطع الذهبية في القاعة الأولى. بدأت الجولة بلوح خشبي رخيص يحمل أربعة عشر اسمًا، وبجواره تسجيل يقرأها ببطء.</p>\n<p>كان اقتراح سلمى.</p>\n<p>قال مدير المتحف إن الزوار يريدون شيئًا مبهرًا عند الدخول. ردت:</p>\n<p>- الاسم اللي عاش ثلاثة آلاف سنة عشان حد يقراه مبهر كفاية.</p>\n<p>عملت سلمى ضمن فريق الترميم، ورفضت منصبًا إداريًا في القاهرة. قالت إنها لا تثق فيمن يبتعد عن الورق ويبدأ في إصدار التعليمات. كان يوسف يصور مراحل التوثيق، لكنه لم يسمح لأي شركة باستخدام الصور في إعلان تجاري.</p>\n<p>في يوم الافتتاح وصل مرتديًا قميصًا غير مكوي. أصلحته مها بيدها أمام الصحفيين، فالتقطوا الصورة وانتشرت بعنوان «سليل القدماء تستعد به أمه». أرسل يوسف للمحرر رسالة يطلب تغيير العنوان. لم يغيره.</p>\n<p>وقف عمران قرب المدخل، ذراعه شُفيت مع انحناء بسيط. إلى جواره أيمن، أنحف من قبل لكنه يقف وحده. لم يحب الزحام، فاختار مكانًا يرى منه الباب.</p>\n<p>أما عمر فجاء ببدلة رسمية لأول مرة. عُلّقت صورة أبيه ونعيم في جزء يوثق بعثة 1978 وكشف الجريمة. تحتها نسخة من القرار الرسمي برد اعتبار الرجلين.</p>\n<p>قال عمر:</p>\n<p>- أبويا أخد ترقية بعد ما مات. كان هيضحك.</p>\n<p>- وجدي بقى مكتشفًا رسميًا، قال يوسف.</p>\n<p>- كان هيشتم.</p>\n<p>- غالبًا.</p>\n<p>دخلت مجموعة من طلاب المدارس. اندفعوا إلى صندوق تفاعلي يبحثون فيه عن الأسماء والمهن. سأل طفل:</p>\n<p>- فين الفرعون؟</p>\n<p>قالت المرشدة:</p>\n<p>- المعرض عن الناس اللي بنوا المقابر.</p>\n<p>- يعني مفيش مومياء ملك؟</p>\n<p>- فيه مومياء كاتب.</p>\n<p>فكر الطفل، ثم قال:</p>\n<p>- كان بيكتب إيه؟</p>\n<p>- مين خد كام رغيف.</p>\n<p>ضحك زملاؤه. لم تغضب المرشدة.</p>\n<p>قالت:</p>\n<p>- مرة واحد سرق أرغفتهم، فالكاتب كتب اسمه. عشان كده إحنا عارفين الحكاية.</p>\n<p>توقفوا عن الضحك قليلًا.</p>\n<p>في نهاية القاعة وضعوا القرص النحاسي داخل صندوق زجاجي. رفض يوسف أن يُنسب إلى عائلته وحدها. كُتب على البطاقة: «أداة قياس انتقلت بين حراس مجهولين، من أصول وقرابات مختلفة.»</p>\n<p>كان بقطر السبب. لا أحد يعرف إن كان من دم حوري، لكنه اختار الطفل والكتاب. حين اقترح أحد الباحثين حذف اسمه من سلسلة العائلة لعدم ثبوت النسب، قالت سلمى:</p>\n<p>- لو عملنا كده نبقى رجعنا القصة تحليل DNA.</p>\n<p>اختفى دفتر نادر في الماء، لكن صفحات منه بقيت مصورة في أرشيف رائف. نشرها فريق التحقيق مع تقرير يوضح تناقضاتها. لم يعد نادر وحشًا أسطوريًا ولا ضحية بريئة؛ صار رجلًا اتخذ قرارًا سيئًا ثم بنى عمرًا كاملًا من الجمل ليعيش معه.</p>\n<p>في المساء، بعد خروج الزوار، جلس يوسف وسلمى على درجات المتحف الخلفية. كان النيل أسود إلا من أضواء المراكب.</p>\n<p>قالت سلمى:</p>\n<p>- جالك عرض المسلسل؟</p>\n<p>- ثلاثة.</p>\n<p>- وهتوافق؟</p>\n<p>- واحد منهم عايز حوري يبقى أميرًا سريًا بيحب بنت الفرعون.</p>\n<p>- منطقي. رغيف العيش مش رومانسي.</p>\n<p>- والتاني عايز رائف يهرب في الآخر عشان موسم تاني.</p>\n<p>- وفعليًا؟</p>\n<p>- فعليًا مات ماسك حتة دهب قد كف الإيد.</p>\n<p>سكتا.</p>\n<p>قال يوسف:</p>\n<p>- أنا بكتب الحكاية.</p>\n<p>نظرت إليه.</p>\n<p>- أنت؟</p>\n<p>- ليه الاستغراب؟</p>\n<p>- لأن رسائلك كلها من غير نقط.</p>\n<p>- هجيب حد يحط النقط.</p>\n<p>- وهتسميها إيه؟</p>\n<p>نظر إلى الكف ذات الأصابع الخمسة المطبوعة على ملصق المعرض.</p>\n<p>- الوريث الخامس.</p>\n<p>قالت:</p>\n<p>- الاسم يوحي إنك ورثت حاجة.</p>\n<p>- ورثت فاتورة طويلة.</p>\n<p>- دي أول جملة كويسة. اكتبها قبل ما تنساها.</p>\n<p>أخرج هاتفه وكتبها.</p>\n<p>لم يكن الهاتف متصلًا بتطبيق جذور. حذف حسابه بعد إغلاق الشركة، وطلب إتلاف عينته. بقيت نتيجة قديمة محفوظة في صورة: وادي النيل 82%، شمال أفريقيا 9%، شرق المتوسط 6%، غير محدد 3%.</p>\n<p>كان يحب الثلاثة بالمئة الأخيرة.</p>\n<p>تركها بلا تفسير.</p>"}, {"id": "chapter-25", "order": 25, "title": "الفصل الخامس والعشرون: الوريث الخامس", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "في الذكرى الثانية لوفاة مريم، اجتمعوا عند شجرة صغيرة زُرعت باسمها في حديقة كلية العلوم. جاءت أمها وأخوها، ورفضت الأم أن يتحدث أحد عن ابنتها كـ«ضحية» فقط.", "wordCount": 541, "minutes": 3, "era": "الحاضر", "theme": "modern", "sound": "pulse", "icon": "◉", "scene": "القاهرة والأقصر", "html": "<p>في الذكرى الثانية لوفاة مريم، اجتمعوا عند شجرة صغيرة زُرعت باسمها في حديقة كلية العلوم. جاءت أمها وأخوها، ورفضت الأم أن يتحدث أحد عن ابنتها كـ«ضحية» فقط.</p>\n<p>قالت:</p>\n<p>- كانت بتضحك بصوت عالي في السينما، وبتحرق الرز، وبتنسى مفاتيحها. اللي هيكتب عنها يكتب ده كمان.</p>\n<p>وعدها يوسف.</p>\n<p>كان قد أنهى المسودة الأولى من الرواية، ثم حذف نصفها. في النسخة الأولى جعل نعيم شجاعًا طوال الوقت. حين قرأ رسالته مرة أخرى فهم أنه بذلك يسرقه. كتب بدلًا من ذلك أنه خاف. جعل سالم خائنًا، ثم عاد وكتب ابنته وسعالها. جعل بقطر حكيمًا، ثم تذكر أنه كان رجلًا يريد دكانًا أكبر ولا يريد طفلًا. جعل حوري يعرف المستقبل، ثم محا كل نبوءاته.</p>\n<p>قالت له سلمى:</p>\n<p>- كده أحسن.</p>\n<p>- لسه حاسة إنها مكتوبة؟</p>\n<p>- كل رواية باين إنها مكتوبة. المهم ما تبانش معمولة من ناس نظيفة بزيادة.</p>\n<p>كان هذا معيارها لكل شيء.</p>\n<p>عادت الحفريات إلى وادي الخرس تحت إشراف رسمي ودولي. استُخرجت السجلات والجرار على مراحل. وجد الباحثون أن الحجرة لم تكن مخزنًا واحدًا، بل أرشيفًا تراكم عبر قرون. أضاف بقطر أسماء بلغته، وسالم وضع ورقة حسابات من زمنه، ونعيم كتب رسالة. صار المكان نفسه وثيقة على أن الحراسة لم تكن سلسلة دم صافية؛ كانت سلسلة أشخاص قرروا أن يضيفوا شيئًا بدل أن يأخذوا.</p>\n<p>أما الذهب، فكان أقل مما قدّره رائف بكثير. رقائق وحصص أجور وأختام معدنية، ثمينة علميًا أكثر من قيمتها في السوق. حين أعلن الخبر، كتب شخص على الإنترنت: «يعني كل الدوشة على شوية ورق؟»</p>\n<p>رد عليه أيمن من حسابه الجديد:</p>\n<p>«أنا ضاع من عمري سبع سنين عشان ناس فاكرة الورق شوية.»</p>\n<p>حصل تعليقه على آلاف الإعجابات. أغلق الهاتف بعد دقيقة؛ لم يكن يحب أن ينظر إليه غرباء كثيرون.</p>\n<p>عاش عمران معه في بيت جديد بعيد عن البيت القديم. لم يستطيعا ترميم السنوات، فبدآ بأشياء صغيرة: فطور في موعد ثابت، باب لا يُقفل من الخارج، وضوء يظل مضاءً في الممر. بعض الليالي كان أيمن يستيقظ مقتنعًا أنه ما زال في الحجرة. يجلس عمران خارج غرفته ولا يدخل حتى يناديه.</p>\n<p>قال له مرة:</p>\n<p>- أنا هنا.</p>\n<p>رد أيمن:</p>\n<p>- عارف. بس قولها تاني.</p>\n<p>فقالها حتى نام.</p>\n<p>لم يتزوج يوسف وسلمى في نهاية سريعة كما توقع الصحفي الذي كتب عن «الحبيبين اللذين جمعهما سر الفراعنة». ظلا يتشاجران حول الصور، والملكية، وطريقة كتابة اسم بقطر. بعد عامين، حين طلب يوسف منها أن تشاركه البيت، قالت:</p>\n<p>- بشرط ما تحطش صور مومياوات في الصالة.</p>\n<p>- صورة واحدة صغيرة.</p>\n<p>- ولا صغيرة.</p>\n<p>وافق، ثم علق صورة الكف السوداء في المكتب. قالت إنها ليست مومياء، فتركته.</p>\n<p>في مساء هادئ عاد يوسف إلى بيت نعيم القديم. رُمم السقف، لكنهم أبقوا لوح الأرضية تحت السرير. جلس مكان عمران الطفل، ووضع الكاميرا الروسية أمامه.</p>\n<p>أصلحها فني عجوز. قال إن العدسة مخدوشة، وإن الغالق بطيء، وإن شراء كاميرا أخرى أرخص. أصر يوسف.</p>\n<p>ثبت فيلمًا جديدًا، وخرج إلى الفناء. كانت مها تقف عند الباب، وعمران وأيمن قرب الحائط. جاءت سلمى متأخرة تحمل أكياس طعام وتشتكي من الطريق. وضعوا الكاميرا فوق حامل وضبط المؤقت.</p>\n<p>قال عمران:</p>\n<p>- هنقف إزاي؟</p>\n<p>- عادي.</p>\n<p>- أبويا كان بيكره الصور.</p>\n<p>قالت مها:</p>\n<p>- عشان كان بيطلع مكشر.</p>\n<p>وقفوا. في اللحظة الأخيرة تحرك أيمن خطوة إلى الخلف، ثم عاد حين أمسك أبوه بيده. لم يطلب منه أحد أن يبتسم.</p>\n<p>صدر صوت الغالق.</p>\n<p>هذه المرة التُقطت الصورة الخامسة فعلًا.</p>\n<p>لم يكن فيها ملوك، ولا كنز، ولا نسب يمكن بيعه في علبة أنيقة.</p>\n<p>خمسة أشخاص فقط، يقفون أمام بيت نجا منهم ونجوا منه، وكل واحد يحمل اسمًا يعرف ما كلفه أن يعود.</p>\n<div class=\"scene-break\" aria-hidden=\"true\"><span></span><span></span><span></span></div>"}, {"id": "chapter-26", "order": 26, "title": "خاتمة: الأسماء حين تُقرأ", "section": "القسم الثالث: البيت الذي تحت التراب", "firstLine": "بعد سنوات، وقف صبي أمام لوح الأسماء في المتحف. كان في زيارة مدرسية، وقد ملّ الشرح وبحث عن أي شيء يلمسه. مرر إصبعه على الزجاج حتى وجد اسمًا يشبه اسم عائلته.", "wordCount": 113, "minutes": 2, "era": "بعد سنوات", "theme": "museum", "sound": "paper", "icon": "◇", "scene": "متحف الأقصر", "html": "<p>بعد سنوات، وقف صبي أمام لوح الأسماء في المتحف. كان في زيارة مدرسية، وقد ملّ الشرح وبحث عن أي شيء يلمسه. مرر إصبعه على الزجاج حتى وجد اسمًا يشبه اسم عائلته.</p>\n<p>نادى أمه:</p>\n<p>- ماما، هو ده جدنا؟</p>\n<p>اقتربت، قرأت الاسم، ثم هزت رأسها.</p>\n<p>- ما نعرفش.</p>\n<p>- طب ممكن؟</p>\n<p>- ممكن.</p>\n<p>- كان ملك؟</p>\n<p>قرأت المهنة المكتوبة تحت الاسم.</p>\n<p>- كان بيجيب المية للعمال.</p>\n<p>فكر الصبي قليلًا. ثم أخذ صورة للاسم، وأرسلها إلى أبيه.</p>\n<p>لم يكن الرجل ملكًا. لم يكن صاحب مقبرة. لم تُصنع له تماثيل، ولم يقل أحد إن دمه عاش في نسبة مئوية داخل شخص حديث.</p>\n<p>كان يحمل الماء.</p>\n<p>وفي ظهيرة بعيدة، بعد أكثر من ثلاثة آلاف عام، نطق طفل اسمه مرة أخرى.</p>\n<p>وهذا كان كافيًا.</p>"}], "sections": ["ما قبل البداية", "القسم الأول: العينة", "القسم الثاني: العلامات الخمس", "القسم الثالث: البيت الذي تحت التراب"]};
